def _validate_model_registry_entry(entry: dict[str, Any], target: ValidationTarget, source_path: Path | None = None) -> None:
    _require_equal(entry, "schema_version", MODEL_REGISTRY_ENTRY_SCHEMA_VERSION, target, prefix="model_registry_entry.")
    target.errors.extend(model_registry_entry_errors(entry))
    links = entry.get("links") if isinstance(entry.get("links"), dict) else {}
    if source_path is not None:
        _validate_model_registry_links_files(links, target, "model_registry_entry.links", source_path)
    target.details.update(
        {
            "entry_id": entry.get("entry_id"),
            "candidate_id": entry.get("candidate_id"),
            "training_eligible": entry.get("training_eligible"),
            "license_status": entry.get("license_status"),
            "link_counts": {
                key: len(value)
                for key, value in links.items()
                if isinstance(key, str) and isinstance(value, list)
            },
        }
    )


def _validate_model_registry(registry: dict[str, Any], target: ValidationTarget, source_path: Path | None = None) -> None:
    _require_equal(registry, "schema_version", MODEL_REGISTRY_SCHEMA_VERSION, target, prefix="model_registry.")
    target.errors.extend(model_registry_errors(registry))
    entries = registry.get("entries") if isinstance(registry.get("entries"), dict) else {}
    aliases = registry.get("aliases") if isinstance(registry.get("aliases"), dict) else {}
    link_counts: dict[str, int] = {}
    for entry_id, entry in entries.items():
        links = entry.get("links") if isinstance(entry, dict) and isinstance(entry.get("links"), dict) else {}
        if source_path is not None:
            _validate_model_registry_links_files(links, target, f"model_registry.entries.{entry_id}.links", source_path)
        for collection, records in links.items():
            if isinstance(collection, str) and isinstance(records, list):
                link_counts[collection] = link_counts.get(collection, 0) + len(records)
    target.details.update(
        {
            "entry_count": len(entries),
            "training_eligible_count": sum(
                1 for entry in entries.values() if isinstance(entry, dict) and entry.get("training_eligible") is True
            ),
            "aliases": aliases,
            "link_counts": link_counts,
        }
    )


def _validate_model_registry_links_files(
    links: Any, target: ValidationTarget, label: str, source_path: Path
) -> None:
    if not isinstance(links, dict):
        return
    for collection, records in links.items():
        if not isinstance(collection, str) or not isinstance(records, list):
            continue
        for index, record in enumerate(records):
            record_label = f"{label}.{collection}[{index}]"
            if not isinstance(record, dict) or "path" not in record:
                continue
            path_value = record.get("path")
            if not isinstance(path_value, str) or not path_value:
                continue
            link_path = _model_registry_link_path(path_value, source_path)
            if link_path.is_symlink():
                target.errors.append(f"{record_label}.path must not resolve to a symlink.")
                continue
            if not link_path.is_file():
                target.errors.append(f"{record_label}.path does not resolve to a linked artifact file.")
                continue
            if _is_non_negative_int(record.get("size_bytes")) and link_path.stat().st_size != record.get("size_bytes"):
                target.errors.append(f"{record_label}.size_bytes does not match the current file.")
            if _is_sha256(record.get("sha256")) and _sha256(link_path) != record.get("sha256"):
                target.errors.append(f"{record_label}.sha256 does not match the current file.")


def _validate_model_layer_file_ref(
    record: dict[str, Any], target: ValidationTarget, label: str, source_path: Path
) -> None:
    if "sha256" not in record and "size_bytes" not in record:
        return
    path_value = record.get("path")
    if not isinstance(path_value, str) or not path_value:
        return
    link_path = _model_registry_link_path(path_value, source_path)
    if link_path.is_symlink():
        target.errors.append(f"{label}.path must not resolve to a symlink.")
        return
    if not link_path.is_file():
        target.errors.append(f"{label}.path does not resolve to a linked artifact file.")
        return
    if not _is_non_negative_int(record.get("size_bytes")):
        target.errors.append(f"{label}.size_bytes must be a non-negative integer for path-backed refs.")
    elif link_path.stat().st_size != record.get("size_bytes"):
        target.errors.append(f"{label}.size_bytes does not match the current file.")
    if not _is_sha256(record.get("sha256")):
        target.errors.append(f"{label}.sha256 must be a 64-character hex digest for path-backed refs.")
    elif _sha256(link_path) != record.get("sha256"):
        target.errors.append(f"{label}.sha256 does not match the current file.")


def _model_registry_link_path(value: str, source_path: Path) -> Path:
    path = Path(value)
    if path.is_absolute():
        return path
    source_relative = source_path.parent / path
    if source_relative.exists():
        return source_relative
    for root in source_path.resolve().parents:
        if (root / ".git").exists() or (root / "pyproject.toml").exists():
            repo_relative = root / path
            if repo_relative.exists():
                return repo_relative
    return source_relative


def _validate_training_plan(plan: dict[str, Any], target: ValidationTarget, source_path: Path | None = None) -> None:
    _require_equal(plan, "schema_version", TRAINING_PLAN_SCHEMA_VERSION, target, prefix="training_plan.")
    target.errors.extend(training_plan_errors(plan))
    model = plan.get("model") if isinstance(plan.get("model"), dict) else {}
    dataset = plan.get("dataset") if isinstance(plan.get("dataset"), dict) else {}
    compatibility_report = plan.get("compatibility_report") if isinstance(plan.get("compatibility_report"), dict) else {}
    if source_path is not None:
        _validate_model_layer_file_ref(
            compatibility_report,
            target,
            "training_plan.compatibility_report",
            source_path,
        )
    target.details.update(
        {
            "model_ref": model.get("model_ref"),
            "candidate_id": model.get("candidate_id"),
            "dataset_id": dataset.get("dataset_id"),
            "compatibility_report_path": compatibility_report.get("path"),
            "compatibility_report_sha256": compatibility_report.get("sha256"),
            "dry_run": plan.get("dry_run"),
            "gpu_execution": plan.get("gpu_execution"),
            "no_weight_download": plan.get("no_weight_download"),
        }
    )


def _validate_agentic_training_flow(flow: dict[str, Any], target: ValidationTarget, source_path: Path) -> None:
    _require_equal(flow, "schema_version", AGENTIC_TRAINING_FLOW_SCHEMA_VERSION, target, prefix="agentic_training_flow.")
    checks = flow.get("checks")
    if not isinstance(checks, list):
        target.errors.append("agentic_training_flow.checks must be a list.")
        checks = []
    failed_checks = _validate_gate_like_checks(checks, target, "agentic_training_flow.checks")
    if flow.get("check_count") != len(checks):
        target.errors.append(f"agentic_training_flow.check_count expected {len(checks)}, got {flow.get('check_count')!r}.")
    if flow.get("failed_check_count") != failed_checks:
        target.errors.append(
            f"agentic_training_flow.failed_check_count expected {failed_checks}, got {flow.get('failed_check_count')!r}."
        )
    expected_passed = failed_checks == 0
    if not isinstance(flow.get("passed"), bool):
        target.errors.append("agentic_training_flow.passed must be a boolean.")
    elif flow.get("passed") != expected_passed:
        target.errors.append("agentic_training_flow.passed must match failed_check_count.")
    expected_readiness = "ready" if expected_passed else "blocked"
    expected_recommendation = FLOW_READY_RECOMMENDATION if expected_passed else FLOW_BLOCK_RECOMMENDATION
    if flow.get("readiness") != expected_readiness:
        target.errors.append(f"agentic_training_flow.readiness expected {expected_readiness!r}, got {flow.get('readiness')!r}.")
    if flow.get("recommendation") != expected_recommendation:
        target.errors.append(
            f"agentic_training_flow.recommendation expected {expected_recommendation!r}, got {flow.get('recommendation')!r}."
        )
    if not isinstance(flow.get("flow_id"), str) or not flow.get("flow_id"):
        target.errors.append("agentic_training_flow.flow_id must be a non-empty string.")
    flow_path = flow.get("flow_path")
    if not isinstance(flow_path, str):
        target.errors.append("agentic_training_flow.flow_path must be a string.")
    elif flow_path and not _is_safe_training_flow_metadata_path(flow_path):
        target.errors.append("agentic_training_flow.flow_path must be a safe relative path without traversal.")
    if not _is_string_list(flow.get("blocked_reasons")):
        target.errors.append("agentic_training_flow.blocked_reasons must be a list of strings.")
    elif expected_passed and flow.get("blocked_reasons"):
        target.errors.append("agentic_training_flow.blocked_reasons must be empty when passed.")
    elif not expected_passed and len(flow.get("blocked_reasons", [])) != failed_checks:
        target.errors.append("agentic_training_flow.blocked_reasons must match failed_check_count.")

    _validate_agentic_training_flow_sources(flow.get("source_artifacts"), target, source_path)
    flow_counts = _validate_agentic_training_flow_delegated_flow(flow.get("delegated_flow"), target, expected_passed)
    mode_contract_check = _validate_agentic_training_flow_mode_contract_check(
        flow.get("mode_contract_check"),
        target,
        flow_counts.get("mode", ""),
        expected_passed,
    )
    _validate_agentic_training_flow_mode_gate(
        flow.get("flow_mode_gate"),
        target,
        flow_counts.get("mode", ""),
        mode_contract_check,
        expected_passed,
    )
    _validate_agentic_training_flow_metrics(flow.get("metrics"), target, flow_counts, len(checks), failed_checks)
    _validate_agentic_training_flow_boundary(flow.get("execution_boundary"), target)
    _validate_agentic_training_flow_contract(flow.get("handoff_contract"), target)
    if not _is_string_list(flow.get("notes")):
        target.errors.append("agentic_training_flow.notes must be a list of strings.")
    target.details.update(
        {
            "passed": flow.get("passed"),
            "mode": flow_counts.get("mode"),
            "stage_count": flow_counts.get("stage_count"),
            "command_arg_count": flow_counts.get("command_arg_count"),
        }
    )


def _validate_agentic_training_flow_sources(value: Any, target: ValidationTarget, source_path: Path) -> None:
    if not isinstance(value, dict):
        target.errors.append("agentic_training_flow.source_artifacts must be an object.")
        return
    expected = {
        "agentic_training_plan": AGENTIC_TRAINING_PLAN_SCHEMA_VERSION,
        "agentic_training_runtime_preflight": AGENTIC_TRAINING_RUNTIME_PREFLIGHT_SCHEMA_VERSION,
        "trainer_consumer_plan": TRAINER_CONSUMER_PLAN_SCHEMA_VERSION,
    }
    for role, schema_version in expected.items():
        ref = value.get(role)
        label = f"agentic_training_flow.source_artifacts.{role}"
        if not isinstance(ref, dict):
            target.errors.append(f"{label} must be an object.")
            continue
        _validate_agentic_training_flow_source_ref(ref, target, label, role, schema_version, source_path)


def _validate_agentic_training_flow_source_ref(
    ref: dict[str, Any],
    target: ValidationTarget,
    label: str,
    role: str,
    schema_version: str,
    source_path: Path,
) -> None:
    if ref.get("role") != role:
        target.errors.append(f"{label}.role must be {role!r}.")
    path_value = ref.get("path")
    if not isinstance(path_value, str) or not path_value:
        target.errors.append(f"{label}.path must be a non-empty string.")
        path_value = ""
    elif not _is_safe_or_redacted_training_flow_path(path_value):
        target.errors.append(f"{label}.path must be a safe relative path without traversal.")
    if ref.get("schema_version") != schema_version:
        target.errors.append(f"{label}.schema_version must be {schema_version!r}.")
    if ref.get("exists") is not True:
        target.errors.append(f"{label}.exists must be true.")
    if ref.get("regular_file") is not True:
        target.errors.append(f"{label}.regular_file must be true.")
    if ref.get("passed") is not True:
        target.errors.append(f"{label}.passed must be true.")
    if not isinstance(ref.get("recommendation"), str) or not ref.get("recommendation"):
        target.errors.append(f"{label}.recommendation must be a non-empty string.")
    if not _is_sha256(ref.get("sha256")):
        target.errors.append(f"{label}.sha256 must be a SHA-256 hex string.")
    if not _is_non_negative_int(ref.get("size_bytes")):
        target.errors.append(f"{label}.size_bytes must be a non-negative integer.")
    if isinstance(path_value, str) and path_value and not path_value.startswith("<"):
        source_dir = source_path.resolve().parent
        candidate_path = source_dir / path_value
        current_path = candidate_path.resolve()
        allowed_roots = [source_dir]
        repo_root = _repo_root_for_artifact(source_path)
        if repo_root is not None:
            allowed_roots.append(repo_root)
        if not any(current_path.is_relative_to(root) for root in allowed_roots):
            target.errors.append(f"{label}.path must resolve under the flow artifact directory or repository root.")
            return
        if _path_has_symlink_component(candidate_path, include_leaf=True):
            target.errors.append(f"{label}.path must resolve to a regular non-symlink file.")
            return
        if not current_path.exists():
            target.errors.append(f"{label}.path must resolve to an existing file.")
            return
        if current_path.is_symlink() or not current_path.is_file():
            target.errors.append(f"{label}.path must resolve to a regular file.")
            return
        if _is_non_negative_int(ref.get("size_bytes")) and current_path.stat().st_size != ref.get("size_bytes"):
            target.errors.append(f"{label}.size_bytes does not match path.")
        if _is_sha256(ref.get("sha256")) and _sha256(current_path) != ref.get("sha256"):
            target.errors.append(f"{label}.sha256 does not match path.")


def _repo_root_for_artifact(source_path: Path) -> Path | None:
    for root in source_path.resolve().parents:
        if (root / ".git").exists() or (root / "pyproject.toml").exists():
            return root
    return None


def _validate_agentic_training_flow_delegated_flow(
    value: Any,
    target: ValidationTarget,
    expected_passed: bool,
) -> dict[str, Any]:
    counts: dict[str, Any] = {
        "mode": "",
        "stage_count": 0,
        "executable_stage_count": 0,
        "selected_view_count": 0,
        "command_arg_count": 0,
        "trainer_input_count": 0,
        "external_code_file_count": 0,
    }
    if not isinstance(value, dict):
        target.errors.append("agentic_training_flow.delegated_flow must be an object.")
        return counts
    mode = value.get("mode")
    counts["mode"] = mode if isinstance(mode, str) else ""
    blocked_advanced_mode = mode in BLOCKED_TRAINER_FLOW_MODES and not expected_passed
    if expected_passed and mode not in EXECUTABLE_FLOW_MODES:
        target.errors.append(f"agentic_training_flow.delegated_flow.mode must be one of {list(EXECUTABLE_FLOW_MODES)!r}.")
    elif mode not in EXECUTABLE_FLOW_MODES and not blocked_advanced_mode:
        target.errors.append(
            f"agentic_training_flow.delegated_flow.mode must be executable or an explicitly blocked mode, got {mode!r}."
        )
    if expected_passed and mode in BLOCKED_TRAINER_FLOW_MODES:
        target.errors.append("agentic_training_flow.delegated_flow.mode must not be an advanced reward or RL mode.")
    if not isinstance(value.get("backend"), str) or not value.get("backend"):
        target.errors.append("agentic_training_flow.delegated_flow.backend must be a non-empty string.")
    stage_sequence = value.get("stage_sequence")
    if not _is_string_list(stage_sequence):
        target.errors.append("agentic_training_flow.delegated_flow.stage_sequence must be a list of strings.")
        stage_sequence = []
    stages = value.get("stages")
    if not isinstance(stages, list):
        target.errors.append("agentic_training_flow.delegated_flow.stages must be a list.")
        stages = []
    if len(stages) != len(stage_sequence):
        target.errors.append("agentic_training_flow.delegated_flow.stages must match stage_sequence length.")
    counts["stage_count"] = len([stage for stage in stages if isinstance(stage, dict)])
    seen_views: set[str] = set()
    for index, stage in enumerate(stages):
        label = f"agentic_training_flow.delegated_flow.stages[{index}]"
        if not isinstance(stage, dict):
            target.errors.append(f"{label} must be an object.")
            continue
        stage_id = stage.get("stage_id")
        allowed_stages = (*EXECUTABLE_STAGES, *BLOCKED_TRAINER_FLOW_STAGES) if blocked_advanced_mode else EXECUTABLE_STAGES
        if stage_id not in allowed_stages:
            target.errors.append(f"{label}.stage_id must be one of {list(allowed_stages)!r}.")
        else:
            if stage_id in EXECUTABLE_STAGES:
                counts["executable_stage_count"] += 1
        if stage.get("stage_index") != index:
            target.errors.append(f"{label}.stage_index expected {index}, got {stage.get('stage_index')!r}.")
        if index < len(stage_sequence) and stage_id != stage_sequence[index]:
            target.errors.append(f"{label}.stage_id must match delegated_flow.stage_sequence[{index}].")
        if stage.get("view_ready") is not True:
            target.errors.append(f"{label}.view_ready must be true.")
        if not isinstance(stage.get("view_name"), str) or not stage.get("view_name"):
            target.errors.append(f"{label}.view_name must be a non-empty string.")
        else:
            seen_views.add(stage["view_name"])
        if not isinstance(stage.get("view_path"), str) or not stage.get("view_path"):
            target.errors.append(f"{label}.view_path must be a non-empty string.")
        if not isinstance(stage.get("view_schema_version"), str) or not stage.get("view_schema_version"):
            target.errors.append(f"{label}.view_schema_version must be a non-empty string.")
        if not _is_non_negative_int(stage.get("row_count")) or stage.get("row_count") <= 0:
            target.errors.append(f"{label}.row_count must be a positive integer.")
    counts["selected_view_count"] = len(seen_views)
    command_counts = _validate_agentic_training_flow_command(value.get("command"), target)
    counts.update(command_counts)
    return counts


def _validate_agentic_training_flow_mode_contract_check(
    value: Any,
    target: ValidationTarget,
    mode: str,
    expected_passed: bool,
) -> dict[str, Any]:
    if not isinstance(value, dict):
        target.errors.append("agentic_training_flow.mode_contract_check must be an object.")
        return {}
    for field_name in ("mode", "category"):
        if not isinstance(value.get(field_name), str):
            target.errors.append(f"agentic_training_flow.mode_contract_check.{field_name} must be a string.")
    if mode and value.get("mode") != mode:
        target.errors.append("agentic_training_flow.mode_contract_check.mode must match delegated_flow.mode.")
    for field_name in ("present", "mode_matches_plan", "planning_gate_open", "passed"):
        if not isinstance(value.get(field_name), bool):
            target.errors.append(f"agentic_training_flow.mode_contract_check.{field_name} must be a boolean.")
    if not isinstance(value.get("planning_required_flag"), (str, type(None))):
        target.errors.append("agentic_training_flow.mode_contract_check.planning_required_flag must be a string or null.")
    if not _is_non_negative_int(value.get("data_requirement_count")):
        target.errors.append("agentic_training_flow.mode_contract_check.data_requirement_count must be a non-negative integer.")
    if not _is_string_list(value.get("unsatisfied_data_requirement_ids")):
        target.errors.append("agentic_training_flow.mode_contract_check.unsatisfied_data_requirement_ids must be a list of strings.")
    errors = value.get("errors")
    if not _is_string_list(errors):
        target.errors.append("agentic_training_flow.mode_contract_check.errors must be a list of strings.")
        errors = []
    if not _is_non_negative_int(value.get("error_count")):
        target.errors.append("agentic_training_flow.mode_contract_check.error_count must be a non-negative integer.")
    elif value.get("error_count") != len(errors):
        target.errors.append("agentic_training_flow.mode_contract_check.error_count must match errors length.")
    _validate_agentic_training_flow_reward_contract(value.get("reward_contract"), target)
    _validate_agentic_training_flow_side_effect_boundary(value.get("side_effect_boundary"), target)
    _validate_agentic_training_flow_external_runner_contract(value.get("external_runner_contract"), target)
    if expected_passed and value.get("passed") is not True:
        target.errors.append("agentic_training_flow.mode_contract_check.passed must be true for ready delegated flow receipts.")
    if mode in BLOCKED_TRAINER_FLOW_MODES:
        if value.get("present") is not True:
            target.errors.append("agentic_training_flow.mode_contract_check.present must be true for blocked advanced-mode receipts.")
        if value.get("mode_matches_plan") is not True:
            target.errors.append("agentic_training_flow.mode_contract_check.mode_matches_plan must be true for blocked advanced-mode receipts.")
    return value


def _validate_agentic_training_flow_reward_contract(value: Any, target: ValidationTarget) -> None:
    label = "agentic_training_flow.mode_contract_check.reward_contract"
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    if not isinstance(value.get("kind"), str):
        target.errors.append(f"{label}.kind must be a string.")
    if not isinstance(value.get("callable_signature"), str):
        target.errors.append(f"{label}.callable_signature must be a string.")
    for field_name in (
        "required",
        "external_runner_must_supply",
        "external_runner_must_validate",
        "flight_recorder_supplies_callable",
        "may_call_paid_services_by_default",
        "may_require_secrets_by_default",
        "must_not_use_unredacted_traces",
    ):
        if not isinstance(value.get(field_name), bool):
            target.errors.append(f"{label}.{field_name} must be a boolean.")


def _validate_agentic_training_flow_side_effect_boundary(value: Any, target: ValidationTarget) -> None:
    label = "agentic_training_flow.mode_contract_check.side_effect_boundary"
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    for field_name in (
        "dry_run_only",
        "training_started",
        "cloud_jobs_started",
        "model_downloads_started",
        "paid_model_grader_calls_started",
        "weights_updated",
        "provider_credentials_required_by_flight_recorder",
    ):
        if not isinstance(value.get(field_name), bool):
            target.errors.append(f"{label}.{field_name} must be a boolean.")


def _validate_agentic_training_flow_external_runner_contract(value: Any, target: ValidationTarget) -> None:
    label = "agentic_training_flow.mode_contract_check.external_runner_contract"
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    if not isinstance(value.get("runner_must_require_recommendation"), str):
        target.errors.append(f"{label}.runner_must_require_recommendation must be a string.")
    for field_name in (
        "runner_owns_execution",
        "runner_must_revalidate_inputs",
        "runner_must_validate_reward_contract",
        "runner_must_block_unredacted_traces",
    ):
        if not isinstance(value.get(field_name), bool):
            target.errors.append(f"{label}.{field_name} must be a boolean.")


def _validate_agentic_training_flow_mode_gate(
    value: Any,
    target: ValidationTarget,
    mode: str,
    mode_contract_check: dict[str, Any],
    expected_passed: bool,
) -> None:
    if not isinstance(value, dict):
        target.errors.append("agentic_training_flow.flow_mode_gate must be an object.")
        return
    if value.get("mode") != mode:
        target.errors.append("agentic_training_flow.flow_mode_gate.mode must match delegated_flow.mode.")
    category = value.get("category")
    if not isinstance(category, str):
        target.errors.append("agentic_training_flow.flow_mode_gate.category must be a string.")
    elif mode_contract_check.get("category") and category != mode_contract_check.get("category"):
        target.errors.append("agentic_training_flow.flow_mode_gate.category must match mode_contract_check.category.")
    expected_executable = mode in EXECUTABLE_FLOW_MODES
    expected_blocked = mode in BLOCKED_TRAINER_FLOW_MODES
    expected_promotion_required = not expected_executable
    expected_status = "default_executable" if expected_executable else "blocked_until_flow_promotion"
    expected_values = {
        "executable_by_default": expected_executable,
        "blocked_by_default": expected_blocked,
        "promotion_required": expected_promotion_required,
        "mode_contract_ready": mode_contract_check.get("passed") is True,
        "external_runner_must_supply_reward": mode_contract_check.get("reward_contract", {}).get("external_runner_must_supply") is True,
        "external_runner_must_validate_reward": mode_contract_check.get("reward_contract", {}).get("external_runner_must_validate") is True,
    }
    for field_name, expected_value in expected_values.items():
        if value.get(field_name) is not expected_value:
            target.errors.append(f"agentic_training_flow.flow_mode_gate.{field_name} must be {expected_value!r}.")
    if value.get("promotion_status") != expected_status:
        target.errors.append(f"agentic_training_flow.flow_mode_gate.promotion_status must be {expected_status!r}.")
    if value.get("required_plan_opt_in_flag") != mode_contract_check.get("planning_required_flag"):
        target.errors.append("agentic_training_flow.flow_mode_gate.required_plan_opt_in_flag must match mode_contract_check.")
    if value.get("reward_contract_kind") != mode_contract_check.get("reward_contract", {}).get("kind", ""):
        target.errors.append("agentic_training_flow.flow_mode_gate.reward_contract_kind must match mode_contract_check.")
    if not isinstance(value.get("reason"), str):
        target.errors.append("agentic_training_flow.flow_mode_gate.reason must be a string.")
    elif expected_blocked and not value.get("reason"):
        target.errors.append("agentic_training_flow.flow_mode_gate.reason must explain blocked advanced-mode receipts.")
    if expected_passed and expected_blocked:
        target.errors.append("agentic_training_flow.flow_mode_gate must not allow a ready advanced-mode flow.")
    expected_category = BLOCKED_FLOW_MODE_CATEGORIES.get(mode)
    if expected_category and category != expected_category:
        target.errors.append(f"agentic_training_flow.flow_mode_gate.category must be {expected_category!r}.")


def _validate_agentic_training_flow_command(value: Any, target: ValidationTarget) -> dict[str, int]:
    counts = {"command_arg_count": 0, "trainer_input_count": 0, "external_code_file_count": 0}
    if not isinstance(value, dict):
        target.errors.append("agentic_training_flow.delegated_flow.command must be an object.")
        return counts
    for field_name in ("execution_cwd", "archive_root", "external_code_root", "command_shell"):
        if not isinstance(value.get(field_name), str):
            target.errors.append(f"agentic_training_flow.delegated_flow.command.{field_name} must be a string.")
    argv = value.get("command_argv")
    if not _is_string_list(argv):
        target.errors.append("agentic_training_flow.delegated_flow.command.command_argv must be a list of strings.")
        argv = []
    clean_argv = [item for item in argv if isinstance(item, str)]
    counts["command_arg_count"] = len(clean_argv)
    expected_shell = shlex.join(clean_argv) if clean_argv else ""
    if value.get("command_shell") != expected_shell:
        target.errors.append("agentic_training_flow.delegated_flow.command.command_shell must match command_argv.")
    for field_name in ("trainer_input_count", "external_code_file_count"):
        if not _is_non_negative_int(value.get(field_name)):
            target.errors.append(f"agentic_training_flow.delegated_flow.command.{field_name} must be a non-negative integer.")
        else:
            counts[field_name] = int(value[field_name])
    if not clean_argv:
        target.errors.append("agentic_training_flow.delegated_flow.command.command_argv must not be empty.")
    return counts


def _validate_agentic_training_flow_metrics(
    value: Any,
    target: ValidationTarget,
    counts: dict[str, Any],
    check_count: int,
    failed_check_count: int,
) -> None:
    if not isinstance(value, dict):
        target.errors.append("agentic_training_flow.metrics must be an object.")
        return
    expected = {
        "check_count": check_count,
        "failed_check_count": failed_check_count,
        "stage_count": counts["stage_count"],
        "executable_stage_count": counts["executable_stage_count"],
        "selected_view_count": counts["selected_view_count"],
        "command_arg_count": counts["command_arg_count"],
        "trainer_input_count": counts["trainer_input_count"],
        "external_code_file_count": counts["external_code_file_count"],
    }
    for field_name, expected_value in expected.items():
        if value.get(field_name) != expected_value:
            target.errors.append(f"agentic_training_flow.metrics.{field_name} expected {expected_value}, got {value.get(field_name)!r}.")


def _validate_agentic_training_flow_boundary(value: Any, target: ValidationTarget) -> None:
    if not isinstance(value, dict):
        target.errors.append("agentic_training_flow.execution_boundary must be an object.")
        return
    if value.get("flow_plan_only") is not True:
        target.errors.append("agentic_training_flow.execution_boundary.flow_plan_only must be true.")
    for field_name in (
        "training_started",
        "trainer_command_executed",
        "subprocess_started",
        "cloud_jobs_started",
        "model_downloads_started",
        "weights_updated_by_flight_recorder",
        "trainer_modules_imported",
        "credential_values_recorded",
    ):
        if value.get(field_name) is not False:
            target.errors.append(f"agentic_training_flow.execution_boundary.{field_name} must be false.")


def _validate_agentic_training_flow_contract(value: Any, target: ValidationTarget) -> None:
    if not isinstance(value, dict):
        target.errors.append("agentic_training_flow.handoff_contract must be an object.")
        return
    if value.get("runner_owns_execution") is not True:
        target.errors.append("agentic_training_flow.handoff_contract.runner_owns_execution must be true.")
    if value.get("runner_must_require_recommendation") != FLOW_READY_RECOMMENDATION:
        target.errors.append(
            "agentic_training_flow.handoff_contract.runner_must_require_recommendation must be ready_for_delegated_trainer_execution."
        )
    if value.get("runner_must_emit_result_schema") != AGENTIC_TRAINING_RESULT_SCHEMA_VERSION:
        target.errors.append("agentic_training_flow.handoff_contract.runner_must_emit_result_schema must be hfr.agentic_training_result.v1.")
    for field_name in (
        "requires_runtime_preflight",
        "requires_trainer_consumer_plan",
        "requires_mode_contract",
        "requires_mode_contract_ready",
        "requires_registered_model_and_dataset",
        "requires_redacted_dataset",
    ):
        if value.get(field_name) is not True:
            target.errors.append(f"agentic_training_flow.handoff_contract.{field_name} must be true.")
    if value.get("flight_recorder_executed_trainer") is not False:
        target.errors.append("agentic_training_flow.handoff_contract.flight_recorder_executed_trainer must be false.")
    if sorted(value.get("executable_modes", [])) != sorted(EXECUTABLE_FLOW_MODES):
        target.errors.append("agentic_training_flow.handoff_contract.executable_modes must match executable trainer flow modes.")
    if sorted(value.get("blocked_modes", [])) != sorted(BLOCKED_TRAINER_FLOW_MODES):
        target.errors.append("agentic_training_flow.handoff_contract.blocked_modes must match blocked trainer flow modes.")
    if sorted(value.get("blocked_mode_categories", [])) != sorted(set(BLOCKED_FLOW_MODE_CATEGORIES.values())):
        target.errors.append("agentic_training_flow.handoff_contract.blocked_mode_categories must match blocked trainer flow categories.")
    if sorted(value.get("blocked_mode_stages", [])) != sorted(BLOCKED_TRAINER_FLOW_STAGES):
        target.errors.append("agentic_training_flow.handoff_contract.blocked_mode_stages must match blocked trainer flow stages.")


def _is_safe_or_redacted_training_flow_path(value: str) -> bool:
    if value.startswith("<redacted:"):
        return True
    path = Path(value)
    windows_path = PureWindowsPath(value)
    return (
        bool(value)
        and not path.is_absolute()
        and not windows_path.is_absolute()
        and not windows_path.drive
        and "\\" not in value
        and "~" not in path.parts
    )


def _is_safe_training_flow_metadata_path(value: str) -> bool:
    path = Path(value)
    return _is_safe_or_redacted_training_flow_path(value) and ".." not in path.parts


def _validate_agentic_training_result(result: dict[str, Any], target: ValidationTarget, source_path: Path) -> None:
    _require_equal(result, "schema_version", AGENTIC_TRAINING_RESULT_SCHEMA_VERSION, target, prefix="agentic_training_result.")
    checks = result.get("checks")
    if not isinstance(checks, list):
        target.errors.append("agentic_training_result.checks must be a list.")
        checks = []
    failed_checks = _validate_gate_like_checks(checks, target, "agentic_training_result.checks")
    if result.get("check_count") != len(checks):
        target.errors.append(f"agentic_training_result.check_count expected {len(checks)}, got {result.get('check_count')!r}.")
    if result.get("failed_check_count") != failed_checks:
        target.errors.append(
            f"agentic_training_result.failed_check_count expected {failed_checks}, got {result.get('failed_check_count')!r}."
        )

    expected_passed = failed_checks == 0
    if not isinstance(result.get("passed"), bool):
        target.errors.append("agentic_training_result.passed must be a boolean.")
    elif result["passed"] != expected_passed:
        target.errors.append("agentic_training_result.passed must match failed_check_count.")
    expected_readiness = "ready" if expected_passed else "blocked"
    if result.get("readiness") != expected_readiness:
        target.errors.append(
            f"agentic_training_result.readiness expected {expected_readiness!r}, got {result.get('readiness')!r}."
        )
    artifact_path = result.get("artifact_path")
    if not isinstance(artifact_path, str) or not artifact_path:
        target.errors.append("agentic_training_result.artifact_path must be a non-empty string.")
    elif not _is_safe_agentic_training_result_path(artifact_path):
        target.errors.append("agentic_training_result.artifact_path must be a safe relative path without traversal.")

    training_result = result.get("training_result")
    if not isinstance(training_result, dict):
        target.errors.append("agentic_training_result.training_result must be an object.")
        training_result = {}
    status = training_result.get("status")
    if status not in RESULT_STATUSES:
        target.errors.append(f"agentic_training_result.training_result.status must be one of {list(RESULT_STATUSES)!r}.")
    if training_result.get("external_runner_reported_status") != status:
        target.errors.append("agentic_training_result.training_result.external_runner_reported_status must match status.")
    if training_result.get("flight_recorder_executed_training") is not False:
        target.errors.append("agentic_training_result.training_result.flight_recorder_executed_training must be false.")
    if training_result.get("model_downloads_started_by_flight_recorder") is not False:
        target.errors.append("agentic_training_result.training_result.model_downloads_started_by_flight_recorder must be false.")
    output_dir = training_result.get("output_dir")
    if not isinstance(output_dir, str):
        target.errors.append("agentic_training_result.training_result.output_dir must be a string.")
    elif output_dir and not _is_safe_agentic_training_result_path(output_dir):
        target.errors.append("agentic_training_result.training_result.output_dir must be a safe relative path without traversal.")

    failure = result.get("failure")
    if not isinstance(failure, dict):
        target.errors.append("agentic_training_result.failure must be an object.")
        failure = {}
    failure_class = failure.get("class")
    failure_message = failure.get("message")
    if failure_class not in FAILURE_CLASSES:
        target.errors.append(f"agentic_training_result.failure.class must be one of {list(FAILURE_CLASSES)!r}.")
    if not isinstance(failure_message, str):
        target.errors.append("agentic_training_result.failure.message must be a string.")
        failure_message = ""
    if isinstance(failure_class, str):
        expected_recoverable = failure_class in RECOVERABLE_FAILURE_CLASSES
        if failure.get("recoverable") != expected_recoverable:
            target.errors.append(
                f"agentic_training_result.failure.recoverable expected {expected_recoverable!r}, got {failure.get('recoverable')!r}."
            )
    if status == "completed" and failure_class != "none":
        target.errors.append("agentic_training_result.failure.class must be none for completed results.")
    if status in {"failed", "blocked", "aborted"} and (failure_class in {"none", "unknown"} or not failure_message.strip()):
        target.errors.append("agentic_training_result non-completed receipts require a classified failure and message.")

    artifact_counts = _validate_agentic_training_result_artifacts(result.get("artifacts"), target, source_path)
    metrics = result.get("metrics")
    if not isinstance(metrics, dict):
        target.errors.append("agentic_training_result.metrics must be an object.")
        metrics = {}
    for field_name, expected in artifact_counts.items():
        if metrics.get(field_name) != expected:
            target.errors.append(f"agentic_training_result.metrics.{field_name} expected {expected}, got {metrics.get(field_name)!r}.")
    if expected_passed and artifact_counts["regular_artifact_count"] != artifact_counts["artifact_count"]:
        target.errors.append("agentic_training_result passed receipts require all artifact refs to be regular files.")
    if status == "completed" and artifact_counts["output_artifact_count"] == 0:
        target.errors.append("agentic_training_result completed receipts must include an adapter or checkpoint artifact.")

    if expected_passed and status == "completed":
        expected_recommendation = REGISTER_RESULT_RECOMMENDATION
    elif expected_passed:
        expected_recommendation = REGISTER_FAILURE_RECOMMENDATION
    else:
        expected_recommendation = BLOCK_REGISTRATION_RECOMMENDATION
    if result.get("recommendation") != expected_recommendation:
        target.errors.append(
            f"agentic_training_result.recommendation expected {expected_recommendation!r}, got {result.get('recommendation')!r}."
        )
    blocked_reasons = result.get("blocked_reasons")
    if not _is_string_list(blocked_reasons):
        target.errors.append("agentic_training_result.blocked_reasons must be a list of strings.")
    elif expected_passed and blocked_reasons:
        target.errors.append("agentic_training_result.blocked_reasons must be empty when passed.")
    elif not expected_passed and len(blocked_reasons) != failed_checks:
        target.errors.append("agentic_training_result.blocked_reasons must match failed_check_count.")

    _validate_agentic_training_result_lineage(result.get("lineage"), target, source_path, status, expected_passed)
    _validate_agentic_training_result_boundary(result.get("execution_boundary"), target, "execution_boundary")
    _validate_agentic_training_result_contract(result.get("handoff_contract"), target)
    if "registry_update" in result:
        _validate_agentic_training_result_registry_update(
            result.get("registry_update"), expected_passed, target, result.get("artifacts"), status, artifact_path
        )
    elif status == "completed":
        target.errors.append("agentic_training_result.registry_update is required for completed receipts.")
    notes = result.get("notes")
    if not isinstance(notes, list) or not all(isinstance(item, str) for item in notes):
        target.errors.append("agentic_training_result.notes must be a list of strings.")

    target.details.update(
        {
            "status": status,
            "recommendation": result.get("recommendation"),
            "artifact_count": artifact_counts["artifact_count"],
            "output_artifact_count": artifact_counts["output_artifact_count"],
        }
    )


AGENTIC_LOOP_CLOUD_TRAINING_ROLES: tuple[str, ...] = (
    "cloud_training_provider_registry",
    "cloud_training_preflight",
    "cloud_training_artifact_manifest",
    "cloud_training_launch_plan",
    "cloud_training_launch_receipt",
    "cloud_training_status_receipt",
)

def _validate_agentic_training_loop_plan(plan: dict[str, Any], target: ValidationTarget, source_path: Path) -> None:
    _require_equal(plan, "schema_version", AGENTIC_TRAINING_LOOP_PLAN_SCHEMA_VERSION, target, prefix="agentic_training_loop_plan.")
    checks = plan.get("checks")
    if not isinstance(checks, list):
        target.errors.append("agentic_training_loop_plan.checks must be a list.")
        checks = []
    failed_checks = _validate_gate_like_checks(checks, target, "agentic_training_loop_plan.checks")
    if plan.get("check_count") != len(checks):
        target.errors.append(f"agentic_training_loop_plan.check_count expected {len(checks)}, got {plan.get('check_count')!r}.")
    if plan.get("failed_check_count") != failed_checks:
        target.errors.append(
            f"agentic_training_loop_plan.failed_check_count expected {failed_checks}, got {plan.get('failed_check_count')!r}."
        )
    if plan.get("passed") != (failed_checks == 0):
        target.errors.append("agentic_training_loop_plan.passed must match failed_check_count.")
    if not isinstance(plan.get("iteration_id"), str) or not plan.get("iteration_id"):
        target.errors.append("agentic_training_loop_plan.iteration_id must be a non-empty string.")
    plan_path = plan.get("plan_path")
    if not isinstance(plan_path, str) or not plan_path:
        target.errors.append("agentic_training_loop_plan.plan_path must be a non-empty string.")
    elif not _is_safe_agentic_training_result_path(plan_path):
        target.errors.append("agentic_training_loop_plan.plan_path must be a safe relative path without traversal.")

    source_artifacts = plan.get("source_artifacts")
    artifact_count = 0
    if not isinstance(source_artifacts, dict):
        target.errors.append("agentic_training_loop_plan.source_artifacts must be an object.")
        source_artifacts = {}
    else:
        for role, refs in source_artifacts.items():
            if not isinstance(role, str) or not role:
                target.errors.append("agentic_training_loop_plan.source_artifacts keys must be non-empty strings.")
            if not isinstance(refs, list):
                target.errors.append(f"agentic_training_loop_plan.source_artifacts.{role} must be a list.")
                continue
            artifact_count += len(refs)
            for index, ref in enumerate(refs):
                _validate_agentic_training_loop_plan_ref(
                    ref,
                    target,
                    f"agentic_training_loop_plan.source_artifacts.{role}[{index}]",
                    source_path,
                )
    if plan.get("artifact_count") != artifact_count:
        target.errors.append(f"agentic_training_loop_plan.artifact_count expected {artifact_count}, got {plan.get('artifact_count')!r}.")
    cloud_training_receipt_state = _expected_agentic_training_loop_cloud_training_receipt_state(
        source_artifacts,
        source_path,
    )
    _validate_agentic_training_loop_cloud_training(
        plan.get("cloud_training"),
        source_artifacts,
        cloud_training_receipt_state,
        target,
        "agentic_training_loop_plan.cloud_training",
    )
    _validate_agentic_training_loop_cloud_training_receipt_state(
        plan.get("cloud_training_receipt_state"),
        cloud_training_receipt_state,
        target,
        "agentic_training_loop_plan.cloud_training_receipt_state",
    )
    _validate_agentic_training_loop_cloud_training_lineage(
        plan.get("cloud_training_lineage"),
        source_artifacts,
        target,
        "agentic_training_loop_plan.cloud_training_lineage",
        source_path,
    )
    check = _cloud_training_check_by_id(
        checks,
        "cloud_training_receipts_are_side_effect_free",
        target,
        "agentic_training_loop_plan.checks",
    )
    if check is not None and check.get("passed") != cloud_training_receipt_state["fail_closed"]:
        target.errors.append(
            "agentic_training_loop_plan.checks.cloud_training_receipts_are_side_effect_free.passed must match receipt state."
        )

    phases = plan.get("phases")
    if not isinstance(phases, list) or not phases:
        target.errors.append("agentic_training_loop_plan.phases must be a non-empty list.")
        phase_missing_inputs: list[str] = []
    else:
        for index, phase in enumerate(phases):
            _validate_agentic_training_loop_plan_phase(phase, target, f"agentic_training_loop_plan.phases[{index}]")
        phase_missing_inputs = sorted(
            {
                item
                for phase in phases
                if isinstance(phase, dict) and isinstance(phase.get("missing_required_artifacts"), list)
                for item in phase["missing_required_artifacts"]
                if isinstance(item, str)
            }
        )
    if plan.get("missing_phase_inputs") != phase_missing_inputs:
        target.errors.append("agentic_training_loop_plan.missing_phase_inputs must match phase missing_required_artifacts.")
    expected_readiness = "ready_for_governance_review" if failed_checks == 0 and not phase_missing_inputs else "planned_fail_closed"
    if plan.get("readiness") != expected_readiness:
        target.errors.append(f"agentic_training_loop_plan.readiness expected {expected_readiness!r}, got {plan.get('readiness')!r}.")
    expected_recommendation = (
        "approve_iteration_execution"
        if expected_readiness == "ready_for_governance_review"
        else "collect_missing_receipts_before_live_execution"
    )
    if plan.get("recommendation") != expected_recommendation:
        target.errors.append(
            f"agentic_training_loop_plan.recommendation expected {expected_recommendation!r}, got {plan.get('recommendation')!r}."
        )

    boundary = plan.get("execution_boundary")
    if not isinstance(boundary, dict):
        target.errors.append("agentic_training_loop_plan.execution_boundary must be an object.")
    else:
        for field_name in ("dry_run_plan_only", "public_artifact_paths_redacted"):
            if boundary.get(field_name) is not True:
                target.errors.append(f"agentic_training_loop_plan.execution_boundary.{field_name} must be true.")
        for field_name in (
            "cloud_jobs_started",
            "paid_model_grader_calls_started",
            "live_benchmarks_started",
            "model_downloads_started",
            "weights_updated_by_flight_recorder",
            "credential_values_recorded",
        ):
            if boundary.get(field_name) is not False:
                target.errors.append(f"agentic_training_loop_plan.execution_boundary.{field_name} must be false.")

    contract = plan.get("handoff_contract")
    if not isinstance(contract, dict):
        target.errors.append("agentic_training_loop_plan.handoff_contract must be an object.")
    else:
        for field_name in (
            "flight_recorder_controls_preflight_and_receipts",
            "external_trainers_own_weight_updates",
            "live_launch_requires_explicit_opt_in",
            "requires_environment_credentials_for_live",
            "requires_trainer_preflight",
            "requires_trainer_launch_check",
            "requires_calibrated_review_before_training_data",
            "requires_heldout_eval_before_promotion",
            "requires_governance_decision_before_alias_update",
        ):
            if contract.get(field_name) is not True:
                target.errors.append(f"agentic_training_loop_plan.handoff_contract.{field_name} must be true.")
        if contract.get("default_live_execution_allowed") is not False:
            target.errors.append("agentic_training_loop_plan.handoff_contract.default_live_execution_allowed must be false.")

    target.details.update(
        {
            "iteration_id": plan.get("iteration_id"),
            "readiness": plan.get("readiness"),
            "artifact_count": plan.get("artifact_count"),
            "phase_count": len(phases) if isinstance(phases, list) else 0,
        }
    )


def _validate_agentic_training_loop_plan_ref(ref: Any, target: ValidationTarget, label: str, source_path: Path) -> None:
    if not isinstance(ref, dict):
        target.errors.append(f"{label} must be an object.")
        return
    for field_name in ("role", "path", "kind"):
        if not isinstance(ref.get(field_name), str) or not ref.get(field_name):
            target.errors.append(f"{label}.{field_name} must be a non-empty string.")
    path_value = ref.get("path")
    if isinstance(path_value, str) and path_value and not _is_safe_agentic_training_result_path(path_value):
        target.errors.append(f"{label}.path must be a safe relative path without traversal.")
    if ref.get("kind") not in {"file", "directory"}:
        target.errors.append(f"{label}.kind must be 'file' or 'directory'.")
    if not isinstance(ref.get("exists"), bool):
        target.errors.append(f"{label}.exists must be a boolean.")
    if ref.get("kind") == "file" and ref.get("exists") is True:
        if not isinstance(ref.get("sha256"), str) or len(ref.get("sha256", "")) != 64:
            target.errors.append(f"{label}.sha256 must be a SHA-256 string for existing files.")
        if not isinstance(ref.get("size_bytes"), int) or ref.get("size_bytes") < 0:
            target.errors.append(f"{label}.size_bytes must be a non-negative integer for existing files.")
        file_path = _resolve_agentic_training_loop_plan_ref_path(path_value, source_path)
        if file_path is not None and _path_has_symlink_component(file_path, include_leaf=True):
            target.errors.append(f"{label}.path must resolve to a regular non-symlink file.")
            return
        if file_path is None or not file_path.exists() or not file_path.is_file():
            target.errors.append(f"{label}.path does not resolve to an existing file.")
            return
        if isinstance(ref.get("size_bytes"), int) and ref.get("size_bytes") >= 0 and file_path.stat().st_size != ref.get("size_bytes"):
            target.errors.append(f"{label}.size_bytes does not match the current file.")
        if isinstance(ref.get("sha256"), str) and len(ref.get("sha256", "")) == 64 and _sha256(file_path) != ref.get("sha256"):
            target.errors.append(f"{label}.sha256 does not match the current file.")


def _resolve_agentic_training_loop_plan_ref_path(value: Any, source_path: Path) -> Path | None:
    if not isinstance(value, str) or not _is_safe_agentic_training_result_path(value):
        return None
    return source_path.parent / value


def _validate_agentic_training_loop_plan_phase(phase: Any, target: ValidationTarget, label: str) -> None:
    if not isinstance(phase, dict):
        target.errors.append(f"{label} must be an object.")
        return
    for field_name in ("id", "name", "gate"):
        if not isinstance(phase.get(field_name), str) or not phase.get(field_name):
            target.errors.append(f"{label}.{field_name} must be a non-empty string.")
    if phase.get("status") not in {"planned", "blocked", "ready"}:
        target.errors.append(f"{label}.status has an unsupported value.")
    required = phase.get("required_artifacts")
    present = phase.get("present_required_artifacts")
    missing = phase.get("missing_required_artifacts")
    produces = phase.get("produces")
    if not _is_string_list(required):
        target.errors.append(f"{label}.required_artifacts must be a list of strings.")
        required = []
    if not _is_string_list(present):
        target.errors.append(f"{label}.present_required_artifacts must be a list of strings.")
        present = []
    if not _is_string_list(missing):
        target.errors.append(f"{label}.missing_required_artifacts must be a list of strings.")
        missing = []
    if not _is_string_list(produces):
        target.errors.append(f"{label}.produces must be a list of strings.")
    if sorted(set(present) | set(missing)) != sorted(set(required)):
        target.errors.append(f"{label}.present_required_artifacts plus missing_required_artifacts must match required_artifacts.")
    if phase.get("status") == "ready" and missing:
        target.errors.append(f"{label}.status cannot be ready while required artifacts are missing.")
    if phase.get("status") == "blocked" and not missing:
        target.errors.append(f"{label}.status cannot be blocked without missing required artifacts.")


def _validate_agentic_training_loop_cloud_training(
    value: Any,
    source_artifacts: dict[str, Any],
    receipt_state: dict[str, Any],
    target: ValidationTarget,
    label: str,
) -> None:
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    present = [role for role in AGENTIC_LOOP_CLOUD_TRAINING_ROLES if _agentic_loop_role_count(source_artifacts, role) > 0]
    missing = [role for role in AGENTIC_LOOP_CLOUD_TRAINING_ROLES if role not in present]
    expected = {
        "required_artifacts": list(AGENTIC_LOOP_CLOUD_TRAINING_ROLES),
        "present_artifacts": present,
        "missing_artifacts": missing,
        "artifact_count": sum(_agentic_loop_role_count(source_artifacts, role) for role in AGENTIC_LOOP_CLOUD_TRAINING_ROLES),
        "provider_registry_present": "cloud_training_provider_registry" in present,
        "preflight_present": "cloud_training_preflight" in present,
        "artifact_manifest_present": "cloud_training_artifact_manifest" in present,
        "launch_plan_present": "cloud_training_launch_plan" in present,
        "launch_receipt_present": "cloud_training_launch_receipt" in present,
        "status_receipt_present": "cloud_training_status_receipt" in present,
        "provider_api_calls_started": receipt_state["provider_api_calls_started"],
        "cloud_jobs_started": receipt_state["cloud_jobs_started"],
        "credential_values_recorded": receipt_state["credential_values_recorded"],
        "live_spend_allowed": False,
    }
    for field_name, expected_value in expected.items():
        if value.get(field_name) != expected_value:
            target.errors.append(f"{label}.{field_name} must match cloud training source artifacts.")


def _validate_agentic_training_loop_cloud_training_receipt_state(
    value: Any,
    expected: dict[str, Any],
    target: ValidationTarget,
    label: str,
) -> None:
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    for field_name, expected_value in expected.items():
        if value.get(field_name) != expected_value:
            target.errors.append(f"{label}.{field_name} must match cloud training receipt artifacts.")


def _validate_agentic_training_loop_cloud_training_lineage(
    value: Any,
    source_artifacts: dict[str, Any],
    target: ValidationTarget,
    label: str,
    source_path: Path,
) -> None:
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    expected = _expected_agentic_training_loop_cloud_training_lineage(source_artifacts, source_path)
    for field_name in (
        "passed",
        "required_link_count",
        "matched_link_count",
        "missing_link_count",
        "mismatched_link_count",
        "ambiguous_link_count",
        "duplicate_role_count",
        "missing_links",
        "mismatched_links",
        "ambiguous_links",
        "duplicate_roles",
        "role_counts",
    ):
        if value.get(field_name) != expected[field_name]:
            target.errors.append(f"{label}.{field_name} must match cloud training source lineage.")
    if value.get("provider") != expected["provider"]:
        target.errors.append(f"{label}.provider must match cloud training provider lineage.")
    links = value.get("links")
    if not isinstance(links, list):
        target.errors.append(f"{label}.links must be a list.")
        links = []
    if len(links) != len(expected["links"]):
        target.errors.append(f"{label}.links must include every required cloud training source link.")
    for index, expected_link in enumerate(expected["links"]):
        if index >= len(links) or not isinstance(links[index], dict):
            target.errors.append(f"{label}.links[{index}] must be an object.")
            continue
        for field_name, expected_value in expected_link.items():
            if links[index].get(field_name) != expected_value:
                target.errors.append(f"{label}.links[{index}].{field_name} must match cloud training source lineage.")


def _expected_agentic_training_loop_cloud_training_lineage(
    source_artifacts: dict[str, Any],
    source_path: Path,
) -> dict[str, Any]:
    provider = _expected_agentic_training_loop_cloud_training_provider_lineage(source_artifacts, source_path)
    links = [
        _expected_agentic_training_loop_cloud_training_link(source_artifacts, source_path, spec)
        for spec in CLOUD_TRAINING_LINEAGE_LINKS
    ]
    missing_links = [link["id"] for link in links if link["status"].startswith("missing_")]
    mismatched_links = [link["id"] for link in links if link["status"] == "mismatched_sha256"]
    ambiguous_links = [link["id"] for link in links if link["status"].startswith("ambiguous_")]
    role_counts = _expected_agentic_training_loop_cloud_training_role_counts(source_artifacts)
    duplicate_roles = [row["role"] for row in role_counts if row["count"] > 1]
    matched_link_count = sum(1 for link in links if link["passed"])
    passed = (
        provider["provider_consistent"]
        and provider["registry_contains_pipeline_provider"]
        and not missing_links
        and not mismatched_links
        and not ambiguous_links
        and not duplicate_roles
    )
    return {
        "passed": passed,
        "required_link_count": len(links),
        "matched_link_count": matched_link_count,
        "missing_link_count": len(missing_links),
        "mismatched_link_count": len(mismatched_links),
        "ambiguous_link_count": len(ambiguous_links),
        "duplicate_role_count": len(duplicate_roles),
        "missing_links": missing_links,
        "mismatched_links": mismatched_links,
        "ambiguous_links": ambiguous_links,
        "duplicate_roles": duplicate_roles,
        "role_counts": role_counts,
        "provider": provider,
        "links": links,
    }


def _expected_agentic_training_loop_cloud_training_receipt_state(
    source_artifacts: dict[str, Any],
    source_path: Path,
) -> dict[str, Any]:
    launch_payloads = _agentic_training_loop_payloads(source_artifacts, "cloud_training_launch_receipt", source_path)
    status_payloads = _agentic_training_loop_payloads(source_artifacts, "cloud_training_status_receipt", source_path)
    all_payloads = [*launch_payloads, *status_payloads]
    first_launch_payload = launch_payloads[0] if launch_payloads else {}
    first_status_payload = status_payloads[0] if status_payloads else {}
    first_launch = _agentic_training_loop_cloud_training_launch(first_launch_payload)
    first_status = _agentic_training_loop_cloud_training_status(first_status_payload)
    provider_api_calls_started = any(
        _agentic_training_loop_cloud_training_launch(payload).get("provider_api_called") is True for payload in launch_payloads
    ) or any(
        _agentic_training_loop_cloud_training_status(payload).get("provider_api_called") is True for payload in status_payloads
    ) or any(
        _agentic_training_loop_cloud_training_boundary(payload).get("provider_api_called") is True
        for payload in all_payloads
    )
    cloud_jobs_started = any(
        _agentic_training_loop_cloud_training_launch(payload).get("cloud_job_started") is True for payload in launch_payloads
    ) or any(
        _agentic_training_loop_cloud_training_boundary(payload).get("cloud_job_started") is True
        for payload in all_payloads
    )
    provider_cancel_called = any(
        _agentic_training_loop_cloud_training_status(payload).get("provider_cancel_called") is True for payload in status_payloads
    )
    credential_values_recorded = any(
        _agentic_training_loop_cloud_training_boundary(payload).get("credential_values_recorded") is True
        for payload in all_payloads
    )
    cost_incurred_usd = sum(
        _safe_non_negative_number(_agentic_training_loop_cloud_training_launch(payload).get("cost_incurred_usd"))
        for payload in launch_payloads
    ) + sum(
        _safe_non_negative_number(_agentic_training_loop_cloud_training_status(payload).get("cost_incurred_usd"))
        for payload in status_payloads
    ) + sum(
        _safe_non_negative_number(_agentic_training_loop_cloud_training_boundary(payload).get("cloud_cost_incurred_usd"))
        for payload in all_payloads
    )
    launch_mode = str(first_launch.get("mode") or "")
    status_provider_status = str(first_status.get("provider_status") or "")
    live_launch_requested = any(
        _agentic_training_loop_cloud_training_launch(payload).get("mode") == "live"
        or _agentic_training_loop_cloud_training_boundary(payload).get("live_requested") is True
        for payload in launch_payloads
    ) or any(
        _agentic_training_loop_cloud_training_boundary(payload).get("live_requested") is True for payload in status_payloads
    )
    fail_closed = (
        provider_api_calls_started is False
        and cloud_jobs_started is False
        and provider_cancel_called is False
        and credential_values_recorded is False
        and live_launch_requested is False
        and cost_incurred_usd == 0
    )
    return {
        "launch_receipt_count": len(launch_payloads),
        "status_receipt_count": len(status_payloads),
        "launch_receipt_passed": bool(launch_payloads) and all(payload.get("passed") is True for payload in launch_payloads),
        "status_receipt_passed": bool(status_payloads) and all(payload.get("passed") is True for payload in status_payloads),
        "receipts_passed": bool(launch_payloads)
        and bool(status_payloads)
        and all(payload.get("passed") is True for payload in all_payloads),
        "launch_mode": launch_mode,
        "launch_readiness": str(first_launch_payload.get("readiness") or ""),
        "launch_recommendation": str(first_launch_payload.get("recommendation") or ""),
        "live_launch_requested": live_launch_requested,
        "status_provider_status": status_provider_status,
        "status_terminal": bool(status_payloads)
        and all(_agentic_training_loop_cloud_training_status(payload).get("terminal") is True for payload in status_payloads),
        "status_not_started": status_provider_status == "not_started",
        "status_readiness": str(first_status_payload.get("readiness") or ""),
        "status_recommendation": str(first_status_payload.get("recommendation") or ""),
        "provider_api_calls_started": provider_api_calls_started,
        "cloud_jobs_started": cloud_jobs_started,
        "provider_cancel_called": provider_cancel_called,
        "credential_values_recorded": credential_values_recorded,
        "cost_incurred_usd": cost_incurred_usd,
        "fail_closed": fail_closed,
    }


def _agentic_training_loop_cloud_training_launch(payload: dict[str, Any]) -> dict[str, Any]:
    launch = payload.get("launch")
    return launch if isinstance(launch, dict) else {}


def _agentic_training_loop_cloud_training_status(payload: dict[str, Any]) -> dict[str, Any]:
    status = payload.get("status")
    return status if isinstance(status, dict) else {}


def _agentic_training_loop_cloud_training_boundary(payload: dict[str, Any]) -> dict[str, Any]:
    boundary = payload.get("execution_boundary")
    return boundary if isinstance(boundary, dict) else {}


def _expected_agentic_training_loop_cloud_training_provider_lineage(
    source_artifacts: dict[str, Any],
    source_path: Path,
) -> dict[str, Any]:
    registry_provider_ids = sorted(
        {
            provider_id
            for payload in _agentic_training_loop_payloads(source_artifacts, "cloud_training_provider_registry", source_path)
            for provider_id in _agentic_training_loop_registry_provider_ids(payload)
        }
    )
    provider_by_role = {
        role: _agentic_training_loop_provider_id(_agentic_training_loop_first_payload(source_artifacts, role, source_path))
        for role in ("cloud_training_preflight", "cloud_training_artifact_manifest", "cloud_training_launch_plan")
    }
    pipeline_provider_ids = sorted({provider_id for provider_id in provider_by_role.values() if provider_id})
    pipeline_provider_id = pipeline_provider_ids[0] if len(pipeline_provider_ids) == 1 else ""
    return {
        "registry_provider_ids": registry_provider_ids,
        "pipeline_provider_ids": pipeline_provider_ids,
        "pipeline_provider_id": pipeline_provider_id,
        "provider_by_role": provider_by_role,
        "provider_consistent": len(pipeline_provider_ids) == 1,
        "registry_contains_pipeline_provider": bool(pipeline_provider_id) and pipeline_provider_id in registry_provider_ids,
    }


def _expected_agentic_training_loop_cloud_training_link(
    source_artifacts: dict[str, Any],
    source_path: Path,
    spec: dict[str, str],
) -> dict[str, Any]:
    source_role = spec["source_role"]
    target_role = spec["target_role"]
    source_ref_name = spec["source_ref"]
    source_count = _agentic_loop_role_count(source_artifacts, source_role)
    target_count = _agentic_loop_role_count(source_artifacts, target_role)
    source_ref = _agentic_training_loop_first_ref(source_artifacts, source_role)
    target_ref = _agentic_training_loop_first_ref(source_artifacts, target_role)
    source_payload = _agentic_training_loop_first_payload(source_artifacts, source_role, source_path)
    nested_refs = source_payload.get("source_artifacts") if isinstance(source_payload.get("source_artifacts"), dict) else {}
    nested_ref = nested_refs.get(source_ref_name) if isinstance(nested_refs, dict) else None
    nested_ref = nested_ref if isinstance(nested_ref, dict) else {}
    nested_sha = nested_ref.get("sha256") if isinstance(nested_ref.get("sha256"), str) else ""
    target_sha = target_ref.get("sha256") if isinstance(target_ref.get("sha256"), str) else ""
    status = "matched"
    if source_count > 1:
        status = "ambiguous_source_artifacts"
    elif target_count > 1:
        status = "ambiguous_target_artifacts"
    elif not source_ref:
        status = "missing_source_artifact"
    elif not target_ref:
        status = "missing_target_artifact"
    elif not nested_ref:
        status = "missing_source_link"
    elif not nested_sha:
        status = "missing_source_link_sha256"
    elif not target_sha:
        status = "missing_target_sha256"
    elif nested_sha != target_sha:
        status = "mismatched_sha256"
    return {
        "id": spec["id"],
        "source_role": source_role,
        "source_ref": source_ref_name,
        "target_role": target_role,
        "source_artifact_count": source_count,
        "target_artifact_count": target_count,
        "source_schema_version": source_ref.get("schema_version", "") if source_ref else "",
        "target_schema_version": target_ref.get("schema_version", "") if target_ref else "",
        "source_ref_sha256": nested_sha,
        "target_sha256": target_sha,
        "passed": status == "matched",
        "status": status,
    }


def _expected_agentic_training_loop_cloud_training_role_counts(source_artifacts: dict[str, Any]) -> list[dict[str, Any]]:
    return [
        {"role": role, "count": _agentic_loop_role_count(source_artifacts, role)}
        for role in CLOUD_TRAINING_LINEAGE_ARTIFACT_ROLES
    ]


def _agentic_training_loop_first_ref(source_artifacts: dict[str, Any], role: str) -> dict[str, Any]:
    rows = source_artifacts.get(role)
    return rows[0] if isinstance(rows, list) and rows and isinstance(rows[0], dict) else {}


def _agentic_training_loop_payloads(source_artifacts: dict[str, Any], role: str, source_path: Path) -> list[dict[str, Any]]:
    payloads: list[dict[str, Any]] = []
    rows = source_artifacts.get(role)
    if not isinstance(rows, list):
        return payloads
    for row in rows:
        if not isinstance(row, dict):
            continue
        path = _resolve_agentic_training_loop_plan_ref_path(row.get("path"), source_path)
        payload = _read_json_object_silent(path) if path is not None else {}
        if payload:
            payloads.append(payload)
    return payloads


def _agentic_training_loop_first_payload(source_artifacts: dict[str, Any], role: str, source_path: Path) -> dict[str, Any]:
    payloads = _agentic_training_loop_payloads(source_artifacts, role, source_path)
    return payloads[0] if payloads else {}


def _agentic_training_loop_registry_provider_ids(payload: dict[str, Any]) -> list[str]:
    providers = payload.get("providers")
    if not isinstance(providers, list):
        return []
    return [str(provider.get("id")) for provider in providers if isinstance(provider, dict) and str(provider.get("id") or "")]


def _agentic_training_loop_provider_id(payload: dict[str, Any]) -> str:
    provider = payload.get("provider")
    if not isinstance(provider, dict):
        return ""
    return str(provider.get("id") or "")


def _read_json_object_silent(path: Path | None) -> dict[str, Any]:
    if path is None:
        return {}
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return {}
    return payload if isinstance(payload, dict) else {}


def _validate_agentic_loop_ledger(ledger: dict[str, Any], target: ValidationTarget, ledger_path: Path) -> None:
    _require_equal(ledger, "schema_version", AGENTIC_LOOP_LEDGER_SCHEMA_VERSION, target, prefix="agentic_loop_ledger.")
    if ledger.get("passed") is not True:
        target.errors.append("agentic_loop_ledger.passed must be true.")
    iterations = ledger.get("iterations")
    if not isinstance(iterations, list) or not iterations:
        target.errors.append("agentic_loop_ledger.iterations must be a non-empty list.")
        iterations = []
    if ledger.get("iteration_count") != len(iterations):
        target.errors.append(f"agentic_loop_ledger.iteration_count expected {len(iterations)}, got {ledger.get('iteration_count')!r}.")
    ready_count = 0
    blocked_count = 0
    for index, row in enumerate(iterations):
        label = f"agentic_loop_ledger.iterations[{index}]"
        if not isinstance(row, dict):
            target.errors.append(f"{label} must be an object.")
            continue
        if row.get("index") != index:
            target.errors.append(f"{label}.index expected {index}, got {row.get('index')!r}.")
        if row.get("schema_version") != AGENTIC_TRAINING_LOOP_PLAN_SCHEMA_VERSION:
            target.errors.append(f"{label}.schema_version must be {AGENTIC_TRAINING_LOOP_PLAN_SCHEMA_VERSION!r}.")
        if not isinstance(row.get("iteration_id"), str) or not row.get("iteration_id"):
            target.errors.append(f"{label}.iteration_id must be a non-empty string.")
        if row.get("readiness") == "ready_for_governance_review":
            ready_count += 1
        else:
            blocked_count += 1
        if not _is_string_list(row.get("missing_phase_inputs")):
            target.errors.append(f"{label}.missing_phase_inputs must be a list of strings.")
        if not _is_non_negative_int(row.get("blocked_reason_count")):
            target.errors.append(f"{label}.blocked_reason_count must be a non-negative integer.")
        if not _is_non_negative_int(row.get("artifact_count")):
            target.errors.append(f"{label}.artifact_count must be a non-negative integer.")
        _validate_agentic_loop_ledger_counts(row.get("phase_status_counts"), target, f"{label}.phase_status_counts", "id")
        _validate_agentic_loop_ledger_counts(row.get("artifact_group_counts"), target, f"{label}.artifact_group_counts", "group")
        _validate_agentic_loop_ledger_counts(row.get("artifact_role_counts"), target, f"{label}.artifact_role_counts", "role")
        _validate_agentic_loop_ledger_source(row, target, ledger_path, label)
        governance = row.get("governance") if isinstance(row.get("governance"), dict) else {}
        for field_name in ("cloud_jobs_started", "paid_model_grader_calls_started", "weights_updated_by_flight_recorder"):
            if governance.get(field_name) is not False:
                target.errors.append(f"{label}.governance.{field_name} must be false.")
        _validate_agentic_loop_ledger_cloud_training(row.get("cloud_training"), row, target, f"{label}.cloud_training")
        _validate_agentic_loop_ledger_cloud_training_receipt_state(
            row.get("cloud_training_receipt_state"),
            row,
            target,
            ledger_path,
            f"{label}.cloud_training_receipt_state",
        )
        _validate_agentic_loop_ledger_cloud_training_lineage(row.get("cloud_training_lineage"), row, target, ledger_path, label)
    metrics = ledger.get("metrics")
    if not isinstance(metrics, dict):
        target.errors.append("agentic_loop_ledger.metrics must be an object.")
        metrics = {}
    if metrics.get("iteration_count") != len(iterations):
        target.errors.append("agentic_loop_ledger.metrics.iteration_count must match iteration_count.")
    if metrics.get("ready_iteration_count") != ready_count:
        target.errors.append("agentic_loop_ledger.metrics.ready_iteration_count does not match iterations.")
    if metrics.get("blocked_iteration_count") != blocked_count:
        target.errors.append("agentic_loop_ledger.metrics.blocked_iteration_count does not match iterations.")
    expected_decision = _build_agentic_loop_ledger_decision(iterations, metrics)
    expected_digest = _build_agentic_loop_ledger_readiness_digest(iterations, expected_decision)
    _validate_agentic_loop_ledger_decision(ledger.get("decision"), expected_decision, target)
    _validate_agentic_loop_ledger_digest(ledger.get("readiness_digest"), iterations, metrics, expected_decision, expected_digest, target)
    boundary = ledger.get("execution_boundary")
    if not isinstance(boundary, dict):
        target.errors.append("agentic_loop_ledger.execution_boundary must be an object.")
    else:
        if boundary.get("ledger_only") is not True:
            target.errors.append("agentic_loop_ledger.execution_boundary.ledger_only must be true.")
        for field_name in (
            "cloud_jobs_started",
            "paid_model_grader_calls_started",
            "live_benchmarks_started",
            "model_downloads_started",
            "weights_updated_by_flight_recorder",
            "credential_values_recorded",
        ):
            if boundary.get(field_name) is not False:
                target.errors.append(f"agentic_loop_ledger.execution_boundary.{field_name} must be false.")
    target.details.update(
        {
            "iteration_count": len(iterations),
            "latest_iteration_id": metrics.get("latest_iteration_id"),
            "latest_readiness": metrics.get("latest_readiness"),
        }
    )


def _validate_agentic_loop_ledger_digest(
    digest: Any,
    iterations: list[Any],
    metrics: dict[str, Any],
    decision: dict[str, Any],
    expected_digest: dict[str, Any],
    target: ValidationTarget,
) -> None:
    if not isinstance(digest, dict):
        target.errors.append("agentic_loop_ledger.readiness_digest must be an object.")
        return
    latest = iterations[-1] if iterations and isinstance(iterations[-1], dict) else {}
    missing_phase_inputs = digest.get("missing_phase_inputs")
    if not _is_string_list(missing_phase_inputs):
        target.errors.append("agentic_loop_ledger.readiness_digest.missing_phase_inputs must be a list of strings.")
        missing_phase_inputs = []
    if digest.get("missing_phase_input_count") != len(missing_phase_inputs):
        target.errors.append("agentic_loop_ledger.readiness_digest.missing_phase_input_count must match missing_phase_inputs.")
    missing_groups = digest.get("missing_artifact_groups")
    if not _is_string_list(missing_groups):
        target.errors.append("agentic_loop_ledger.readiness_digest.missing_artifact_groups must be a list of strings.")
        missing_groups = []
    if digest.get("missing_artifact_group_count") != len(missing_groups):
        target.errors.append("agentic_loop_ledger.readiness_digest.missing_artifact_group_count must match missing_artifact_groups.")
    if digest.get("side_effects_started") is not False:
        target.errors.append("agentic_loop_ledger.readiness_digest.side_effects_started must be false.")
    if latest:
        latest_missing_phase_inputs = (
            [item for item in latest.get("missing_phase_inputs", []) if isinstance(item, str)]
            if isinstance(latest.get("missing_phase_inputs"), list)
            else []
        )
        latest_group_counts = {
            row.get("group"): _safe_non_negative_int(row.get("count"))
            for row in latest.get("artifact_group_counts", [])
            if isinstance(row, dict) and isinstance(row.get("group"), str)
        }
        latest_missing_groups = sorted(group for group, count in latest_group_counts.items() if count == 0)
        if digest.get("latest_iteration_id") != latest.get("iteration_id"):
            target.errors.append("agentic_loop_ledger.readiness_digest.latest_iteration_id must match the latest iteration.")
        if digest.get("latest_iteration_index") != latest.get("index"):
            target.errors.append("agentic_loop_ledger.readiness_digest.latest_iteration_index must match the latest iteration.")
        if digest.get("readiness") != latest.get("readiness"):
            target.errors.append("agentic_loop_ledger.readiness_digest.readiness must match the latest iteration.")
        if digest.get("recommendation") != latest.get("recommendation"):
            target.errors.append("agentic_loop_ledger.readiness_digest.recommendation must match the latest iteration.")
        if digest.get("recommended_governance_action") != decision.get("recommended_governance_action"):
            target.errors.append("agentic_loop_ledger.readiness_digest.recommended_governance_action must match decision.")
        if missing_phase_inputs != latest_missing_phase_inputs:
            target.errors.append("agentic_loop_ledger.readiness_digest.missing_phase_inputs must match the latest iteration.")
        if missing_groups != latest_missing_groups:
            target.errors.append("agentic_loop_ledger.readiness_digest.missing_artifact_groups must match the latest iteration.")
        latest_lineage = latest.get("cloud_training_lineage") if isinstance(latest.get("cloud_training_lineage"), dict) else {}
        latest_lineage_provider = latest_lineage.get("provider") if isinstance(latest_lineage.get("provider"), dict) else {}
        latest_receipt_state = (
            latest.get("cloud_training_receipt_state") if isinstance(latest.get("cloud_training_receipt_state"), dict) else {}
        )
        expected_ready = (
            latest.get("readiness") == "ready_for_governance_review"
            and not latest_missing_phase_inputs
            and latest_lineage.get("passed") is True
            and latest_receipt_state.get("fail_closed") is True
        )
        if digest.get("ready_for_governance_review") != expected_ready:
            target.errors.append("agentic_loop_ledger.readiness_digest.ready_for_governance_review must match latest iteration readiness.")
        if digest.get("cloud_training_lineage_bound") != (latest_lineage.get("passed") is True):
            target.errors.append("agentic_loop_ledger.readiness_digest.cloud_training_lineage_bound must match the latest iteration.")
        if digest.get("cloud_training_receipts_fail_closed") != (latest_receipt_state.get("fail_closed") is True):
            target.errors.append("agentic_loop_ledger.readiness_digest.cloud_training_receipts_fail_closed must match the latest iteration.")
        if digest.get("cloud_training_live_launch_requested") != (latest_receipt_state.get("live_launch_requested") is True):
            target.errors.append(
                "agentic_loop_ledger.readiness_digest.cloud_training_live_launch_requested must match the latest iteration."
            )
        if digest.get("cloud_training_cost_incurred_usd") != _safe_non_negative_number(latest_receipt_state.get("cost_incurred_usd")):
            target.errors.append("agentic_loop_ledger.readiness_digest.cloud_training_cost_incurred_usd must match the latest iteration.")
        if digest.get("cloud_training_launch_mode") != str(latest_receipt_state.get("launch_mode") or ""):
            target.errors.append("agentic_loop_ledger.readiness_digest.cloud_training_launch_mode must match the latest iteration.")
        if digest.get("cloud_training_status_provider_status") != str(latest_receipt_state.get("status_provider_status") or ""):
            target.errors.append(
                "agentic_loop_ledger.readiness_digest.cloud_training_status_provider_status must match the latest iteration."
            )
        if digest.get("cloud_training_provider_id") != str(latest_lineage_provider.get("pipeline_provider_id") or ""):
            target.errors.append("agentic_loop_ledger.readiness_digest.cloud_training_provider_id must match the latest iteration.")
        if digest.get("cloud_training_missing_link_count") != _safe_non_negative_int(latest_lineage.get("missing_link_count")):
            target.errors.append("agentic_loop_ledger.readiness_digest.cloud_training_missing_link_count must match the latest iteration.")
        if digest.get("cloud_training_mismatched_link_count") != _safe_non_negative_int(latest_lineage.get("mismatched_link_count")):
            target.errors.append("agentic_loop_ledger.readiness_digest.cloud_training_mismatched_link_count must match the latest iteration.")
        if digest.get("cloud_training_ambiguous_link_count") != _safe_non_negative_int(latest_lineage.get("ambiguous_link_count")):
            target.errors.append("agentic_loop_ledger.readiness_digest.cloud_training_ambiguous_link_count must match the latest iteration.")
        if digest.get("cloud_training_duplicate_role_count") != _safe_non_negative_int(latest_lineage.get("duplicate_role_count")):
            target.errors.append("agentic_loop_ledger.readiness_digest.cloud_training_duplicate_role_count must match the latest iteration.")
        expected_summary = str(expected_digest.get("summary") or "")
        if digest.get("summary") != expected_summary:
            target.errors.append("agentic_loop_ledger.readiness_digest.summary must match latest iteration readiness.")
    if digest.get("latest_iteration_id") != metrics.get("latest_iteration_id"):
        target.errors.append("agentic_loop_ledger.readiness_digest.latest_iteration_id must match metrics.latest_iteration_id.")


def _validate_agentic_loop_ledger_decision(
    decision: Any,
    expected: dict[str, Any],
    target: ValidationTarget,
) -> None:
    if not isinstance(decision, dict):
        target.errors.append("agentic_loop_ledger.decision must be an object.")
        return
    for field_name in (
        "readiness",
        "recommendation",
        "recommended_governance_action",
        "governance_action_count",
        "latest_iteration_index",
        "latest_iteration_id",
        "blocked_iteration_count",
        "summary",
    ):
        if decision.get(field_name) != expected.get(field_name):
            target.errors.append(f"agentic_loop_ledger.decision.{field_name} must match latest iteration state.")
    if decision.get("governance_actions") != expected["governance_actions"]:
        target.errors.append("agentic_loop_ledger.decision.governance_actions must match latest iteration state.")


def _validate_agentic_loop_ledger_cloud_training(value: Any, row: dict[str, Any], target: ValidationTarget, label: str) -> None:
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    role_counts = _agentic_loop_count_map(row.get("artifact_role_counts"), "role")
    present = [role for role in AGENTIC_LOOP_CLOUD_TRAINING_ROLES if role_counts.get(role, 0) > 0]
    missing = [role for role in AGENTIC_LOOP_CLOUD_TRAINING_ROLES if role not in present]
    expected = {
        "group": "cloud_training",
        "artifact_count": sum(role_counts.get(role, 0) for role in AGENTIC_LOOP_CLOUD_TRAINING_ROLES),
        "roles_present": present,
        "roles_missing": missing,
        "provider_registry_present": "cloud_training_provider_registry" in present,
        "preflight_present": "cloud_training_preflight" in present,
        "artifact_manifest_present": "cloud_training_artifact_manifest" in present,
        "launch_plan_present": "cloud_training_launch_plan" in present,
        "launch_receipt_present": "cloud_training_launch_receipt" in present,
        "status_receipt_present": "cloud_training_status_receipt" in present,
        "provider_api_calls_started": False,
        "cloud_jobs_started": False,
        "credential_values_recorded": False,
        "live_spend_allowed": False,
    }
    for field_name, expected_value in expected.items():
        if value.get(field_name) != expected_value:
            target.errors.append(f"{label}.{field_name} must match ledger cloud training role counts.")


def _validate_agentic_loop_ledger_cloud_training_receipt_state(
    value: Any,
    row: dict[str, Any],
    target: ValidationTarget,
    ledger_path: Path,
    label: str,
) -> None:
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    source_path = _resolve_agentic_loop_ledger_source_path(row, ledger_path)
    if source_path is None or not source_path.exists() or not source_path.is_file():
        return
    source_plan = _read_json_object_silent(source_path)
    source_artifacts = source_plan.get("source_artifacts") if isinstance(source_plan.get("source_artifacts"), dict) else {}
    expected = _expected_agentic_training_loop_cloud_training_receipt_state(source_artifacts, source_path)
    for field_name, expected_value in expected.items():
        if value.get(field_name) != expected_value:
            target.errors.append(f"{label}.{field_name} must match source loop plan cloud training receipt artifacts.")


def _validate_agentic_loop_ledger_cloud_training_lineage(
    value: Any,
    row: dict[str, Any],
    target: ValidationTarget,
    ledger_path: Path,
    row_label: str,
) -> None:
    label = f"{row_label}.cloud_training_lineage"
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    source_path = _resolve_agentic_loop_ledger_source_path(row, ledger_path)
    if source_path is None or not source_path.exists() or not source_path.is_file():
        return
    source_plan = _read_json_object_silent(source_path)
    expected = source_plan.get("cloud_training_lineage") if isinstance(source_plan.get("cloud_training_lineage"), dict) else {}
    if value != expected:
        target.errors.append(f"{label} must match the source loop plan cloud_training_lineage.")


def _agentic_loop_role_count(source_artifacts: dict[str, Any], role: str) -> int:
    rows = source_artifacts.get(role)
    return len(rows) if isinstance(rows, list) else 0


def _agentic_loop_count_map(value: Any, key_name: str) -> dict[str, int]:
    if not isinstance(value, list):
        return {}
    counts: dict[str, int] = {}
    for row in value:
        if isinstance(row, dict) and isinstance(row.get(key_name), str):
            counts[row[key_name]] = _safe_non_negative_int(row.get("count"))
    return counts


def _validate_agentic_loop_ledger_counts(value: Any, target: ValidationTarget, label: str, key_name: str) -> None:
    if not isinstance(value, list):
        target.errors.append(f"{label} must be a list.")
        return
    seen: set[str] = set()
    for index, row in enumerate(value):
        row_label = f"{label}[{index}]"
        if not isinstance(row, dict):
            target.errors.append(f"{row_label} must be an object.")
            continue
        key = row.get(key_name)
        if not isinstance(key, str) or not key:
            target.errors.append(f"{row_label}.{key_name} must be a non-empty string.")
        elif key in seen:
            target.errors.append(f"{row_label}.{key_name} duplicates {key!r}.")
        seen.add(str(key))
        if not _is_non_negative_int(row.get("count")):
            target.errors.append(f"{row_label}.count must be a non-negative integer.")


def _validate_agentic_loop_ledger_source(row: dict[str, Any], target: ValidationTarget, ledger_path: Path, label: str) -> None:
    path_value = row.get("path")
    if not isinstance(path_value, str) or not path_value:
        target.errors.append(f"{label}.path must be a non-empty string.")
        return
    if not _is_safe_agentic_training_result_path(path_value):
        target.errors.append(f"{label}.path must be a safe relative path without traversal.")
        return
    source_path = _resolve_agentic_loop_ledger_source_path(row, ledger_path)
    if source_path is None:
        target.errors.append(f"{label}.path must be a safe relative path without traversal.")
        return
    if not source_path.exists() or not source_path.is_file():
        target.errors.append(f"{label}.path must resolve to an existing source loop plan.")
        return
    if row.get("exists") is not True:
        target.errors.append(f"{label}.exists must be true.")
    size = row.get("size_bytes")
    if not _is_non_negative_int(size):
        target.errors.append(f"{label}.size_bytes must be a non-negative integer.")
    elif source_path.stat().st_size != size:
        target.errors.append(f"{label}.size_bytes does not match the current file.")
    sha = row.get("sha256")
    if not _is_sha256(sha):
        target.errors.append(f"{label}.sha256 must be a sha256 hex digest.")
    elif _sha256(source_path) != sha:
        target.errors.append(f"{label}.sha256 does not match the current file.")


def _resolve_agentic_loop_ledger_source_path(row: dict[str, Any], ledger_path: Path) -> Path | None:
    path_value = row.get("path")
    if not isinstance(path_value, str) or not path_value or not _is_safe_agentic_training_result_path(path_value):
        return None
    return (ledger_path.parent / path_value).resolve()


def _validate_next_iteration_schedule(schedule: dict[str, Any], target: ValidationTarget) -> None:
    _require_equal(schedule, "schema_version", NEXT_ITERATION_SCHEDULE_SCHEMA_VERSION, target, prefix="next_iteration_schedule.")
    checks = schedule.get("checks")
    if not isinstance(checks, list):
        target.errors.append("next_iteration_schedule.checks must be a list.")
        checks = []
    failed_checks = _validate_gate_like_checks(checks, target, "next_iteration_schedule.checks")
    if schedule.get("check_count") != len(checks):
        target.errors.append(f"next_iteration_schedule.check_count expected {len(checks)}, got {schedule.get('check_count')!r}.")
    if schedule.get("failed_check_count") != failed_checks:
        target.errors.append(
            f"next_iteration_schedule.failed_check_count expected {failed_checks}, got {schedule.get('failed_check_count')!r}."
        )
    if schedule.get("passed") != (failed_checks == 0):
        target.errors.append("next_iteration_schedule.passed must match failed_check_count.")
    expected_readiness = "ready_to_schedule" if failed_checks == 0 else "blocked"
    if schedule.get("readiness") != expected_readiness:
        target.errors.append(f"next_iteration_schedule.readiness expected {expected_readiness!r}, got {schedule.get('readiness')!r}.")
    expected_recommendations = {"create_next_loop_plan", "monitor_or_promote_without_new_iteration"} if failed_checks == 0 else {"fix_schedule_inputs"}
    if schedule.get("recommendation") not in expected_recommendations:
        target.errors.append("next_iteration_schedule.recommendation does not match readiness.")
    if not _is_string_list(schedule.get("blocked_reasons")):
        target.errors.append("next_iteration_schedule.blocked_reasons must be a list of strings.")

    ledgers = schedule.get("source_ledgers")
    if not isinstance(ledgers, dict):
        target.errors.append("next_iteration_schedule.source_ledgers must be an object.")
        ledgers = {}
    expected_sources = {
        "agentic_loop_ledger": "hfr.agentic_loop_ledger.v1",
        "action_ledger": "hfr.action_ledger.v1",
        "improvement_ledger": "hfr.improvement_ledger.v1",
    }
    for role, schema_version in expected_sources.items():
        rows = ledgers.get(role)
        if not isinstance(rows, list) or len(rows) != 1:
            target.errors.append(f"next_iteration_schedule.source_ledgers.{role} must contain exactly one ref.")
            continue
        _validate_next_iteration_schedule_ref(rows[0], target, f"next_iteration_schedule.source_ledgers.{role}[0]", role, schema_version)

    pressure = schedule.get("pressure")
    if not isinstance(pressure, dict):
        target.errors.append("next_iteration_schedule.pressure must be an object.")
        pressure = {}
    else:
        for field_name in (
            "latest_missing_phase_input_count",
            "open_action_count",
            "recurring_action_count",
            "open_work_item_count",
            "critical_open_work_item_count",
            "high_open_work_item_count",
            "total_open_signal_count",
        ):
            if not _is_non_negative_int(pressure.get(field_name)):
                target.errors.append(f"next_iteration_schedule.pressure.{field_name} must be a non-negative integer.")
        expected_total = (
            _safe_non_negative_int(pressure.get("latest_missing_phase_input_count"))
            + _safe_non_negative_int(pressure.get("open_action_count"))
            + _safe_non_negative_int(pressure.get("open_work_item_count"))
        )
        if _is_non_negative_int(pressure.get("total_open_signal_count")) and pressure.get("total_open_signal_count") != expected_total:
            target.errors.append("next_iteration_schedule.pressure.total_open_signal_count must equal missing phases + open actions + open work.")
    next_iteration = schedule.get("next_iteration")
    if not isinstance(next_iteration, dict):
        target.errors.append("next_iteration_schedule.next_iteration must be an object.")
    else:
        for field_name in ("iteration_id", "objective", "trigger", "reason"):
            if not isinstance(next_iteration.get(field_name), str) or not next_iteration.get(field_name):
                target.errors.append(f"next_iteration_schedule.next_iteration.{field_name} must be a non-empty string.")
        if next_iteration.get("scheduled") is not False:
            target.errors.append("next_iteration_schedule.next_iteration.scheduled must be false.")
        if next_iteration.get("trigger") != "manual_or_external_scheduler":
            target.errors.append("next_iteration_schedule.next_iteration.trigger must be manual_or_external_scheduler.")
        if not isinstance(next_iteration.get("schedule"), dict):
            target.errors.append("next_iteration_schedule.next_iteration.schedule must be an object.")

    boundary = schedule.get("execution_boundary")
    if not isinstance(boundary, dict):
        target.errors.append("next_iteration_schedule.execution_boundary must be an object.")
    else:
        if boundary.get("schedule_only") is not True:
            target.errors.append("next_iteration_schedule.execution_boundary.schedule_only must be true.")
        for field_name in (
            "automations_created",
            "codex_threads_created",
            "calendar_events_created",
            "cloud_jobs_started",
            "weights_updated_by_flight_recorder",
            "credential_values_recorded",
        ):
            if boundary.get(field_name) is not False:
                target.errors.append(f"next_iteration_schedule.execution_boundary.{field_name} must be false.")
    target.details.update(
        {
            "readiness": schedule.get("readiness"),
            "recommendation": schedule.get("recommendation"),
            "next_iteration_id": next_iteration.get("iteration_id") if isinstance(next_iteration, dict) else None,
        }
    )


def _validate_next_iteration_schedule_ref(
    row: Any,
    target: ValidationTarget,
    label: str,
    role: str,
    schema_version: str,
) -> None:
    if not isinstance(row, dict):
        target.errors.append(f"{label} must be an object.")
        return
    if row.get("role") != role:
        target.errors.append(f"{label}.role must be {role!r}.")
    if row.get("kind") != "file":
        target.errors.append(f"{label}.kind must be 'file'.")
    if row.get("exists") is not True:
        target.errors.append(f"{label}.exists must be true.")
    if row.get("schema_version") != schema_version:
        target.errors.append(f"{label}.schema_version must be {schema_version!r}.")
    if row.get("passed") is not True:
        target.errors.append(f"{label}.passed must be true.")
    if not isinstance(row.get("path"), str) or not row.get("path"):
        target.errors.append(f"{label}.path must be a non-empty string.")
    if not _is_sha256(row.get("sha256")):
        target.errors.append(f"{label}.sha256 must be a SHA-256 hex string.")
    if not _is_non_negative_int(row.get("size_bytes")):
        target.errors.append(f"{label}.size_bytes must be a non-negative integer.")


def _safe_non_negative_int(value: Any) -> int:
    return value if _is_non_negative_int(value) else 0


def _safe_non_negative_number(value: Any) -> int | float:
    return value if isinstance(value, (int, float)) and not isinstance(value, bool) and value >= 0 else 0


def _validate_cloud_training_contract(
    payload: dict[str, Any],
    target: ValidationTarget,
    expected_schema_version: str,
    *,
    source_path: Path | None = None,
) -> None:
    _require_equal(payload, "schema_version", expected_schema_version, target, prefix=f"{target.target_type}.")
    checks = payload.get("checks")
    if checks is not None:
        if not isinstance(checks, list):
            target.errors.append(f"{target.target_type}.checks must be a list.")
            checks = []
        failed_checks = _validate_gate_like_checks(checks, target, f"{target.target_type}.checks")
        if payload.get("check_count") != len(checks):
            target.errors.append(f"{target.target_type}.check_count expected {len(checks)}, got {payload.get('check_count')!r}.")
        if payload.get("failed_check_count") != failed_checks:
            target.errors.append(
                f"{target.target_type}.failed_check_count expected {failed_checks}, got {payload.get('failed_check_count')!r}."
            )
        if isinstance(payload.get("passed"), bool) and payload.get("passed") != (failed_checks == 0):
            target.errors.append(f"{target.target_type}.passed must match failed_check_count.")
    boundary = payload.get("execution_boundary")
    if not isinstance(boundary, dict):
        target.errors.append(f"{target.target_type}.execution_boundary must be an object.")
    else:
        if boundary.get("provider_api_called") is not False:
            target.errors.append(f"{target.target_type}.execution_boundary.provider_api_called must be false.")
        if boundary.get("cloud_job_started") is not False:
            target.errors.append(f"{target.target_type}.execution_boundary.cloud_job_started must be false.")
        if boundary.get("credential_values_recorded") is not False:
            target.errors.append(f"{target.target_type}.execution_boundary.credential_values_recorded must be false.")
        if boundary.get("weights_updated_by_flight_recorder") is not False:
            target.errors.append(f"{target.target_type}.execution_boundary.weights_updated_by_flight_recorder must be false.")
        if boundary.get("cloud_cost_incurred_usd") != 0:
            target.errors.append(f"{target.target_type}.execution_boundary.cloud_cost_incurred_usd must be 0.")
    provider = payload.get("provider")
    if isinstance(provider, dict):
        _validate_cloud_training_provider_record(provider, target, f"{target.target_type}.provider")
    if expected_schema_version in {
        CLOUD_TRAINING_PREFLIGHT_SCHEMA_VERSION,
        CLOUD_TRAINING_LAUNCH_PLAN_SCHEMA_VERSION,
        CLOUD_TRAINING_LAUNCH_RECEIPT_SCHEMA_VERSION,
        CLOUD_TRAINING_STATUS_RECEIPT_SCHEMA_VERSION,
    }:
        _validate_cloud_training_source_artifacts(
            payload.get("source_artifacts"),
            target,
            f"{target.target_type}.source_artifacts",
            source_path,
            _cloud_training_required_source_artifacts(expected_schema_version),
        )
    if expected_schema_version == CLOUD_TRAINING_LAUNCH_PLAN_SCHEMA_VERSION:
        expected_provider_chain = _expected_cloud_training_launch_plan_provider_chain(
            payload.get("source_artifacts"),
            source_path,
        )
        _validate_cloud_training_launch_plan_source_refs(
            payload,
            checks if isinstance(checks, list) else [],
            payload.get("source_artifacts"),
            target,
            "cloud_training_launch_plan.source_artifacts",
        )
        _validate_cloud_training_launch_plan_provider_chain(
            payload.get("provider_chain"),
            expected_provider_chain,
            target,
        )
        _validate_cloud_training_launch_plan_provider_matches_chain(payload.get("provider"), expected_provider_chain, target)
        _validate_cloud_training_launch_plan_readiness(
            payload,
            checks if isinstance(checks, list) else [],
            expected_provider_chain,
            target,
            source_path,
        )
    if expected_schema_version == CLOUD_TRAINING_LAUNCH_RECEIPT_SCHEMA_VERSION:
        _validate_cloud_training_launch_receipt_readiness(
            payload,
            checks if isinstance(checks, list) else [],
            target,
            source_path,
        )
    if expected_schema_version == CLOUD_TRAINING_STATUS_RECEIPT_SCHEMA_VERSION:
        _validate_cloud_training_status_receipt_readiness(
            payload,
            checks if isinstance(checks, list) else [],
            target,
            source_path,
        )
    if expected_schema_version == CLOUD_TRAINING_ARTIFACT_MANIFEST_SCHEMA_VERSION:
        upload_artifacts = payload.get("upload_artifacts")
        expected_download_artifacts = payload.get("expected_download_artifacts")
        _validate_cloud_training_artifact_refs(
            upload_artifacts,
            target,
            f"{target.target_type}.upload_artifacts",
            source_path,
            require_non_empty=True,
        )
        _validate_cloud_training_artifact_refs(
            expected_download_artifacts,
            target,
            f"{target.target_type}.expected_download_artifacts",
            source_path,
        )
        _validate_cloud_training_transfer_plan(
            payload.get("transfer_plan"),
            target,
            upload_artifacts,
            expected_download_artifacts,
            payload.get("artifact_protocols"),
        )
    target.details.update(
        {
            "schema_version": payload.get("schema_version"),
            "readiness": payload.get("readiness"),
            "recommendation": payload.get("recommendation"),
            "check_count": payload.get("check_count"),
        }
    )


def _validate_cloud_training_provider_record(record: Any, target: ValidationTarget, label: str) -> None:
    if not isinstance(record, dict):
        target.errors.append(f"{label} must be an object.")
        return
    provider_id = record.get("id")
    if not isinstance(provider_id, str) or not provider_id:
        target.errors.append(f"{label}.id must be a non-empty string.")
        provider_id = ""
    if record.get("default_live_execution_allowed") is not False:
        target.errors.append(f"{label}.default_live_execution_allowed must be false.")
    contract = record.get("adapter_contract")
    _validate_cloud_training_adapter_contract(contract, target, f"{label}.adapter_contract", provider_id)


def _validate_cloud_training_adapter_contract(contract: Any, target: ValidationTarget, label: str, provider_id: str) -> None:
    if not isinstance(contract, dict):
        target.errors.append(f"{label} must be an object.")
        return
    if contract.get("schema_version") != CLOUD_TRAINING_PROVIDER_ADAPTER_CONTRACT_VERSION:
        target.errors.append(f"{label}.schema_version must be {CLOUD_TRAINING_PROVIDER_ADAPTER_CONTRACT_VERSION!r}.")
    if contract.get("provider_id") != provider_id:
        target.errors.append(f"{label}.provider_id must match provider id.")
    if not isinstance(contract.get("adapter_id"), str) or not contract.get("adapter_id"):
        target.errors.append(f"{label}.adapter_id must be a non-empty string.")
    receipt_types = contract.get("receipt_types")
    if not _is_string_list(receipt_types):
        target.errors.append(f"{label}.receipt_types must be a list of strings.")
        receipt_types = []
    missing_receipts = sorted(set(PROVIDER_ADAPTER_RECEIPT_TYPES) - set(receipt_types))
    if missing_receipts:
        target.errors.append(f"{label}.receipt_types missing required receipt types: {', '.join(missing_receipts)}.")
    if len(set(receipt_types)) != len(receipt_types):
        target.errors.append(f"{label}.receipt_types must not contain duplicates.")
    if contract.get("dry_run_transport") != "mock_receipts":
        target.errors.append(f"{label}.dry_run_transport must be mock_receipts.")
    if contract.get("live_preflight_transport") != "metadata_only":
        target.errors.append(f"{label}.live_preflight_transport must be metadata_only.")
    for field_name in (
        "live_preflight_supported",
        "status_cancel_receipts_supported",
        "requires_explicit_live_opt_in",
        "requires_environment_credentials_for_live",
        "requires_cost_limit",
        "requires_region_and_gpu_constraints",
    ):
        if contract.get(field_name) is not True:
            target.errors.append(f"{label}.{field_name} must be true.")
    for field_name in (
        "live_launch_supported",
        "provider_api_called_by_flight_recorder",
        "client_modules_imported_by_flight_recorder",
        "credential_values_recorded",
        "model_downloads_started",
        "weights_updated_by_flight_recorder",
    ):
        if contract.get(field_name) is not False:
            target.errors.append(f"{label}.{field_name} must be false.")
    if contract.get("cloud_cost_incurred_usd") != 0:
        target.errors.append(f"{label}.cloud_cost_incurred_usd must be 0.")


def _validate_cloud_training_source_artifacts(
    value: Any,
    target: ValidationTarget,
    label: str,
    source_path: Path | None,
    required_names: tuple[str, ...],
) -> None:
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    for name in required_names:
        if name not in value:
            target.errors.append(f"{label}.{name} is required.")
    for name, record in value.items():
        if not isinstance(name, str) or not name:
            target.errors.append(f"{label} keys must be non-empty strings.")
            continue
        _validate_cloud_training_artifact_ref(record, target, f"{label}.{name}", source_path)


def _validate_cloud_training_launch_plan_source_refs(
    payload: dict[str, Any],
    checks: list[Any],
    value: Any,
    target: ValidationTarget,
    label: str,
) -> None:
    if not isinstance(value, dict):
        return
    preflight_ref = value.get("preflight")
    if isinstance(preflight_ref, dict) and preflight_ref.get("exists") is not True:
        target.errors.append(f"{label}.preflight.exists must be true.")
    artifact_manifest_ref = value.get("artifact_manifest")
    if not isinstance(artifact_manifest_ref, dict) or artifact_manifest_ref.get("exists") is True:
        return
    if artifact_manifest_ref.get("path") != "":
        target.errors.append(
            "cloud_training_launch_plan.source_artifacts.artifact_manifest.path must be empty when artifact_manifest is missing."
        )
    failed_check_ids = {check.get("id") for check in checks if isinstance(check, dict) and check.get("passed") is False}
    for check_id in ("artifact_manifest_ready", "provider_chain_consistent"):
        if check_id not in failed_check_ids:
            target.errors.append(f"cloud_training_launch_plan.checks must include failed {check_id} when artifact_manifest is missing.")
    provider_chain = payload.get("provider_chain") if isinstance(payload.get("provider_chain"), dict) else {}
    if provider_chain.get("artifact_manifest_required") is not True:
        target.errors.append("cloud_training_launch_plan.provider_chain.artifact_manifest_required must be true.")
    if provider_chain.get("provider_consistent") is not False:
        target.errors.append(
            "cloud_training_launch_plan.provider_chain.provider_consistent must be false when artifact_manifest is missing."
        )
    if payload.get("readiness") != "blocked":
        target.errors.append("cloud_training_launch_plan.readiness must be blocked when artifact_manifest is missing.")
    if payload.get("recommendation") != "block_launch_receipt":
        target.errors.append("cloud_training_launch_plan.recommendation must be block_launch_receipt when artifact_manifest is missing.")


def _validate_cloud_training_artifact_refs(
    value: Any,
    target: ValidationTarget,
    label: str,
    source_path: Path | None,
    *,
    require_non_empty: bool = False,
) -> None:
    if not isinstance(value, list):
        target.errors.append(f"{label} must be a list.")
        return
    if require_non_empty and not value:
        target.errors.append(f"{label} must include at least one artifact.")
    for index, record in enumerate(value):
        _validate_cloud_training_artifact_ref(record, target, f"{label}[{index}]", source_path)


def _validate_cloud_training_transfer_plan(
    value: Any,
    target: ValidationTarget,
    upload_artifacts: Any,
    expected_download_artifacts: Any,
    artifact_protocols: Any,
) -> None:
    label = "cloud_training_artifact_manifest.transfer_plan"
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    uploads = upload_artifacts if isinstance(upload_artifacts, list) else []
    downloads = expected_download_artifacts if isinstance(expected_download_artifacts, list) else []
    protocols = artifact_protocols if _is_string_list(artifact_protocols) else []
    upload_size_bytes = 0
    for artifact in uploads:
        if isinstance(artifact, dict) and artifact.get("exists") is True and _is_non_negative_int(artifact.get("size_bytes")):
            upload_size_bytes += artifact["size_bytes"]
    expected_values = {
        "mode": "dry_run_manifest_only",
        "upload_count": len(uploads),
        "expected_download_count": len(downloads),
        "upload_size_bytes": upload_size_bytes,
        "artifact_protocols": protocols,
        "requires_external_runner_upload": bool(uploads),
        "requires_external_runner_download": bool(downloads),
        "download_artifacts_expected_to_exist_before_launch": False,
    }
    for field_name, expected in expected_values.items():
        if value.get(field_name) != expected:
            target.errors.append(f"{label}.{field_name} must match cloud training artifact rows.")
    for field_name in (
        "flight_recorder_uploaded_artifacts",
        "flight_recorder_downloaded_artifacts",
        "provider_api_called",
        "credential_values_recorded",
    ):
        if value.get(field_name) is not False:
            target.errors.append(f"{label}.{field_name} must be false.")


def _validate_cloud_training_launch_plan_provider_chain(
    value: Any,
    expected: dict[str, Any],
    target: ValidationTarget,
) -> None:
    label = "cloud_training_launch_plan.provider_chain"
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    for field_name, expected_value in expected.items():
        if value.get(field_name) != expected_value:
            target.errors.append(f"{label}.{field_name} must match launch-plan source providers.")


def _validate_cloud_training_launch_plan_provider_matches_chain(
    value: Any,
    expected_chain: dict[str, Any],
    target: ValidationTarget,
) -> None:
    expected_provider_id = expected_chain.get("preflight_provider_id")
    if not expected_provider_id:
        return
    provider_id = value.get("id") if isinstance(value, dict) else None
    if provider_id != expected_provider_id:
        target.errors.append("cloud_training_launch_plan.provider.id must match provider_chain.preflight_provider_id.")


def _validate_cloud_training_launch_plan_readiness(
    payload: dict[str, Any],
    checks: list[Any],
    expected_chain: dict[str, Any],
    target: ValidationTarget,
    source_path: Path | None,
) -> None:
    sources = payload.get("source_artifacts") if isinstance(payload.get("source_artifacts"), dict) else {}
    preflight_state = _cloud_training_source_state(
        sources.get("preflight"),
        source_path,
        "cloud_training_preflight",
    )
    artifact_manifest_state = _cloud_training_source_state(
        sources.get("artifact_manifest"),
        source_path,
        "cloud_training_artifact_manifest",
    )
    for role, state in (("preflight", preflight_state), ("artifact_manifest", artifact_manifest_state)):
        _validate_cloud_training_source_state(f"cloud_training_launch_plan.source_artifacts.{role}", state, target)
    expected_checks = {
        "preflight_ready": preflight_state["ready"],
        "artifact_manifest_ready": artifact_manifest_state["ready"],
        "provider_chain_consistent": expected_chain["provider_consistent"],
        "dry_run_launch_only": True,
    }
    for check_id, expected_passed in expected_checks.items():
        check = _cloud_training_check_by_id(checks, check_id, target, "cloud_training_launch_plan.checks")
        if check is None:
            continue
        if check.get("passed") != expected_passed:
            target.errors.append(f"cloud_training_launch_plan.checks.{check_id}.passed must match source readiness.")
    _validate_cloud_training_expected_state(
        "cloud_training_launch_plan",
        payload,
        expected_checks,
        ready_readiness="ready_for_dry_run_launch",
        ready_recommendation="emit_dry_run_launch_receipt",
        blocked_recommendation="block_launch_receipt",
        target=target,
    )


def _validate_cloud_training_launch_receipt_readiness(
    payload: dict[str, Any],
    checks: list[Any],
    target: ValidationTarget,
    source_path: Path | None,
) -> None:
    sources = payload.get("source_artifacts") if isinstance(payload.get("source_artifacts"), dict) else {}
    launch_plan_state = _cloud_training_source_state(
        sources.get("launch_plan"),
        source_path,
        "cloud_training_launch_plan",
    )
    _validate_cloud_training_source_state(
        "cloud_training_launch_receipt.source_artifacts.launch_plan",
        launch_plan_state,
        target,
    )
    launch = payload.get("launch") if isinstance(payload.get("launch"), dict) else {}
    if not isinstance(payload.get("launch"), dict):
        target.errors.append("cloud_training_launch_receipt.launch must be an object.")
    live_requested = launch.get("mode") == "live"
    if launch.get("mode") not in {"dry_run", "live"}:
        target.errors.append("cloud_training_launch_receipt.launch.mode must be dry_run or live.")
    if launch.get("cloud_job_started") is not False:
        target.errors.append("cloud_training_launch_receipt.launch.cloud_job_started must be false.")
    if launch.get("provider_api_called") is not False:
        target.errors.append("cloud_training_launch_receipt.launch.provider_api_called must be false.")
    if launch.get("provider_job_id") is not None:
        target.errors.append("cloud_training_launch_receipt.launch.provider_job_id must be null.")
    if launch.get("cost_incurred_usd") != 0:
        target.errors.append("cloud_training_launch_receipt.launch.cost_incurred_usd must be 0.")
    boundary = payload.get("execution_boundary") if isinstance(payload.get("execution_boundary"), dict) else {}
    if boundary.get("live_requested") != live_requested:
        target.errors.append("cloud_training_launch_receipt.execution_boundary.live_requested must match launch.mode.")
    if boundary.get("allow_live") is not False:
        target.errors.append("cloud_training_launch_receipt.execution_boundary.allow_live must be false.")
    cloud_job_not_started = (
        launch.get("cloud_job_started") is False
        and launch.get("provider_api_called") is False
        and launch.get("provider_job_id") is None
        and launch.get("cost_incurred_usd") == 0
    )
    expected_checks = {
        "launch_plan_ready": launch_plan_state["ready"],
        "live_launch_not_implemented": not live_requested,
        "cloud_job_not_started": cloud_job_not_started,
    }
    for check_id, expected_passed in expected_checks.items():
        check = _cloud_training_check_by_id(checks, check_id, target, "cloud_training_launch_receipt.checks")
        if check is not None and check.get("passed") != expected_passed:
            target.errors.append(f"cloud_training_launch_receipt.checks.{check_id}.passed must match source readiness.")
    _validate_cloud_training_expected_state(
        "cloud_training_launch_receipt",
        payload,
        expected_checks,
        ready_readiness="dry_run_recorded",
        ready_recommendation="safe_to_archive_dry_run_receipt",
        blocked_recommendation="block_live_cloud_launch",
        target=target,
    )


def _validate_cloud_training_status_receipt_readiness(
    payload: dict[str, Any],
    checks: list[Any],
    target: ValidationTarget,
    source_path: Path | None,
) -> None:
    sources = payload.get("source_artifacts") if isinstance(payload.get("source_artifacts"), dict) else {}
    launch_receipt_state = _cloud_training_source_state(
        sources.get("launch_receipt"),
        source_path,
        "cloud_training_launch_receipt",
    )
    _validate_cloud_training_source_state(
        "cloud_training_status_receipt.source_artifacts.launch_receipt",
        launch_receipt_state,
        target,
    )
    status = payload.get("status") if isinstance(payload.get("status"), dict) else {}
    if not isinstance(payload.get("status"), dict):
        target.errors.append("cloud_training_status_receipt.status must be an object.")
    if status.get("provider_status") != "not_started":
        target.errors.append("cloud_training_status_receipt.status.provider_status must be not_started.")
    if status.get("terminal") is not True:
        target.errors.append("cloud_training_status_receipt.status.terminal must be true.")
    if not isinstance(status.get("cancel_requested"), bool):
        target.errors.append("cloud_training_status_receipt.status.cancel_requested must be a boolean.")
    if status.get("provider_cancel_called") is not False:
        target.errors.append("cloud_training_status_receipt.status.provider_cancel_called must be false.")
    if status.get("provider_api_called") is not False:
        target.errors.append("cloud_training_status_receipt.status.provider_api_called must be false.")
    if status.get("cost_incurred_usd") != 0:
        target.errors.append("cloud_training_status_receipt.status.cost_incurred_usd must be 0.")
    expected_checks = {
        "launch_receipt_readable": launch_receipt_state["ref_exists"],
        "status_check_did_not_call_provider": status.get("provider_api_called") is False,
        "cancel_is_dry_run": status.get("provider_cancel_called") is False,
    }
    for check_id, expected_passed in expected_checks.items():
        check = _cloud_training_check_by_id(checks, check_id, target, "cloud_training_status_receipt.checks")
        if check is not None and check.get("passed") != expected_passed:
            target.errors.append(f"cloud_training_status_receipt.checks.{check_id}.passed must match source readiness.")
    _validate_cloud_training_expected_state(
        "cloud_training_status_receipt",
        payload,
        expected_checks,
        ready_readiness="status_recorded",
        ready_recommendation="archive_status_receipt",
        blocked_recommendation="inspect_launch_receipt",
        target=target,
    )


def _validate_cloud_training_expected_state(
    label: str,
    payload: dict[str, Any],
    expected_checks: dict[str, bool],
    *,
    ready_readiness: str,
    ready_recommendation: str,
    blocked_recommendation: str,
    target: ValidationTarget,
) -> None:
    expected_failed_count = sum(1 for passed in expected_checks.values() if not passed)
    expected_passed = expected_failed_count == 0
    if payload.get("failed_check_count") != expected_failed_count:
        target.errors.append(f"{label}.failed_check_count expected {expected_failed_count}.")
    if payload.get("passed") != expected_passed:
        target.errors.append(f"{label}.passed must match source readiness.")
    expected_readiness = ready_readiness if expected_passed else "blocked"
    expected_recommendation = ready_recommendation if expected_passed else blocked_recommendation
    if payload.get("readiness") != expected_readiness:
        target.errors.append(f"{label}.readiness must be {expected_readiness}.")
    if payload.get("recommendation") != expected_recommendation:
        target.errors.append(f"{label}.recommendation must be {expected_recommendation}.")


def _validate_cloud_training_source_state(label: str, state: dict[str, Any], target: ValidationTarget) -> None:
    ref = state["ref"]
    if not isinstance(ref, dict):
        return
    for field_name in ("schema_name", "schema_passed", "source_passed", "source_recommendation"):
        expected_value = state[field_name]
        if ref.get(field_name) != expected_value:
            target.errors.append(f"{label}.{field_name} must match the referenced source artifact.")


def _cloud_training_source_state(record: Any, source_path: Path | None, schema_name: str) -> dict[str, Any]:
    state = {
        "ref": record,
        "ref_exists": isinstance(record, dict) and record.get("exists") is True,
        "schema_name": schema_name,
        "schema_passed": False,
        "source_passed": None,
        "source_recommendation": "",
        "ready": False,
    }
    if not isinstance(record, dict) or record.get("exists") is not True:
        return state
    artifact_path = _resolve_cloud_training_artifact_path(record.get("path"), source_path)
    payload = _read_json_object_silent(artifact_path)
    schema_passed = _cloud_training_schema_check_passed(artifact_path, schema_name)
    source_passed = payload.get("passed") if isinstance(payload.get("passed"), bool) else None
    state.update(
        {
            "schema_passed": schema_passed,
            "source_passed": source_passed,
            "source_recommendation": str(payload.get("recommendation") or ""),
            "ready": schema_passed and source_passed is True,
        }
    )
    return state


def _cloud_training_schema_check_passed(path: Path | None, schema_name: str) -> bool:
    if path is None:
        return False
    try:
        return check_schema_file(path, schema_name).get("passed") is True
    except (OSError, json.JSONDecodeError, SchemaRegistryError):
        return False


def _cloud_training_check_by_id(
    checks: list[Any],
    check_id: str,
    target: ValidationTarget,
    label: str,
) -> dict[str, Any] | None:
    matches = [check for check in checks if isinstance(check, dict) and check.get("id") == check_id]
    if len(matches) != 1:
        target.errors.append(f"{label} must include exactly one {check_id} check.")
        return None
    return matches[0]


def _expected_cloud_training_launch_plan_provider_chain(source_artifacts: Any, source_path: Path | None) -> dict[str, Any]:
    sources = source_artifacts if isinstance(source_artifacts, dict) else {}
    preflight_provider_id = _cloud_training_provider_id_from_source_ref(sources.get("preflight"), source_path)
    artifact_manifest_ref = sources.get("artifact_manifest") if isinstance(sources.get("artifact_manifest"), dict) else {}
    artifact_manifest_required = True
    artifact_manifest_provider_id = _cloud_training_provider_id_from_source_ref(artifact_manifest_ref, source_path)
    provider_consistent = (
        bool(preflight_provider_id)
        and (
            not artifact_manifest_required
            or (bool(artifact_manifest_provider_id) and preflight_provider_id == artifact_manifest_provider_id)
        )
    )
    return {
        "preflight_provider_id": preflight_provider_id,
        "artifact_manifest_provider_id": artifact_manifest_provider_id,
        "artifact_manifest_required": artifact_manifest_required,
        "provider_consistent": provider_consistent,
        "mismatched_provider_ids": (
            []
            if provider_consistent
            else [provider_id for provider_id in (preflight_provider_id, artifact_manifest_provider_id) if provider_id]
        ),
    }


def _cloud_training_provider_id_from_source_ref(record: Any, source_path: Path | None) -> str:
    if not isinstance(record, dict) or record.get("exists") is not True:
        return ""
    artifact_path = _resolve_cloud_training_artifact_path(record.get("path"), source_path)
    payload = _read_json_object_silent(artifact_path)
    provider = payload.get("provider") if isinstance(payload.get("provider"), dict) else {}
    return str(provider.get("id") or "") if isinstance(provider, dict) else ""


def _cloud_training_required_source_artifacts(schema_version: str) -> tuple[str, ...]:
    return {
        CLOUD_TRAINING_PREFLIGHT_SCHEMA_VERSION: ("agentic_training_plan", "trainer_preflight", "trainer_launch_check"),
        CLOUD_TRAINING_LAUNCH_PLAN_SCHEMA_VERSION: ("preflight", "artifact_manifest"),
        CLOUD_TRAINING_LAUNCH_RECEIPT_SCHEMA_VERSION: ("launch_plan",),
        CLOUD_TRAINING_STATUS_RECEIPT_SCHEMA_VERSION: ("launch_receipt",),
    }.get(schema_version, ())


def _validate_cloud_training_artifact_ref(record: Any, target: ValidationTarget, label: str, source_path: Path | None) -> None:
    if not isinstance(record, dict):
        target.errors.append(f"{label} must be an object.")
        return
    if not isinstance(record.get("role"), str) or not record.get("role"):
        target.errors.append(f"{label}.role must be a non-empty string.")
    if not isinstance(record.get("exists"), bool):
        target.errors.append(f"{label}.exists must be a boolean.")
        return
    if record.get("exists") is not True:
        if record.get("sha256") is not None:
            target.errors.append(f"{label}.sha256 must be null when exists is false.")
        if record.get("size_bytes") is not None:
            target.errors.append(f"{label}.size_bytes must be null when exists is false.")
        return
    if not isinstance(record.get("path"), str) or not record.get("path"):
        target.errors.append(f"{label}.path must be a non-empty string when exists is true.")
        return
    if _looks_absolute(record["path"]):
        target.errors.append(f"{label}.path must be relative to the cloud-training artifact.")
        return
    if not _is_lowercase_sha256(record.get("sha256")):
        target.errors.append(f"{label}.sha256 must be a lowercase SHA-256 hex string when exists is true.")
    if not _is_non_negative_int(record.get("size_bytes")):
        target.errors.append(f"{label}.size_bytes must be a non-negative integer when exists is true.")
    artifact_path = _resolve_cloud_training_artifact_path(record.get("path"), source_path)
    if artifact_path is not None and _path_has_symlink_component(artifact_path, include_leaf=True):
        target.errors.append(f"{label}.path must resolve to a regular non-symlink file when exists is true.")
        return
    if artifact_path is None or not artifact_path.exists() or not artifact_path.is_file():
        target.errors.append(f"{label}.path must resolve to an existing file when exists is true.")
        return
    if _is_non_negative_int(record.get("size_bytes")) and artifact_path.stat().st_size != record.get("size_bytes"):
        target.errors.append(f"{label}.size_bytes does not match the current file.")
    if _is_lowercase_sha256(record.get("sha256")) and _sha256(artifact_path) != record.get("sha256"):
        target.errors.append(f"{label}.sha256 does not match the current file.")


def _resolve_cloud_training_artifact_path(value: Any, source_path: Path | None) -> Path | None:
    if not isinstance(value, str) or not value:
        return None
    path = Path(value)
    if _looks_absolute(value):
        return None
    if source_path is None:
        return None
    return source_path.parent / path


def _validate_cloud_training_credentials(value: Any, target: ValidationTarget) -> None:
    if not isinstance(value, list):
        target.errors.append("cloud_training_preflight.credential_checks must be a list.")
        return
    for index, row in enumerate(value):
        label = f"cloud_training_preflight.credential_checks[{index}]"
        if not isinstance(row, dict):
            target.errors.append(f"{label} must be an object.")
            continue
        if not isinstance(row.get("env_var"), str) or not row.get("env_var"):
            target.errors.append(f"{label}.env_var must be a non-empty string.")
        if not isinstance(row.get("present"), bool):
            target.errors.append(f"{label}.present must be a boolean.")
        if row.get("value_recorded") is not False:
            target.errors.append(f"{label}.value_recorded must be false.")


def _validate_cloud_training_live_preflight(value: Any, target: ValidationTarget) -> None:
    if value is None:
        return
    label = "cloud_training_preflight.live_preflight"
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object when present.")
        return
    if not isinstance(value.get("requested"), bool):
        target.errors.append(f"{label}.requested must be a boolean.")
    if value.get("transport") != "metadata_only":
        target.errors.append(f"{label}.transport must be metadata_only.")
    for field_name in ("provider_api_called", "client_modules_imported", "credential_values_recorded"):
        if value.get(field_name) is not False:
            target.errors.append(f"{label}.{field_name} must be false.")
    dependency_checks = value.get("client_dependency_checks")
    if not isinstance(dependency_checks, list):
        target.errors.append(f"{label}.client_dependency_checks must be a list.")
        dependency_checks = []
    available_count = 0
    for index, row in enumerate(dependency_checks):
        row_label = f"{label}.client_dependency_checks[{index}]"
        if not isinstance(row, dict):
            target.errors.append(f"{row_label} must be an object.")
            continue
        if not isinstance(row.get("module"), str) or not row.get("module"):
            target.errors.append(f"{row_label}.module must be a non-empty string.")
        if not isinstance(row.get("available"), bool):
            target.errors.append(f"{row_label}.available must be a boolean.")
        elif row["available"]:
            available_count += 1
        if row.get("module_imported") is not False:
            target.errors.append(f"{row_label}.module_imported must be false.")
    if value.get("client_dependency_required_count") != len(dependency_checks):
        target.errors.append(
            f"{label}.client_dependency_required_count expected {len(dependency_checks)}, got {value.get('client_dependency_required_count')!r}."
        )
    if value.get("client_dependency_available_count") != available_count:
        target.errors.append(
            f"{label}.client_dependency_available_count expected {available_count}, got {value.get('client_dependency_available_count')!r}."
        )
    if not _is_non_negative_int(value.get("credential_required_count")):
        target.errors.append(f"{label}.credential_required_count must be a non-negative integer.")
    if not _is_non_negative_int(value.get("credential_present_count")):
        target.errors.append(f"{label}.credential_present_count must be a non-negative integer.")
    if (
        _is_non_negative_int(value.get("credential_required_count"))
        and _is_non_negative_int(value.get("credential_present_count"))
        and value.get("credential_present_count") > value.get("credential_required_count")
    ):
        target.errors.append(f"{label}.credential_present_count must not exceed credential_required_count.")


def _validate_agentic_rollout_plan(plan: dict[str, Any], target: ValidationTarget) -> None:
    _require_equal(plan, "schema_version", AGENTIC_ROLLOUT_PLAN_SCHEMA_VERSION, target, prefix="agentic_rollout_plan.")
    checks = plan.get("checks")
    if not isinstance(checks, list):
        target.errors.append("agentic_rollout_plan.checks must be a list.")
        checks = []
    failed_checks = _validate_gate_like_checks(checks, target, "agentic_rollout_plan.checks")
    if plan.get("check_count") != len(checks):
        target.errors.append(f"agentic_rollout_plan.check_count expected {len(checks)}, got {plan.get('check_count')!r}.")
    if plan.get("failed_check_count") != failed_checks:
        target.errors.append(f"agentic_rollout_plan.failed_check_count expected {failed_checks}, got {plan.get('failed_check_count')!r}.")
    if plan.get("passed") != (failed_checks == 0):
        target.errors.append("agentic_rollout_plan.passed must match failed_check_count.")
    expected_readiness = "ready_for_harness_batch" if failed_checks == 0 else "blocked"
    if plan.get("readiness") != expected_readiness:
        target.errors.append(f"agentic_rollout_plan.readiness expected {expected_readiness!r}, got {plan.get('readiness')!r}.")
    budget = plan.get("budget") if isinstance(plan.get("budget"), dict) else {}
    batches = plan.get("harness_batches") if isinstance(plan.get("harness_batches"), list) else []
    if budget.get("planned_rollouts") != len(batches):
        target.errors.append(f"agentic_rollout_plan.budget.planned_rollouts expected {len(batches)}, got {budget.get('planned_rollouts')!r}.")
    if budget.get("live_provider_calls_allowed") is not False:
        target.errors.append("agentic_rollout_plan.budget.live_provider_calls_allowed must be false.")
    _validate_agentic_rollout_environment(plan.get("environment"), target, "agentic_rollout_plan.environment")
    boundary = plan.get("execution_boundary")
    if not isinstance(boundary, dict):
        target.errors.append("agentic_rollout_plan.execution_boundary must be an object.")
    else:
        for field_name in ("plan_only",):
            if boundary.get(field_name) is not True:
                target.errors.append(f"agentic_rollout_plan.execution_boundary.{field_name} must be true.")
        for field_name in ("rollouts_started", "model_provider_calls_started", "paid_model_grader_calls_started", "dataset_rows_written"):
            if boundary.get(field_name) is not False:
                target.errors.append(f"agentic_rollout_plan.execution_boundary.{field_name} must be false.")
    target.details.update(
        {
            "iteration_id": plan.get("iteration_id"),
            "planned_rollouts": budget.get("planned_rollouts"),
            "readiness": plan.get("readiness"),
        }
    )


def _validate_agentic_rollout_receipt(receipt: dict[str, Any], target: ValidationTarget, source_path: Path) -> None:
    _require_equal(receipt, "schema_version", AGENTIC_ROLLOUT_RECEIPT_SCHEMA_VERSION, target, prefix="agentic_rollout_receipt.")
    checks = receipt.get("checks")
    if not isinstance(checks, list):
        target.errors.append("agentic_rollout_receipt.checks must be a list.")
        checks = []
    failed_checks = _validate_gate_like_checks(checks, target, "agentic_rollout_receipt.checks")
    if receipt.get("check_count") != len(checks):
        target.errors.append(f"agentic_rollout_receipt.check_count expected {len(checks)}, got {receipt.get('check_count')!r}.")
    if receipt.get("failed_check_count") != failed_checks:
        target.errors.append(
            f"agentic_rollout_receipt.failed_check_count expected {failed_checks}, got {receipt.get('failed_check_count')!r}."
        )
    if receipt.get("passed") != (failed_checks == 0):
        target.errors.append("agentic_rollout_receipt.passed must match failed_check_count.")
    expected_readiness = "mock_rollouts_recorded" if failed_checks == 0 else "blocked"
    if receipt.get("readiness") != expected_readiness:
        target.errors.append(f"agentic_rollout_receipt.readiness expected {expected_readiness!r}, got {receipt.get('readiness')!r}.")
    expected_recommendation = "score_and_review_mock_rollouts" if failed_checks == 0 else "fix_rollout_plan_before_mock_execution"
    if receipt.get("recommendation") != expected_recommendation:
        target.errors.append(
            f"agentic_rollout_receipt.recommendation expected {expected_recommendation!r}, got {receipt.get('recommendation')!r}."
        )
    if not _is_string_list(receipt.get("blocked_reasons")):
        target.errors.append("agentic_rollout_receipt.blocked_reasons must be a list of strings.")

    source_plan = receipt.get("source_plan")
    if not isinstance(source_plan, dict):
        target.errors.append("agentic_rollout_receipt.source_plan must be an object.")
    else:
        _validate_agentic_rollout_receipt_source_plan(source_plan, target, source_path)

    _validate_agentic_rollout_environment(receipt.get("environment"), target, "agentic_rollout_receipt.environment")

    rollouts = receipt.get("mock_rollouts")
    if not isinstance(rollouts, list):
        target.errors.append("agentic_rollout_receipt.mock_rollouts must be a list.")
        rollouts = []
    if receipt.get("mock_rollout_count") != len(rollouts):
        target.errors.append(
            f"agentic_rollout_receipt.mock_rollout_count expected {len(rollouts)}, got {receipt.get('mock_rollout_count')!r}."
        )
    for index, row in enumerate(rollouts):
        _validate_agentic_mock_rollout(row, index, target)

    lineage = receipt.get("lineage")
    if not isinstance(lineage, dict):
        target.errors.append("agentic_rollout_receipt.lineage must be an object.")
    else:
        for field_name in ("dataset_rows_created", "trace_files_written", "scorecards_written"):
            if lineage.get(field_name) is not False:
                target.errors.append(f"agentic_rollout_receipt.lineage.{field_name} must be false.")
        if lineage.get("ready_for_rejection_sampling") != receipt.get("passed"):
            target.errors.append("agentic_rollout_receipt.lineage.ready_for_rejection_sampling must match passed.")

    boundary = receipt.get("execution_boundary")
    if not isinstance(boundary, dict):
        target.errors.append("agentic_rollout_receipt.execution_boundary must be an object.")
    else:
        if boundary.get("mock_receipt_only") is not True:
            target.errors.append("agentic_rollout_receipt.execution_boundary.mock_receipt_only must be true.")
        if boundary.get("mock_rollouts_recorded") != bool(rollouts):
            target.errors.append("agentic_rollout_receipt.execution_boundary.mock_rollouts_recorded must match mock_rollouts presence.")
        for field_name in (
            "live_rollouts_started",
            "model_provider_calls_started",
            "paid_model_grader_calls_started",
            "dataset_rows_written",
        ):
            if boundary.get(field_name) is not False:
                target.errors.append(f"agentic_rollout_receipt.execution_boundary.{field_name} must be false.")

    target.details.update(
        {
            "passed": receipt.get("passed"),
            "readiness": receipt.get("readiness"),
            "mock_rollout_count": len(rollouts),
        }
    )


def _validate_agentic_rollout_environment(value: Any, target: ValidationTarget, label: str) -> None:
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    if not isinstance(value.get("id"), str) or not value.get("id"):
        target.errors.append(f"{label}.id must be a non-empty string.")
    if value.get("replayable") is not True:
        target.errors.append(f"{label}.replayable must be true.")
    if value.get("network_default") != "disabled":
        target.errors.append(f"{label}.network_default must be disabled.")
    verifier_refs = value.get("external_state_verifiers")
    if not isinstance(verifier_refs, list):
        target.errors.append(f"{label}.external_state_verifiers must be a list.")
        verifier_refs = []
    resolved_count = 0
    for index, ref in enumerate(verifier_refs):
        ref_label = f"{label}.external_state_verifiers[{index}]"
        if not isinstance(ref, dict):
            target.errors.append(f"{ref_label} must be an object.")
            continue
        if ref.get("role") != "verifier_config":
            target.errors.append(f"{ref_label}.role must be verifier_config.")
        if not isinstance(ref.get("path"), str) or not ref.get("path"):
            target.errors.append(f"{ref_label}.path must be a non-empty string.")
        if not isinstance(ref.get("exists"), bool):
            target.errors.append(f"{ref_label}.exists must be a boolean.")
        elif ref.get("exists") is True:
            resolved_count += 1
            if not _is_sha256(ref.get("sha256")):
                target.errors.append(f"{ref_label}.sha256 must be a SHA-256 hex string when exists is true.")
            if not _is_non_negative_int(ref.get("size_bytes")):
                target.errors.append(f"{ref_label}.size_bytes must be a non-negative integer when exists is true.")
        else:
            if ref.get("sha256") is not None:
                target.errors.append(f"{ref_label}.sha256 must be null when exists is false.")
            if ref.get("size_bytes") is not None:
                target.errors.append(f"{ref_label}.size_bytes must be null when exists is false.")
    gate = value.get("external_state_verifier_gate")
    if not isinstance(gate, dict):
        target.errors.append(f"{label}.external_state_verifier_gate must be an object.")
        return
    if gate.get("declared_count") != len(verifier_refs):
        target.errors.append(f"{label}.external_state_verifier_gate.declared_count must match external_state_verifiers.")
    if gate.get("resolved_count") != resolved_count:
        target.errors.append(f"{label}.external_state_verifier_gate.resolved_count must match existing verifier refs.")
    if gate.get("all_declared_verifiers_resolved") != (resolved_count == len(verifier_refs)):
        target.errors.append(f"{label}.external_state_verifier_gate.all_declared_verifiers_resolved must match verifier refs.")
    if gate.get("required_for_external_state_checks") != bool(verifier_refs):
        target.errors.append(f"{label}.external_state_verifier_gate.required_for_external_state_checks must match verifier refs.")
    for field_name in ("verification_side_effects_started", "credential_values_recorded"):
        if gate.get(field_name) is not False:
            target.errors.append(f"{label}.external_state_verifier_gate.{field_name} must be false.")


def _validate_agentic_rollout_receipt_source_plan(source_plan: dict[str, Any], target: ValidationTarget, source_path: Path) -> None:
    label = "agentic_rollout_receipt.source_plan"
    if source_plan.get("schema_version") != AGENTIC_ROLLOUT_PLAN_SCHEMA_VERSION:
        target.errors.append(f"{label}.schema_version must be {AGENTIC_ROLLOUT_PLAN_SCHEMA_VERSION!r}.")
    if source_plan.get("exists") is not True:
        target.errors.append(f"{label}.exists must be true.")
        return
    path_value = source_plan.get("path")
    if not isinstance(path_value, str) or not path_value:
        target.errors.append(f"{label}.path must be a non-empty string when exists is true.")
        return
    plan_path = _external_eval_reference_path(path_value, source_path)
    if not plan_path.is_file():
        target.errors.append(f"{label}.path does not resolve to an agentic rollout plan file.")
        return
    if not _is_non_negative_int(source_plan.get("size_bytes")):
        target.errors.append(f"{label}.size_bytes must be a non-negative integer when exists is true.")
    elif plan_path.stat().st_size != source_plan.get("size_bytes"):
        target.errors.append(f"{label}.size_bytes does not match the current file.")
    if not _is_sha256(source_plan.get("sha256")):
        target.errors.append(f"{label}.sha256 must be a SHA-256 hex string when exists is true.")
    elif _sha256(plan_path) != source_plan.get("sha256"):
        target.errors.append(f"{label}.sha256 does not match the current file.")
    plan = _read_object(plan_path, target, f"{label}.path")
    if plan is not None:
        if plan.get("schema_version") != source_plan.get("schema_version"):
            target.errors.append(f"{label}.schema_version must match the current file.")
        if plan.get("passed") != source_plan.get("passed"):
            target.errors.append(f"{label}.passed must match the current file.")
        if plan.get("readiness") != source_plan.get("readiness"):
            target.errors.append(f"{label}.readiness must match the current file.")


def _validate_agentic_mock_rollout(row: Any, index: int, target: ValidationTarget) -> None:
    label = f"agentic_rollout_receipt.mock_rollouts[{index}]"
    if not isinstance(row, dict):
        target.errors.append(f"{label} must be an object.")
        return
    for field_name in ("rollout_id", "batch_id", "scenario_id", "policy_role", "policy_id"):
        if not isinstance(row.get(field_name), str) or not row.get(field_name):
            target.errors.append(f"{label}.{field_name} must be a non-empty string.")
    if row.get("scenario_sha256") is not None and not _is_sha256(row.get("scenario_sha256")):
        target.errors.append(f"{label}.scenario_sha256 must be a SHA-256 hex string or null.")
    if row.get("harness_mode") != "offline_mock":
        target.errors.append(f"{label}.harness_mode must be 'offline_mock'.")
    if row.get("status") != "mock_recorded":
        target.errors.append(f"{label}.status must be 'mock_recorded'.")
    for field_name in ("model_provider_called", "trace_written", "scorecard_written", "dataset_row_written"):
        if row.get(field_name) is not False:
            target.errors.append(f"{label}.{field_name} must be false.")


def _validate_rejection_sampling_gate(gate: dict[str, Any], target: ValidationTarget) -> None:
    _require_equal(gate, "schema_version", REJECTION_SAMPLING_GATE_SCHEMA_VERSION, target, prefix="rejection_sampling_gate.")
    checks = gate.get("checks")
    if not isinstance(checks, list):
        target.errors.append("rejection_sampling_gate.checks must be a list.")
        checks = []
    failed_checks = _validate_gate_like_checks(checks, target, "rejection_sampling_gate.checks")
    if gate.get("check_count") != len(checks):
        target.errors.append(f"rejection_sampling_gate.check_count expected {len(checks)}, got {gate.get('check_count')!r}.")
    if gate.get("failed_check_count") != failed_checks:
        target.errors.append(f"rejection_sampling_gate.failed_check_count expected {failed_checks}, got {gate.get('failed_check_count')!r}.")
    if gate.get("passed") != (failed_checks == 0):
        target.errors.append("rejection_sampling_gate.passed must match failed_check_count.")
    expected_readiness = "ready_for_dataset_curation" if failed_checks == 0 else "blocked"
    if gate.get("readiness") != expected_readiness:
        target.errors.append(f"rejection_sampling_gate.readiness expected {expected_readiness!r}, got {gate.get('readiness')!r}.")
    expected_recommendation = "curate_accepted_training_rows" if failed_checks == 0 else "collect_calibrated_reviews_before_sampling"
    if gate.get("recommendation") != expected_recommendation:
        target.errors.append(
            f"rejection_sampling_gate.recommendation expected {expected_recommendation!r}, got {gate.get('recommendation')!r}."
        )
    if not _is_string_list(gate.get("blocked_reasons")):
        target.errors.append("rejection_sampling_gate.blocked_reasons must be a list of strings.")

    artifacts = gate.get("input_artifacts")
    if not isinstance(artifacts, dict):
        target.errors.append("rejection_sampling_gate.input_artifacts must be an object.")
        artifacts = {}
    required_roles = {
        "agentic_rollout_receipt": "hfr.agentic_rollout_receipt.v1",
        "model_grader_gate": "hfr.model_grader_gate.v1",
        "review_calibration": "hfr.review_calibration.v1",
        "reviewed_gate": "hfr.reviewed_gate.v1",
    }
    for role, schema_version in required_roles.items():
        rows = artifacts.get(role)
        if not isinstance(rows, list) or not rows:
            target.errors.append(f"rejection_sampling_gate.input_artifacts.{role} must contain at least one artifact ref.")
            continue
        for index, row in enumerate(rows):
            _validate_rejection_sampling_gate_ref(row, target, f"rejection_sampling_gate.input_artifacts.{role}[{index}]", schema_version)

    summary = gate.get("rollout_summary")
    if not isinstance(summary, dict):
        target.errors.append("rejection_sampling_gate.rollout_summary must be an object.")
    else:
        if not _is_non_negative_int(summary.get("receipt_count")):
            target.errors.append("rejection_sampling_gate.rollout_summary.receipt_count must be a non-negative integer.")
        if not _is_non_negative_int(summary.get("mock_rollout_count")):
            target.errors.append("rejection_sampling_gate.rollout_summary.mock_rollout_count must be a non-negative integer.")
        if summary.get("live_rollouts_started") is not False:
            target.errors.append("rejection_sampling_gate.rollout_summary.live_rollouts_started must be false.")
        if summary.get("dataset_rows_created") is not False:
            target.errors.append("rejection_sampling_gate.rollout_summary.dataset_rows_created must be false.")

    policy = gate.get("admission_policy")
    if not isinstance(policy, dict):
        target.errors.append("rejection_sampling_gate.admission_policy must be an object.")
    else:
        for field_name in ("requires_mock_rollout_receipt", "requires_calibrated_review", "requires_model_grader_gate", "requires_reviewed_gate"):
            if policy.get(field_name) is not True:
                target.errors.append(f"rejection_sampling_gate.admission_policy.{field_name} must be true.")
        if policy.get("accepts_uncalibrated_labels") is not False:
            target.errors.append("rejection_sampling_gate.admission_policy.accepts_uncalibrated_labels must be false.")
        if not _is_string_list(policy.get("accepted_dataset_roles")):
            target.errors.append("rejection_sampling_gate.admission_policy.accepted_dataset_roles must be a list of strings.")

    boundary = gate.get("execution_boundary")
    if not isinstance(boundary, dict):
        target.errors.append("rejection_sampling_gate.execution_boundary must be an object.")
    else:
        if boundary.get("gate_only") is not True:
            target.errors.append("rejection_sampling_gate.execution_boundary.gate_only must be true.")
        for field_name in (
            "dataset_rows_written",
            "model_provider_calls_started",
            "paid_model_grader_calls_started",
            "weights_updated_by_flight_recorder",
        ):
            if boundary.get(field_name) is not False:
                target.errors.append(f"rejection_sampling_gate.execution_boundary.{field_name} must be false.")

    target.details.update(
        {
            "passed": gate.get("passed"),
            "readiness": gate.get("readiness"),
            "mock_rollout_count": summary.get("mock_rollout_count") if isinstance(summary, dict) else None,
        }
    )


def _validate_rejection_sampling_gate_ref(row: Any, target: ValidationTarget, label: str, schema_version: str) -> None:
    if not isinstance(row, dict):
        target.errors.append(f"{label} must be an object.")
        return
    for field_name in ("role", "path", "kind", "schema_version", "readiness"):
        if not isinstance(row.get(field_name), str):
            target.errors.append(f"{label}.{field_name} must be a string.")
    if row.get("kind") not in {"file", "directory"}:
        target.errors.append(f"{label}.kind must be 'file' or 'directory'.")
    if row.get("exists") is not True:
        target.errors.append(f"{label}.exists must be true.")
    if row.get("schema_version") != schema_version:
        target.errors.append(f"{label}.schema_version must be {schema_version!r}.")
    if row.get("passed") is not True:
        target.errors.append(f"{label}.passed must be true.")
    if row.get("kind") == "file":
        if not _is_sha256(row.get("sha256")):
            target.errors.append(f"{label}.sha256 must be a SHA-256 hex string for file refs.")
        if not _is_non_negative_int(row.get("size_bytes")):
            target.errors.append(f"{label}.size_bytes must be a non-negative integer for file refs.")
    if row.get("role") == "agentic_rollout_receipt":
        if row.get("readiness") != "mock_rollouts_recorded":
            target.errors.append(f"{label}.readiness must be 'mock_rollouts_recorded'.")
        if not _is_non_negative_int(row.get("mock_rollout_count")) or row.get("mock_rollout_count") <= 0:
            target.errors.append(f"{label}.mock_rollout_count must be positive.")
        if row.get("mock_receipt_only") is not True:
            target.errors.append(f"{label}.mock_receipt_only must be true.")
        if row.get("live_rollouts_started") is not False:
            target.errors.append(f"{label}.live_rollouts_started must be false.")
        if row.get("dataset_rows_written") is not False:
            target.errors.append(f"{label}.dataset_rows_written must be false.")


def _validate_dataset_curation_receipt(receipt: dict[str, Any], target: ValidationTarget) -> None:
    _require_equal(receipt, "schema_version", DATASET_CURATION_RECEIPT_SCHEMA_VERSION, target, prefix="dataset_curation_receipt.")
    checks = receipt.get("checks")
    if not isinstance(checks, list):
        target.errors.append("dataset_curation_receipt.checks must be a list.")
        checks = []
    failed_checks = _validate_gate_like_checks(checks, target, "dataset_curation_receipt.checks")
    if receipt.get("check_count") != len(checks):
        target.errors.append(f"dataset_curation_receipt.check_count expected {len(checks)}, got {receipt.get('check_count')!r}.")
    if receipt.get("failed_check_count") != failed_checks:
        target.errors.append(f"dataset_curation_receipt.failed_check_count expected {failed_checks}, got {receipt.get('failed_check_count')!r}.")
    if receipt.get("passed") != (failed_checks == 0):
        target.errors.append("dataset_curation_receipt.passed must match failed_check_count.")
    expected_readiness = "ready_for_external_trainer_handoff" if failed_checks == 0 else "blocked"
    if receipt.get("readiness") != expected_readiness:
        target.errors.append(f"dataset_curation_receipt.readiness expected {expected_readiness!r}, got {receipt.get('readiness')!r}.")
    expected_recommendation = "run_training_gate_and_trainer_preflight" if failed_checks == 0 else "fix_rejection_sampling_or_training_exports"
    if receipt.get("recommendation") != expected_recommendation:
        target.errors.append(
            f"dataset_curation_receipt.recommendation expected {expected_recommendation!r}, got {receipt.get('recommendation')!r}."
        )
    if not _is_string_list(receipt.get("blocked_reasons")):
        target.errors.append("dataset_curation_receipt.blocked_reasons must be a list of strings.")

    artifacts = receipt.get("input_artifacts")
    if not isinstance(artifacts, dict):
        target.errors.append("dataset_curation_receipt.input_artifacts must be an object.")
        artifacts = {}
    gate_rows = artifacts.get("rejection_sampling_gate")
    if not isinstance(gate_rows, list) or not gate_rows:
        target.errors.append("dataset_curation_receipt.input_artifacts.rejection_sampling_gate must contain at least one ref.")
    else:
        for index, row in enumerate(gate_rows):
            _validate_dataset_curation_ref(
                row,
                target,
                f"dataset_curation_receipt.input_artifacts.rejection_sampling_gate[{index}]",
                "hfr.rejection_sampling_gate.v1",
                "ready_for_dataset_curation",
            )
    export_rows = artifacts.get("training_export")
    if not isinstance(export_rows, list) or not export_rows:
        target.errors.append("dataset_curation_receipt.input_artifacts.training_export must contain at least one ref.")
    else:
        for index, row in enumerate(export_rows):
            _validate_dataset_curation_ref(row, target, f"dataset_curation_receipt.input_artifacts.training_export[{index}]", "", "")

    summary = receipt.get("curation_summary")
    if not isinstance(summary, dict):
        target.errors.append("dataset_curation_receipt.curation_summary must be an object.")
    else:
        for field_name in ("rejection_sampling_gate_count", "training_export_count"):
            if not _is_non_negative_int(summary.get(field_name)):
                target.errors.append(f"dataset_curation_receipt.curation_summary.{field_name} must be a non-negative integer.")
        for field_name in ("curated_rows_written", "accepted_rows_written", "rejected_rows_written"):
            if summary.get(field_name) != 0:
                target.errors.append(f"dataset_curation_receipt.curation_summary.{field_name} must be 0.")
        if summary.get("dataset_registry_updated") is not False:
            target.errors.append("dataset_curation_receipt.curation_summary.dataset_registry_updated must be false.")

    handoff = receipt.get("trainer_handoff")
    if not isinstance(handoff, dict):
        target.errors.append("dataset_curation_receipt.trainer_handoff must be an object.")
    else:
        if handoff.get("dataset_rows_source") != "existing_training_exports":
            target.errors.append("dataset_curation_receipt.trainer_handoff.dataset_rows_source must be existing_training_exports.")
        if not _is_string_list(handoff.get("allowed_dataset_roles")):
            target.errors.append("dataset_curation_receipt.trainer_handoff.allowed_dataset_roles must be a list of strings.")
        for field_name in ("requires_rejection_sampling_gate", "requires_training_gate_before_live_training", "requires_trainer_preflight"):
            if handoff.get(field_name) is not True:
                target.errors.append(f"dataset_curation_receipt.trainer_handoff.{field_name} must be true.")

    boundary = receipt.get("execution_boundary")
    if not isinstance(boundary, dict):
        target.errors.append("dataset_curation_receipt.execution_boundary must be an object.")
    else:
        if boundary.get("receipt_only") is not True:
            target.errors.append("dataset_curation_receipt.execution_boundary.receipt_only must be true.")
        for field_name in ("dataset_rows_written", "dataset_registry_updated", "cloud_jobs_started", "weights_updated_by_flight_recorder"):
            if boundary.get(field_name) is not False:
                target.errors.append(f"dataset_curation_receipt.execution_boundary.{field_name} must be false.")

    target.details.update(
        {
            "passed": receipt.get("passed"),
            "readiness": receipt.get("readiness"),
            "training_export_count": summary.get("training_export_count") if isinstance(summary, dict) else None,
        }
    )


def _validate_dataset_curation_ref(row: Any, target: ValidationTarget, label: str, schema_version: str, readiness: str) -> None:
    if not isinstance(row, dict):
        target.errors.append(f"{label} must be an object.")
        return
    for field_name in ("role", "path", "kind"):
        if not isinstance(row.get(field_name), str) or not row.get(field_name):
            target.errors.append(f"{label}.{field_name} must be a non-empty string.")
    if row.get("kind") not in {"file", "directory"}:
        target.errors.append(f"{label}.kind must be 'file' or 'directory'.")
    if row.get("exists") is not True:
        target.errors.append(f"{label}.exists must be true.")
    if schema_version:
        if row.get("schema_version") != schema_version:
            target.errors.append(f"{label}.schema_version must be {schema_version!r}.")
        if row.get("passed") is not True:
            target.errors.append(f"{label}.passed must be true.")
    if readiness and row.get("readiness") != readiness:
        target.errors.append(f"{label}.readiness must be {readiness!r}.")
    if row.get("kind") == "file":
        if not _is_sha256(row.get("sha256")):
            target.errors.append(f"{label}.sha256 must be a SHA-256 hex string for file refs.")
        if not _is_non_negative_int(row.get("size_bytes")):
            target.errors.append(f"{label}.size_bytes must be a non-negative integer for file refs.")
    if row.get("kind") == "directory":
        if row.get("manifest_exists") is not True:
            target.errors.append(f"{label}.manifest_exists must be true for directory refs.")
        if not _is_sha256(row.get("manifest_sha256")):
            target.errors.append(f"{label}.manifest_sha256 must be a SHA-256 hex string for directory refs.")
        if not _is_non_negative_int(row.get("manifest_size_bytes")):
            target.errors.append(f"{label}.manifest_size_bytes must be a non-negative integer for directory refs.")


def _validate_rubric_spec(rubric: dict[str, Any], target: ValidationTarget, source_path: Path) -> None:
    _require_equal(rubric, "schema_version", RUBRIC_SPEC_SCHEMA_VERSION, target, prefix="rubric_spec.")
    review_export_paths = _validate_model_grader_review_export_ref(
        rubric.get("review_export"),
        target,
        "rubric_spec.review_export",
        source_path,
    )
    if not isinstance(rubric.get("rubric_id"), str) or not rubric.get("rubric_id"):
        target.errors.append("rubric_spec.rubric_id must be a non-empty string.")
    criteria = rubric.get("criteria")
    if not isinstance(criteria, list):
        target.errors.append("rubric_spec.criteria must be a list.")
        criteria = []
    for index, row in enumerate(criteria):
        label = f"rubric_spec.criteria[{index}]"
        if not isinstance(row, dict):
            target.errors.append(f"{label} must be an object.")
            continue
        if not isinstance(row.get("criterion_id"), str) or not row.get("criterion_id"):
            target.errors.append(f"{label}.criterion_id must be a non-empty string.")
        if not isinstance(row.get("description"), str) or not row.get("description"):
            target.errors.append(f"{label}.description must be a non-empty string.")
        if row.get("required") is not True:
            target.errors.append(f"{label}.required must be true.")
    if rubric.get("criterion_count") != len(criteria):
        target.errors.append(f"rubric_spec.criterion_count expected {len(criteria)}, got {rubric.get('criterion_count')!r}.")
    labels = rubric.get("label_options")
    if labels != list(REVIEW_LABELS):
        target.errors.append(f"rubric_spec.label_options must be {list(REVIEW_LABELS)!r}.")
    fingerprints = rubric.get("review_item_fingerprints")
    if not isinstance(fingerprints, list):
        target.errors.append("rubric_spec.review_item_fingerprints must be a list.")
        fingerprints = []
    if rubric.get("review_item_count") != len(fingerprints):
        target.errors.append(
            f"rubric_spec.review_item_count expected {len(fingerprints)}, got {rubric.get('review_item_count')!r}."
        )
    for index, row in enumerate(fingerprints):
        label = f"rubric_spec.review_item_fingerprints[{index}]"
        if not isinstance(row, dict):
            target.errors.append(f"{label} must be an object.")
            continue
        for field_name in ("review_item_id", "episode_id", "scenario_id"):
            if not isinstance(row.get(field_name), str) or not row.get(field_name):
                target.errors.append(f"{label}.{field_name} must be a non-empty string.")
        if not _is_sha256(row.get("review_item_sha256")):
            target.errors.append(f"{label}.review_item_sha256 must be a sha256 hex digest.")
    _validate_rubric_review_item_fingerprints(
        fingerprints,
        review_export_paths.get("review_items"),
        target,
    )
    requirements = rubric.get("calibration_requirements") if isinstance(rubric.get("calibration_requirements"), dict) else {}
    if requirements.get("required_before_training_admission") is not True:
        target.errors.append("rubric_spec.calibration_requirements.required_before_training_admission must be true.")
    if requirements.get("max_uncalibrated_labels_admitted") != 0:
        target.errors.append("rubric_spec.calibration_requirements.max_uncalibrated_labels_admitted must be 0.")
    _validate_model_grader_boundary(rubric.get("execution_boundary"), target, "rubric_spec")
    target.details.update(
        {
            "rubric_id": rubric.get("rubric_id"),
            "criterion_count": rubric.get("criterion_count"),
            "review_item_count": rubric.get("review_item_count"),
        }
    )


def _validate_model_grader_dry_run(receipt: dict[str, Any], target: ValidationTarget, source_path: Path) -> None:
    _require_equal(receipt, "schema_version", MODEL_GRADER_DRY_RUN_SCHEMA_VERSION, target, prefix="model_grader_dry_run.")
    _validate_model_grader_checked_artifact(receipt, target, "model_grader_dry_run")
    source_paths = _validate_model_grader_dry_run_sources(receipt.get("source_artifacts"), target, source_path)
    grader = receipt.get("grader") if isinstance(receipt.get("grader"), dict) else {}
    if grader.get("mode") != "dry_run":
        target.errors.append("model_grader_dry_run.grader.mode must be dry_run.")
    if grader.get("transport") != "mock":
        target.errors.append("model_grader_dry_run.grader.transport must be mock.")
    if grader.get("provider_api_called") is not False:
        target.errors.append("model_grader_dry_run.grader.provider_api_called must be false.")
    if grader.get("paid_model_grader_calls_started") is not False:
        target.errors.append("model_grader_dry_run.grader.paid_model_grader_calls_started must be false.")
    labels = receipt.get("grader_labels")
    if not isinstance(labels, list):
        target.errors.append("model_grader_dry_run.grader_labels must be a list.")
        labels = []
    if receipt.get("graded_item_count") != len(labels):
        target.errors.append(
            f"model_grader_dry_run.graded_item_count expected {len(labels)}, got {receipt.get('graded_item_count')!r}."
        )
    labels_requiring_review = 0
    expected_disagreement_queue: list[dict[str, str]] = []
    observed_label_source_keys: list[dict[str, Any]] = []
    label_counts = _model_grader_label_counts(receipt.get("label_counts"), target, "model_grader_dry_run.label_counts")
    expected_counts = {label: 0 for label in REVIEW_LABELS}
    for index, row in enumerate(labels):
        label = f"model_grader_dry_run.grader_labels[{index}]"
        if not isinstance(row, dict):
            target.errors.append(f"{label} must be an object.")
            continue
        for field_name in ("review_item_id", "episode_id", "scenario_id", "task_family", "review_item_sha256", "mock_model_label", "mock_confidence", "rationale", "grader_id", "provider", "label_sha256"):
            if not isinstance(row.get(field_name), str) or not row.get(field_name):
                target.errors.append(f"{label}.{field_name} must be a non-empty string.")
        if row.get("mock_model_label") not in REVIEW_LABELS:
            target.errors.append(f"{label}.mock_model_label must be one of {list(REVIEW_LABELS)!r}.")
        elif row["mock_model_label"] in expected_counts:
            expected_counts[row["mock_model_label"]] += 1
        if row.get("mock_confidence") not in REVIEW_CONFIDENCE_LEVELS:
            target.errors.append(f"{label}.mock_confidence must be one of {list(REVIEW_CONFIDENCE_LEVELS)!r}.")
        if not isinstance(row.get("requires_human_review"), bool):
            target.errors.append(f"{label}.requires_human_review must be a boolean.")
        elif row.get("requires_human_review") is True:
            labels_requiring_review += 1
            expected_disagreement_queue.append(_model_grader_disagreement_queue_key(row))
        if not _is_sha256(row.get("review_item_sha256")):
            target.errors.append(f"{label}.review_item_sha256 must be a sha256 hex digest.")
        label_hash = row.get("label_sha256")
        if not _is_sha256(label_hash):
            target.errors.append(f"{label}.label_sha256 must be a sha256 hex digest.")
        elif label_hash != _model_grader_label_sha256(row):
            target.errors.append(f"{label}.label_sha256 does not match label contents.")
        observed_label_source_keys.append(_model_grader_label_source_key(row))
    _validate_model_grader_dry_run_labels_match_review_items(
        observed_label_source_keys,
        source_paths.get("review_items"),
        grader,
        target,
    )
    for label_name, expected in expected_counts.items():
        if label_counts.get(label_name) != expected:
            target.errors.append(
                f"model_grader_dry_run.label_counts[{label_name}] expected {expected}, got {label_counts.get(label_name)!r}."
            )
    disagreement_queue = receipt.get("disagreement_queue")
    if not isinstance(disagreement_queue, list):
        target.errors.append("model_grader_dry_run.disagreement_queue must be a list.")
        disagreement_queue = []
    observed_disagreement_queue = _validate_model_grader_disagreement_queue(disagreement_queue, target)
    if len(disagreement_queue) != labels_requiring_review:
        target.errors.append(
            "model_grader_dry_run.disagreement_queue must contain one item for each label requiring human review."
        )
    if observed_disagreement_queue != expected_disagreement_queue:
        target.errors.append("model_grader_dry_run.disagreement_queue must match labels requiring human review.")
    admission = receipt.get("training_admission") if isinstance(receipt.get("training_admission"), dict) else {}
    if admission.get("labels_allowed_for_training") is not False:
        target.errors.append("model_grader_dry_run.training_admission.labels_allowed_for_training must be false.")
    if admission.get("labels_admitted_count") != 0:
        target.errors.append("model_grader_dry_run.training_admission.labels_admitted_count must be 0.")
    if admission.get("requires_calibrated_gate") is not True:
        target.errors.append("model_grader_dry_run.training_admission.requires_calibrated_gate must be true.")
    _validate_model_grader_boundary(receipt.get("execution_boundary"), target, "model_grader_dry_run")
    target.details.update(
        {
            "graded_item_count": receipt.get("graded_item_count"),
            "readiness": receipt.get("readiness"),
            "recommendation": receipt.get("recommendation"),
        }
    )


def _validate_model_grader_override_receipt(receipt: dict[str, Any], target: ValidationTarget, source_path: Path) -> None:
    _require_equal(
        receipt,
        "schema_version",
        MODEL_GRADER_OVERRIDE_RECEIPT_SCHEMA_VERSION,
        target,
        prefix="model_grader_override_receipt.",
    )
    failed_checks = _validate_model_grader_checked_artifact(receipt, target, "model_grader_override_receipt")
    _validate_model_grader_override_sources(receipt.get("source_artifacts"), target, source_path)
    expected_readiness = "ready_for_model_grader_gate" if failed_checks == 0 else "blocked"
    if receipt.get("readiness") != expected_readiness:
        target.errors.append(
            f"model_grader_override_receipt.readiness expected {expected_readiness!r}, got {receipt.get('readiness')!r}."
        )
    queue = receipt.get("queue") if isinstance(receipt.get("queue"), dict) else {}
    for field_name in ("required_review_item_ids", "resolved_review_item_ids", "unresolved_review_item_ids"):
        if not _is_string_list(queue.get(field_name)):
            target.errors.append(f"model_grader_override_receipt.queue.{field_name} must be a list of strings.")
    required_ids = set(queue.get("required_review_item_ids", [])) if isinstance(queue.get("required_review_item_ids"), list) else set()
    resolved_ids = set(queue.get("resolved_review_item_ids", [])) if isinstance(queue.get("resolved_review_item_ids"), list) else set()
    unresolved_ids = set(queue.get("unresolved_review_item_ids", [])) if isinstance(queue.get("unresolved_review_item_ids"), list) else set()
    if not _is_non_negative_int(queue.get("dry_run_disagreement_queue_count")):
        target.errors.append("model_grader_override_receipt.queue.dry_run_disagreement_queue_count must be a non-negative integer.")
    elif queue.get("dry_run_disagreement_queue_count") != len(required_ids):
        target.errors.append("model_grader_override_receipt.queue.dry_run_disagreement_queue_count must match required_review_item_ids.")
    if resolved_ids - required_ids:
        target.errors.append("model_grader_override_receipt.queue.resolved_review_item_ids must be a subset of required_review_item_ids.")
    if unresolved_ids != required_ids - resolved_ids:
        target.errors.append("model_grader_override_receipt.queue.unresolved_review_item_ids must be required minus resolved ids.")
    overrides = receipt.get("overrides")
    if not isinstance(overrides, list):
        target.errors.append("model_grader_override_receipt.overrides must be a list.")
        overrides = []
    accepted_count = 0
    for index, row in enumerate(overrides):
        label = f"model_grader_override_receipt.overrides[{index}]"
        if not isinstance(row, dict):
            target.errors.append(f"{label} must be an object.")
            continue
        for field_name in ("review_item_id", "human_label", "reviewer_confidence", "reviewer", "reviewed_at", "notes"):
            if not isinstance(row.get(field_name), str):
                target.errors.append(f"{label}.{field_name} must be a string.")
        if not row.get("review_item_id"):
            target.errors.append(f"{label}.review_item_id must be non-empty.")
        if row.get("human_label") not in set(REVIEW_LABELS) - {"needs_review"}:
            target.errors.append(f"{label}.human_label must be a finalized review label.")
        if row.get("reviewer_confidence") not in {"high", "medium"}:
            target.errors.append(f"{label}.reviewer_confidence must be high or medium.")
        if not row.get("reviewer"):
            target.errors.append(f"{label}.reviewer must be non-empty.")
        if not row.get("reviewed_at"):
            target.errors.append(f"{label}.reviewed_at must be non-empty.")
        if not isinstance(row.get("resolves_queue_item"), bool):
            target.errors.append(f"{label}.resolves_queue_item must be a boolean.")
        if not isinstance(row.get("accepted"), bool):
            target.errors.append(f"{label}.accepted must be a boolean.")
        elif row.get("accepted") is True:
            accepted_count += 1
        if not isinstance(row.get("errors"), list) or not all(isinstance(item, str) for item in row.get("errors", [])):
            target.errors.append(f"{label}.errors must be a list of strings.")
        override_hash = row.get("override_sha256")
        if not _is_sha256(override_hash):
            target.errors.append(f"{label}.override_sha256 must be a sha256 hex digest.")
        elif override_hash != _model_grader_override_sha256(row):
            target.errors.append(f"{label}.override_sha256 does not match override contents.")
    metrics = receipt.get("metrics") if isinstance(receipt.get("metrics"), dict) else {}
    for field_name in (
        "override_row_count",
        "resolved_queue_count",
        "unresolved_queue_count",
        "unmatched_override_count",
        "invalid_override_count",
    ):
        if not _is_non_negative_int(metrics.get(field_name)):
            target.errors.append(f"model_grader_override_receipt.metrics.{field_name} must be a non-negative integer.")
    if metrics.get("override_row_count") != len(overrides):
        target.errors.append("model_grader_override_receipt.metrics.override_row_count must match overrides length.")
    if metrics.get("resolved_queue_count") != len(resolved_ids):
        target.errors.append("model_grader_override_receipt.metrics.resolved_queue_count must match resolved ids.")
    if metrics.get("unresolved_queue_count") != len(unresolved_ids):
        target.errors.append("model_grader_override_receipt.metrics.unresolved_queue_count must match unresolved ids.")
    if failed_checks == 0 and metrics.get("unresolved_queue_count") != 0:
        target.errors.append("model_grader_override_receipt.metrics.unresolved_queue_count must be 0 when passed.")
    if failed_checks == 0 and accepted_count != len(required_ids):
        target.errors.append("model_grader_override_receipt accepted overrides must cover all required queue ids when passed.")
    admission = receipt.get("training_admission") if isinstance(receipt.get("training_admission"), dict) else {}
    if admission.get("labels_allowed_for_training") is not False:
        target.errors.append("model_grader_override_receipt.training_admission.labels_allowed_for_training must be false.")
    if admission.get("labels_admitted_count") != 0:
        target.errors.append("model_grader_override_receipt.training_admission.labels_admitted_count must be 0.")
    if admission.get("requires_model_grader_gate") is not True:
        target.errors.append("model_grader_override_receipt.training_admission.requires_model_grader_gate must be true.")
    _validate_model_grader_boundary(receipt.get("execution_boundary"), target, "model_grader_override_receipt")
    target.details.update(
        {
            "readiness": receipt.get("readiness"),
            "resolved_queue_count": metrics.get("resolved_queue_count"),
            "unresolved_queue_count": metrics.get("unresolved_queue_count"),
        }
    )

def _validate_model_grader_gate(gate: dict[str, Any], target: ValidationTarget, source_path: Path) -> None:
    _require_equal(gate, "schema_version", MODEL_GRADER_GATE_SCHEMA_VERSION, target, prefix="model_grader_gate.")
    failed_checks = _validate_model_grader_checked_artifact(gate, target, "model_grader_gate")
    _validate_model_grader_gate_sources(gate.get("source_artifacts"), target, source_path)
    expected_readiness = "labels_calibrated_for_curated_handoff" if failed_checks == 0 else "blocked"
    if gate.get("readiness") != expected_readiness:
        target.errors.append(f"model_grader_gate.readiness expected {expected_readiness!r}, got {gate.get('readiness')!r}.")
    admission = gate.get("admission") if isinstance(gate.get("admission"), dict) else {}
    labels_allowed = admission.get("labels_allowed_for_training")
    if labels_allowed != (failed_checks == 0):
        target.errors.append("model_grader_gate.admission.labels_allowed_for_training must match gate pass/fail.")
    if admission.get("uncalibrated_labels_admitted") != 0:
        target.errors.append("model_grader_gate.admission.uncalibrated_labels_admitted must be 0.")
    if failed_checks and admission.get("labels_admitted_count") != 0:
        target.errors.append("model_grader_gate.admission.labels_admitted_count must be 0 when the gate is blocked.")
    metrics = gate.get("metrics") if isinstance(gate.get("metrics"), dict) else {}
    for field_name in (
        "graded_item_count",
        "calibration_disagreement_count",
        "dry_run_disagreement_queue_count",
        "dry_run_labels_requiring_human_review_count",
        "human_override_resolved_count",
        "human_override_unresolved_count",
    ):
        if not _is_non_negative_int(metrics.get(field_name)):
            target.errors.append(f"model_grader_gate.metrics.{field_name} must be a non-negative integer.")
    if not isinstance(metrics.get("agreement_rate"), (int, float)) or not 0 <= metrics.get("agreement_rate") <= 1:
        target.errors.append("model_grader_gate.metrics.agreement_rate must be a number from 0 to 1.")
    if not isinstance(metrics.get("human_override_receipt_present"), bool):
        target.errors.append("model_grader_gate.metrics.human_override_receipt_present must be a boolean.")
    if failed_checks == 0:
        admitted_count = admission.get("labels_admitted_count")
        if admitted_count != metrics.get("graded_item_count"):
            target.errors.append("model_grader_gate.admission.labels_admitted_count must equal graded_item_count when passed.")
        unresolved_source_count = max(
            metrics.get("dry_run_disagreement_queue_count", 0),
            metrics.get("dry_run_labels_requiring_human_review_count", 0),
        )
        if unresolved_source_count:
            if metrics.get("human_override_receipt_present") is not True:
                target.errors.append("model_grader_gate.metrics.human_override_receipt_present must be true when queued labels pass.")
            if metrics.get("human_override_unresolved_count") != 0:
                target.errors.append("model_grader_gate.metrics.human_override_unresolved_count must be 0 when passed.")
            if metrics.get("human_override_resolved_count", 0) < unresolved_source_count:
                target.errors.append("model_grader_gate.metrics.human_override_resolved_count must cover queued labels when passed.")
    _validate_model_grader_boundary(gate.get("execution_boundary"), target, "model_grader_gate")
    target.details.update(
        {
            "readiness": gate.get("readiness"),
            "recommendation": gate.get("recommendation"),
            "admitted_count": admission.get("labels_admitted_count"),
        }
    )


def _validate_model_grader_checked_artifact(payload: dict[str, Any], target: ValidationTarget, label: str) -> int:
    checks = payload.get("checks")
    if not isinstance(checks, list):
        target.errors.append(f"{label}.checks must be a list.")
        checks = []
    failed_checks = _validate_gate_like_checks(checks, target, f"{label}.checks")
    if payload.get("check_count") != len(checks):
        target.errors.append(f"{label}.check_count expected {len(checks)}, got {payload.get('check_count')!r}.")
    if payload.get("failed_check_count") != failed_checks:
        target.errors.append(f"{label}.failed_check_count expected {failed_checks}, got {payload.get('failed_check_count')!r}.")
    if isinstance(payload.get("passed"), bool) and payload["passed"] != (failed_checks == 0):
        target.errors.append(f"{label}.passed must match failed_check_count.")
    if not isinstance(payload.get("blocked_reasons"), list) or not all(isinstance(item, str) for item in payload.get("blocked_reasons", [])):
        target.errors.append(f"{label}.blocked_reasons must be a list of strings.")
    return failed_checks


def _validate_model_grader_dry_run_sources(value: Any, target: ValidationTarget, source_path: Path) -> dict[str, Path]:
    paths: dict[str, Path] = {}
    if not isinstance(value, dict):
        target.errors.append("model_grader_dry_run.source_artifacts must be an object.")
        return paths
    review_export_paths = _validate_model_grader_review_export_ref(
        value.get("review_export"),
        target,
        "model_grader_dry_run.source_artifacts.review_export",
        source_path,
    )
    if "review_items" in review_export_paths:
        paths["review_items"] = review_export_paths["review_items"]
    rubric_path = _validate_model_grader_referenced_artifact(
        value.get("rubric_spec"),
        target,
        "model_grader_dry_run.source_artifacts.rubric_spec",
        source_path,
        validate_rubric_spec,
        allow_missing=False,
    )
    if rubric_path is not None:
        paths["rubric_spec"] = rubric_path
        _validate_model_grader_dry_run_review_export_matches_rubric(review_export_paths, rubric_path, target)
    return paths


def _validate_rubric_review_item_fingerprints(
    fingerprints: list[Any],
    review_items_path: Path | None,
    target: ValidationTarget,
) -> None:
    if review_items_path is None:
        return
    review_items = _read_jsonl_objects(
        review_items_path,
        target,
        "rubric_spec.review_export.review_items",
    )
    expected = [
        {
            "review_item_id": str(item.get("review_item_id") or ""),
            "episode_id": str(item.get("episode_id") or ""),
            "scenario_id": str(item.get("scenario_id") or ""),
            "review_item_sha256": review_item_sha256(item),
        }
        for item in review_items
    ]
    if fingerprints != expected:
        target.errors.append("rubric_spec.review_item_fingerprints must match review_export.review_items.")


def _validate_model_grader_dry_run_labels_match_review_items(
    label_source_keys: list[dict[str, Any]],
    review_items_path: Path | None,
    grader: dict[str, Any],
    target: ValidationTarget,
) -> None:
    if review_items_path is None:
        return
    review_items = _read_jsonl_objects(
        review_items_path,
        target,
        "model_grader_dry_run.source_artifacts.review_export.review_items",
    )
    expected = [_model_grader_expected_label_source_key(item, grader) for item in review_items]
    if label_source_keys != expected:
        target.errors.append("model_grader_dry_run.grader_labels must match source_artifacts.review_export.review_items.")


def _validate_model_grader_dry_run_review_export_matches_rubric(
    dry_run_paths: dict[str, Path],
    rubric_path: Path,
    target: ValidationTarget,
) -> None:
    if not dry_run_paths:
        return
    try:
        rubric = json.loads(rubric_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return
    if not isinstance(rubric, dict):
        return
    rubric_paths = _validate_model_grader_review_export_ref(
        rubric.get("review_export"),
        target,
        "model_grader_dry_run.source_artifacts.rubric_spec.review_export",
        rubric_path,
    )
    for field_name in ("manifest", "review_items"):
        dry_path = dry_run_paths.get(field_name)
        rubric_review_path = rubric_paths.get(field_name)
        if dry_path is not None and rubric_review_path is not None and not _same_model_grader_source_file(
            dry_path,
            rubric_review_path,
        ):
            target.errors.append("model_grader_dry_run.source_artifacts.review_export must match rubric_spec.review_export.")
            return


def _validate_model_grader_disagreement_queue(
    queue: list[Any],
    target: ValidationTarget,
) -> list[dict[str, str]]:
    observed: list[dict[str, str]] = []
    for index, row in enumerate(queue):
        label = f"model_grader_dry_run.disagreement_queue[{index}]"
        if not isinstance(row, dict):
            target.errors.append(f"{label} must be an object.")
            continue
        for field_name in ("review_item_id", "episode_id", "scenario_id", "task_family", "review_item_sha256", "mock_model_label", "reason"):
            if not isinstance(row.get(field_name), str) or not row.get(field_name):
                target.errors.append(f"{label}.{field_name} must be a non-empty string.")
        if not _is_sha256(row.get("review_item_sha256")):
            target.errors.append(f"{label}.review_item_sha256 must be a sha256 hex digest.")
        if row.get("mock_model_label") not in REVIEW_LABELS:
            target.errors.append(f"{label}.mock_model_label must be one of {list(REVIEW_LABELS)!r}.")
        if row.get("reason") != "human_review_required_by_rubric_or_low_confidence":
            target.errors.append(f"{label}.reason must be human_review_required_by_rubric_or_low_confidence.")
        if row.get("source_report") is not None and not isinstance(row.get("source_report"), str):
            target.errors.append(f"{label}.source_report must be a string or null.")
        observed.append(_model_grader_disagreement_queue_key(row))
    return observed


def _model_grader_disagreement_queue_key(row: dict[str, Any]) -> dict[str, str]:
    return {
        "review_item_id": str(row.get("review_item_id") or ""),
        "episode_id": str(row.get("episode_id") or ""),
        "scenario_id": str(row.get("scenario_id") or ""),
        "task_family": str(row.get("task_family") or ""),
        "review_item_sha256": str(row.get("review_item_sha256") or ""),
        "mock_model_label": str(row.get("mock_model_label") or ""),
    }


def _model_grader_label_source_key(row: dict[str, Any]) -> dict[str, Any]:
    return {
        "review_item_id": str(row.get("review_item_id") or ""),
        "episode_id": str(row.get("episode_id") or ""),
        "scenario_id": str(row.get("scenario_id") or ""),
        "task_family": str(row.get("task_family") or ""),
        "review_item_sha256": str(row.get("review_item_sha256") or ""),
        "mock_model_label": str(row.get("mock_model_label") or ""),
        "mock_confidence": str(row.get("mock_confidence") or ""),
        "requires_human_review": row.get("requires_human_review") if isinstance(row.get("requires_human_review"), bool) else None,
        "grader_id": str(row.get("grader_id") or ""),
        "provider": str(row.get("provider") or ""),
    }


def _model_grader_expected_label_source_key(item: dict[str, Any], grader: dict[str, Any]) -> dict[str, Any]:
    scorecard = item.get("scorecard") if isinstance(item.get("scorecard"), dict) else {}
    suggested = str(item.get("suggested_human_label") or ("accept" if scorecard.get("passed") is True else "reject"))
    if suggested not in REVIEW_LABELS:
        suggested = "needs_review"
    confidence = "medium" if suggested in {"accept", "reject"} else "low"
    return {
        "review_item_id": str(item.get("review_item_id") or ""),
        "episode_id": str(item.get("episode_id") or ""),
        "scenario_id": str(item.get("scenario_id") or ""),
        "task_family": str(item.get("task_family") or "unknown"),
        "review_item_sha256": review_item_sha256(item),
        "mock_model_label": suggested,
        "mock_confidence": confidence,
        "requires_human_review": suggested in {"needs_review", "unsafe", "incomplete"} or confidence == "low",
        "grader_id": str(grader.get("grader_id") or ""),
        "provider": str(grader.get("provider") or ""),
    }


def _model_grader_label_sha256(row: dict[str, Any]) -> str:
    return _model_grader_row_sha256(row)


def _model_grader_override_sha256(row: dict[str, Any]) -> str:
    payload = dict(row)
    payload["override_sha256"] = ""
    return _model_grader_row_sha256(payload)


def _model_grader_row_sha256(row: dict[str, Any]) -> str:
    payload = {key: item for key, item in row.items() if key != "label_sha256"}
    encoded = json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8")
    return hashlib.sha256(encoded).hexdigest()


def _validate_model_grader_gate_sources(value: Any, target: ValidationTarget, source_path: Path) -> None:
    if not isinstance(value, dict):
        target.errors.append("model_grader_gate.source_artifacts must be an object.")
        return
    _validate_model_grader_referenced_artifact(
        value.get("dry_run_receipt"),
        target,
        "model_grader_gate.source_artifacts.dry_run_receipt",
        source_path,
        validate_model_grader_dry_run,
        allow_missing=False,
    )
    _validate_model_grader_referenced_artifact(
        value.get("rubric_spec"),
        target,
        "model_grader_gate.source_artifacts.rubric_spec",
        source_path,
        validate_rubric_spec,
        allow_missing=False,
    )
    _validate_model_grader_referenced_artifact(
        value.get("review_calibration"),
        target,
        "model_grader_gate.source_artifacts.review_calibration",
        source_path,
        validate_review_calibration,
        allow_missing=True,
    )
    _validate_model_grader_referenced_artifact(
        value.get("model_grader_override_receipt"),
        target,
        "model_grader_gate.source_artifacts.model_grader_override_receipt",
        source_path,
        validate_model_grader_override_receipt,
        allow_missing=True,
    )


def _validate_model_grader_override_sources(value: Any, target: ValidationTarget, source_path: Path) -> None:
    if not isinstance(value, dict):
        target.errors.append("model_grader_override_receipt.source_artifacts must be an object.")
        return
    _validate_model_grader_referenced_artifact(
        value.get("dry_run_receipt"),
        target,
        "model_grader_override_receipt.source_artifacts.dry_run_receipt",
        source_path,
        validate_model_grader_dry_run,
        allow_missing=False,
    )
    _validate_model_grader_source_file_ref(
        value.get("override_rows"),
        target,
        "model_grader_override_receipt.source_artifacts.override_rows",
        source_path,
        allow_missing=False,
    )


def _validate_model_grader_review_export_ref(
    value: Any,
    target: ValidationTarget,
    label: str,
    source_path: Path,
) -> dict[str, Path]:
    paths: dict[str, Path] = {}
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return paths
    if not isinstance(value.get("path"), str) or not value.get("path"):
        target.errors.append(f"{label}.path must be a non-empty string.")
    manifest_path = _validate_model_grader_source_file_ref(
        value.get("manifest"),
        target,
        f"{label}.manifest",
        source_path,
        allow_missing=False,
    )
    if manifest_path is not None:
        paths["manifest"] = manifest_path
    review_items_path = _validate_model_grader_source_file_ref(
        value.get("review_items"),
        target,
        f"{label}.review_items",
        source_path,
        allow_missing=False,
    )
    if review_items_path is not None:
        paths["review_items"] = review_items_path
    return paths


def _validate_model_grader_referenced_artifact(
    record: Any,
    target: ValidationTarget,
    label: str,
    source_path: Path,
    validator: Any,
    *,
    allow_missing: bool,
) -> Path | None:
    if allow_missing and record is None:
        return None
    artifact_path = _validate_model_grader_source_file_ref(record, target, label, source_path, allow_missing=allow_missing)
    if artifact_path is None:
        return None
    referenced = validator(artifact_path)
    target.warnings.extend(f"{label}: {warning}" for warning in referenced.warnings)
    target.errors.extend(f"{label}: {error}" for error in referenced.errors)
    return artifact_path


def _validate_model_grader_source_file_ref(
    record: Any,
    target: ValidationTarget,
    label: str,
    source_path: Path,
    *,
    allow_missing: bool,
) -> Path | None:
    if not isinstance(record, dict):
        target.errors.append(f"{label} must be an object.")
        return None
    path_value = record.get("path")
    artifact_path: Path | None = None
    if isinstance(path_value, str) and path_value:
        artifact_path = _resolve_model_grader_source_path(path_value, source_path)
        if artifact_path is None:
            target.errors.append(f"{label}.path must resolve from the model-grader artifact location.")
            return None
        if _path_has_symlink_component(artifact_path, include_leaf=True):
            target.errors.append(f"{label}.path must resolve to a regular non-symlink file.")
            return None
    exists = record.get("exists")
    if exists is not True:
        if allow_missing and exists is False:
            return None
        target.errors.append(f"{label}.exists must be true.")
        return None
    if artifact_path is None:
        target.errors.append(f"{label}.path must be a non-empty string when exists is true.")
        return None
    if not _is_non_negative_int(record.get("size_bytes")):
        target.errors.append(f"{label}.size_bytes must be a non-negative integer when exists is true.")
    if not _is_lowercase_sha256(record.get("sha256")):
        target.errors.append(f"{label}.sha256 must be a lowercase SHA-256 hex string when exists is true.")
    if not artifact_path.exists() or not artifact_path.is_file():
        target.errors.append(f"{label}.path must resolve to an existing file when exists is true.")
        return None
    if _is_non_negative_int(record.get("size_bytes")) and artifact_path.stat().st_size != record.get("size_bytes"):
        target.errors.append(f"{label}.size_bytes does not match the current file.")
    if _is_lowercase_sha256(record.get("sha256")) and _sha256(artifact_path) != record.get("sha256"):
        target.errors.append(f"{label}.sha256 does not match the current file.")
    return artifact_path


def _resolve_model_grader_source_path(value: Any, source_path: Path) -> Path | None:
    if not isinstance(value, str) or not value:
        return None
    path = Path(value)
    if path.is_absolute():
        return path
    if _is_windows_absolute(value):
        return None
    return source_path.parent / path


def _same_model_grader_source_file(left: Path, right: Path) -> bool:
    try:
        if left.resolve() == right.resolve():
            return True
        if left.stat().st_size != right.stat().st_size:
            return False
        return _sha256(left) == _sha256(right)
    except OSError:
        return False


def _validate_model_grader_boundary(value: Any, target: ValidationTarget, label: str) -> None:
    if not isinstance(value, dict):
        target.errors.append(f"{label}.execution_boundary must be an object.")
        return
    true_fields = ("dry_run_only",)
    false_fields = (
        "provider_api_called",
        "paid_model_grader_calls_started",
        "credential_values_recorded",
        "labels_admitted_to_training",
        "weights_updated_by_flight_recorder",
    )
    for field_name in true_fields:
        if value.get(field_name) is not True:
            target.errors.append(f"{label}.execution_boundary.{field_name} must be true.")
    for field_name in false_fields:
        if value.get(field_name) is not False:
            target.errors.append(f"{label}.execution_boundary.{field_name} must be false.")
    if value.get("cloud_cost_incurred_usd") != 0:
        target.errors.append(f"{label}.execution_boundary.cloud_cost_incurred_usd must be 0.")


def _model_grader_label_counts(value: Any, target: ValidationTarget, label: str) -> dict[str, int]:
    counts = {name: 0 for name in REVIEW_LABELS}
    if not isinstance(value, list):
        target.errors.append(f"{label} must be a list.")
        return counts
    seen: set[str] = set()
    for index, row in enumerate(value):
        row_label = f"{label}[{index}]"
        if not isinstance(row, dict):
            target.errors.append(f"{row_label} must be an object.")
            continue
        name = row.get("label")
        count = row.get("count")
        if name not in REVIEW_LABELS:
            target.errors.append(f"{row_label}.label must be one of {list(REVIEW_LABELS)!r}.")
            continue
        if name in seen:
            target.errors.append(f"{row_label}.label duplicates {name!r}.")
        seen.add(name)
        if not _is_non_negative_int(count):
            target.errors.append(f"{row_label}.count must be a non-negative integer.")
            continue
        counts[name] = int(count)
    missing = sorted(set(REVIEW_LABELS) - seen)
    if missing:
        target.errors.append(f"{label} missing label count row(s): {', '.join(missing)}.")
    return counts


def _validate_agentic_training_result_artifacts(value: Any, target: ValidationTarget, source_path: Path) -> dict[str, int]:
    counts = {
        "artifact_count": 0,
        "regular_artifact_count": 0,
        "output_artifact_count": 0,
        "config_count": 0,
        "metrics_file_count": 0,
        "adapter_count": 0,
        "checkpoint_count": 0,
        "log_count": 0,
        "failure_report_count": 0,
    }
    if not isinstance(value, list):
        target.errors.append("agentic_training_result.artifacts must be a list.")
        return counts
    counts["artifact_count"] = len(value)
    role_metric_fields = {
        "config": "config_count",
        "metrics": "metrics_file_count",
        "adapter": "adapter_count",
        "checkpoint": "checkpoint_count",
        "log": "log_count",
        "failure_report": "failure_report_count",
    }
    for index, artifact in enumerate(value):
        label = f"agentic_training_result.artifacts[{index}]"
        if not isinstance(artifact, dict):
            target.errors.append(f"{label} must be an object.")
            continue
        role = artifact.get("role")
        if not isinstance(role, str) or not role:
            target.errors.append(f"{label}.role must be a non-empty string.")
        elif role in role_metric_fields:
            counts[role_metric_fields[role]] += 1
        if role in OUTPUT_ARTIFACT_ROLES:
            counts["output_artifact_count"] += 1
        path_value = artifact.get("path")
        path_is_safe = isinstance(path_value, str) and _is_safe_agentic_training_result_path(path_value)
        current_path = _agentic_training_result_reference_path(path_value, source_path) if path_is_safe else None
        if not isinstance(path_value, str) or not path_value:
            target.errors.append(f"{label}.path must be a non-empty string.")
        elif not path_is_safe:
            target.errors.append(f"{label}.path must be a safe relative path without traversal.")
        for field_name in ("exists", "regular_file"):
            if not isinstance(artifact.get(field_name), bool):
                target.errors.append(f"{label}.{field_name} must be a boolean.")
        if artifact.get("exists") is True and current_path is not None and not current_path.exists():
            target.errors.append(f"{label}.path does not resolve to the current file.")
        if artifact.get("regular_file") is True and current_path is not None and current_path.is_symlink():
            target.errors.append(f"{label}.path must not be a symlink.")
        if artifact.get("regular_file") is True and current_path is not None and not current_path.is_file():
            target.errors.append(f"{label}.path does not resolve to a regular file.")
        if artifact.get("regular_file") is True:
            counts["regular_artifact_count"] += 1
            if not _is_sha256(artifact.get("sha256")):
                target.errors.append(f"{label}.sha256 must be a SHA-256 hex string for regular files.")
        elif artifact.get("sha256") is not None and not _is_sha256(artifact.get("sha256")):
            target.errors.append(f"{label}.sha256 must be a SHA-256 hex string or null.")
        if not _is_non_negative_int(artifact.get("size_bytes")):
            target.errors.append(f"{label}.size_bytes must be a non-negative integer.")
        elif artifact.get("regular_file") is True and current_path is not None and current_path.is_file():
            if current_path.stat().st_size != artifact.get("size_bytes"):
                target.errors.append(f"{label}.size_bytes does not match the current file.")
            if _is_sha256(artifact.get("sha256")) and _sha256(current_path) != artifact.get("sha256"):
                target.errors.append(f"{label}.sha256 does not match the current file.")
    return counts


def _validate_agentic_training_result_lineage(
    value: Any,
    target: ValidationTarget,
    source_path: Path,
    status: Any,
    expected_passed: bool,
) -> None:
    if not isinstance(value, dict):
        target.errors.append("agentic_training_result.lineage must be an object.")
        return
    plan_inputs = _agentic_training_result_plan_input_manifests(value, source_path)
    for field_name in ("plan", "runtime_preflight"):
        ref = value.get(field_name)
        label = f"agentic_training_result.lineage.{field_name}"
        if not isinstance(ref, dict):
            target.errors.append(f"{label} must be an object.")
            continue
        for string_field in ("path", "schema_name"):
            if not isinstance(ref.get(string_field), str) or not ref.get(string_field):
                target.errors.append(f"{label}.{string_field} must be a non-empty string.")
        if isinstance(ref.get("path"), str) and ref.get("path") and not _is_safe_agentic_training_result_path(ref["path"]):
            target.errors.append(f"{label}.path must be a safe relative path without traversal.")
        for bool_field in ("exists", "regular_file"):
            if not isinstance(ref.get(bool_field), bool):
                target.errors.append(f"{label}.{bool_field} must be a boolean.")
        if not _is_sha256(ref.get("sha256")):
            target.errors.append(f"{label}.sha256 must be a SHA-256 hex string.")
        if not _is_non_negative_int(ref.get("size_bytes")):
            target.errors.append(f"{label}.size_bytes must be a non-negative integer.")
        _validate_agentic_training_result_lineage_file(ref, target, label, source_path)
    for field_name in ("model", "dataset"):
        ref = value.get(field_name)
        label = f"agentic_training_result.lineage.{field_name}"
        if not isinstance(ref, dict):
            target.errors.append(f"{label} must be an object.")
            continue
        for string_field in ("id", "path", "sha256"):
            if not isinstance(ref.get(string_field), str):
                target.errors.append(f"{label}.{string_field} must be a string.")
        if isinstance(ref.get("path"), str) and ref.get("path") and not _is_safe_agentic_training_result_path(ref["path"]):
            target.errors.append(f"{label}.path must be a safe relative path without traversal.")
        if ref.get("sha256") and not _is_sha256(ref.get("sha256")):
            target.errors.append(f"{label}.sha256 must be a SHA-256 hex string when present.")
        if not _is_non_negative_int(ref.get("size_bytes")):
            target.errors.append(f"{label}.size_bytes must be a non-negative integer.")
        if ref.get("license_allows_training") is not True:
            target.errors.append(f"{label}.license_allows_training must be true.")
        expected_ref = plan_inputs.get(field_name)
        if isinstance(expected_ref, dict):
            _validate_agentic_training_result_manifest_matches_plan(ref, expected_ref, target, label, field_name)
    flow_ref = value.get("agentic_training_flow")
    if status == "completed" and expected_passed and not isinstance(flow_ref, dict):
        target.errors.append("agentic_training_result.lineage.agentic_training_flow is required for completed receipts.")
    if isinstance(flow_ref, dict):
        label = "agentic_training_result.lineage.agentic_training_flow"
        for string_field in ("path", "schema_name"):
            if not isinstance(flow_ref.get(string_field), str) or not flow_ref.get(string_field):
                target.errors.append(f"{label}.{string_field} must be a non-empty string.")
        if flow_ref.get("schema_name") != "agentic_training_flow":
            target.errors.append(f"{label}.schema_name must be 'agentic_training_flow'.")
        if isinstance(flow_ref.get("path"), str) and flow_ref.get("path") and not _is_safe_agentic_training_result_path(flow_ref["path"]):
            target.errors.append(f"{label}.path must be a safe relative path without traversal.")
        for bool_field in ("exists", "regular_file"):
            if not isinstance(flow_ref.get(bool_field), bool):
                target.errors.append(f"{label}.{bool_field} must be a boolean.")
        if not _is_sha256(flow_ref.get("sha256")):
            target.errors.append(f"{label}.sha256 must be a SHA-256 hex string.")
        if not _is_non_negative_int(flow_ref.get("size_bytes")):
            target.errors.append(f"{label}.size_bytes must be a non-negative integer.")
        _validate_agentic_training_result_lineage_file(flow_ref, target, label, source_path)
        _validate_agentic_training_result_flow_lineage(flow_ref, value, target, source_path, status, expected_passed)


def _validate_agentic_training_result_flow_lineage(
    flow_ref: dict[str, Any],
    lineage: dict[str, Any],
    target: ValidationTarget,
    source_path: Path,
    status: Any,
    expected_passed: bool,
) -> None:
    path_value = flow_ref.get("path")
    if not isinstance(path_value, str) or not _is_safe_agentic_training_result_path(path_value):
        return
    flow_path = _agentic_training_result_reference_path(path_value, source_path)
    if not flow_path.is_file() or flow_path.is_symlink():
        return
    try:
        flow = json.loads(flow_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        if status == "completed" and expected_passed:
            target.errors.append("agentic_training_result.lineage.agentic_training_flow.path must contain readable JSON.")
        return
    if not isinstance(flow, dict):
        if status == "completed" and expected_passed:
            target.errors.append("agentic_training_result.lineage.agentic_training_flow.path must contain a JSON object.")
        return
    if status != "completed" or not expected_passed:
        return
    flow_target = ValidationTarget("agentic_training_flow", str(flow_path))
    _validate_agentic_training_flow(flow, flow_target, flow_path)
    if flow_target.errors:
        for error in flow_target.errors:
            target.errors.append(f"agentic_training_result.lineage.agentic_training_flow invalid: {error}")
    if flow.get("schema_version") != AGENTIC_TRAINING_FLOW_SCHEMA_VERSION:
        target.errors.append(
            f"agentic_training_result.lineage.agentic_training_flow.schema_version must be {AGENTIC_TRAINING_FLOW_SCHEMA_VERSION!r}."
        )
    if flow.get("passed") is not True:
        target.errors.append("agentic_training_result.lineage.agentic_training_flow.passed must be true for completed receipts.")
    if flow.get("recommendation") != FLOW_READY_RECOMMENDATION:
        target.errors.append(
            "agentic_training_result.lineage.agentic_training_flow.recommendation must be ready_for_delegated_trainer_execution."
        )
    flow_mode_gate = flow.get("flow_mode_gate") if isinstance(flow.get("flow_mode_gate"), dict) else {}
    if flow_mode_gate.get("executable_by_default") is not True:
        target.errors.append("agentic_training_result.lineage.agentic_training_flow.flow_mode_gate.executable_by_default must be true.")
    if flow_mode_gate.get("blocked_by_default") is not False:
        target.errors.append("agentic_training_result.lineage.agentic_training_flow.flow_mode_gate.blocked_by_default must be false.")
    source_artifacts = flow.get("source_artifacts") if isinstance(flow.get("source_artifacts"), dict) else {}
    expected = {
        "agentic_training_plan": ("plan", "plan"),
        "agentic_training_runtime_preflight": ("runtime_preflight", "runtime_preflight"),
    }
    for flow_role, (lineage_role, label_role) in expected.items():
        flow_source = source_artifacts.get(flow_role) if isinstance(source_artifacts.get(flow_role), dict) else {}
        lineage_source = lineage.get(lineage_role) if isinstance(lineage.get(lineage_role), dict) else {}
        if flow_source.get("sha256") != lineage_source.get("sha256"):
            target.errors.append(
                "agentic_training_result.lineage.agentic_training_flow.source_artifacts."
                f"{flow_role}.sha256 must match lineage.{label_role}.sha256."
            )


def _agentic_training_result_plan_input_manifests(lineage: dict[str, Any], source_path: Path) -> dict[str, Any]:
    plan_ref = lineage.get("plan")
    if not isinstance(plan_ref, dict):
        return {}
    path_value = plan_ref.get("path")
    if not isinstance(path_value, str) or not path_value:
        return {}
    if not _is_safe_agentic_training_result_path(path_value):
        return {}
    plan_path = _agentic_training_result_reference_path(path_value, source_path)
    if not plan_path.is_file():
        return {}
    try:
        payload = json.loads(plan_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return {}
    if not isinstance(payload, dict):
        return {}
    manifests = payload.get("input_manifests")
    return manifests if isinstance(manifests, dict) else {}


def _validate_agentic_training_result_manifest_matches_plan(
    ref: dict[str, Any],
    expected_ref: dict[str, Any],
    target: ValidationTarget,
    label: str,
    field_name: str,
) -> None:
    expected_label = f"agentic_training_plan.input_manifests.{field_name}"
    for string_field in ("id", "sha256"):
        if isinstance(expected_ref.get(string_field), str) and ref.get(string_field) != expected_ref.get(string_field):
            target.errors.append(f"{label}.{string_field} must match {expected_label}.{string_field}.")
    if isinstance(expected_ref.get("path"), str):
        expected_path = _agentic_training_result_redacted_path(expected_ref["path"])
        if ref.get("path") != expected_path:
            target.errors.append(f"{label}.path must match the safe {expected_label}.path.")
    if _is_non_negative_int(expected_ref.get("size_bytes")) and ref.get("size_bytes") != expected_ref.get("size_bytes"):
        target.errors.append(f"{label}.size_bytes must match {expected_label}.size_bytes.")
    if isinstance(expected_ref.get("license_allows_training"), bool) and ref.get("license_allows_training") != expected_ref.get(
        "license_allows_training"
    ):
        target.errors.append(f"{label}.license_allows_training must match {expected_label}.license_allows_training.")


def _validate_agentic_training_result_lineage_file(
    ref: dict[str, Any], target: ValidationTarget, label: str, source_path: Path
) -> None:
    path_value = ref.get("path")
    if not isinstance(path_value, str) or not path_value:
        return
    if not _is_safe_agentic_training_result_path(path_value):
        return
    current_path = _agentic_training_result_reference_path(path_value, source_path)
    if ref.get("exists") is not True:
        target.errors.append(f"{label}.exists must be true.")
    if ref.get("regular_file") is not True:
        target.errors.append(f"{label}.regular_file must be true.")
    if ref.get("exists") is True and not current_path.exists():
        target.errors.append(f"{label}.path does not resolve to the current file.")
        return
    if ref.get("regular_file") is True and not current_path.is_file():
        target.errors.append(f"{label}.path does not resolve to a regular file.")
        return
    if not current_path.exists() or not current_path.is_file():
        return
    if current_path.is_symlink():
        target.errors.append(f"{label}.path must not be a symlink.")
        return
    if _is_non_negative_int(ref.get("size_bytes")) and current_path.stat().st_size != ref.get("size_bytes"):
        target.errors.append(f"{label}.size_bytes does not match the current file.")
    if _is_sha256(ref.get("sha256")) and _sha256(current_path) != ref.get("sha256"):
        target.errors.append(f"{label}.sha256 does not match the current file.")


def _agentic_training_result_reference_path(value: str, source_path: Path) -> Path:
    path = Path(value)
    if path.is_absolute():
        return path
    return source_path.parent / path


def _validate_agentic_training_result_boundary(value: Any, target: ValidationTarget, field_name: str) -> None:
    label = f"agentic_training_result.{field_name}"
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    expected = {
        "archive_only": True,
        "runner_owns_execution": True,
        "flight_recorder_launched_training": False,
        "training_started_by_flight_recorder": False,
        "model_downloads_started_by_flight_recorder": False,
        "trainer_modules_imported_by_flight_recorder": False,
    }
    for key, expected_value in expected.items():
        if value.get(key) != expected_value:
            target.errors.append(f"{label}.{key} expected {expected_value!r}, got {value.get(key)!r}.")


def _validate_agentic_training_result_contract(value: Any, target: ValidationTarget) -> None:
    label = "agentic_training_result.handoff_contract"
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    expected = {
        "runner_owns_execution": True,
        "requires_agentic_training_plan": True,
        "requires_runtime_preflight": True,
        "requires_agentic_training_flow_for_completed": True,
        "requires_runtime_ready_for_completed": True,
        "requires_flow_ready_for_completed": True,
        "requires_classified_failure_for_non_completed": True,
        "requires_output_artifact_for_completed": True,
        "requires_registered_model": True,
        "requires_registered_dataset": True,
        "requires_redacted_dataset": True,
        "flight_recorder_launched_training": False,
        "model_downloads_started_by_flight_recorder": False,
    }
    for key, expected_value in expected.items():
        if value.get(key) != expected_value:
            target.errors.append(f"{label}.{key} expected {expected_value!r}, got {value.get(key)!r}.")


def _validate_agentic_training_result_registry_update(
    value: Any, expected_ready: bool, target: ValidationTarget, artifacts: Any, status: Any, receipt_artifact_path: Any
) -> None:
    label = "agentic_training_result.registry_update"
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object when present.")
        return
    for key, expected_value in {"applied": False, "side_effect_free": True, "ready_to_apply": expected_ready}.items():
        if value.get(key) != expected_value:
            target.errors.append(f"{label}.{key} expected {expected_value!r}, got {value.get(key)!r}.")
    for field_name in ("target_model_id", "target_dataset_id"):
        if not isinstance(value.get(field_name), str):
            target.errors.append(f"{label}.{field_name} must be a string.")
    links = value.get("links")
    if not isinstance(links, list):
        target.errors.append(f"{label}.links must be a list.")
        return
    if not links:
        target.errors.append(f"{label}.links must not be empty.")
    output_artifact_counter = _agentic_training_result_output_artifact_counter(artifacts)
    linked_output_counter: Counter[tuple[Any, Any, Any, Any]] = Counter()
    for index, link in enumerate(links):
        link_label = f"{label}.links[{index}]"
        if not isinstance(link, dict):
            target.errors.append(f"{link_label} must be an object.")
            continue
        for field_name in ("collection", "artifact_id", "kind", "status", "path"):
            if not isinstance(link.get(field_name), str) or not link.get(field_name):
                target.errors.append(f"{link_label}.{field_name} must be a non-empty string.")
        path_value = link.get("path")
        if isinstance(path_value, str) and path_value and not _is_safe_agentic_training_result_path(path_value):
            target.errors.append(f"{link_label}.path must be a safe relative path without traversal.")
        if link.get("collection") == "training_runs":
            if isinstance(receipt_artifact_path, str) and link.get("path") != receipt_artifact_path:
                target.errors.append(f"{link_label}.path must match agentic_training_result.artifact_path.")
            if "sha256" in link and link.get("sha256") is not None and not _is_sha256(link.get("sha256")):
                target.errors.append(f"{link_label}.sha256 must be a SHA-256 hex string or null.")
            if "size_bytes" in link and not _is_non_negative_int(link.get("size_bytes")):
                target.errors.append(f"{link_label}.size_bytes must be a non-negative integer.")
            continue
        if not _is_sha256(link.get("sha256")):
            target.errors.append(f"{link_label}.sha256 must be a SHA-256 hex string for artifact registry links.")
        if not _is_non_negative_int(link.get("size_bytes")):
            target.errors.append(f"{link_label}.size_bytes must be a non-negative integer for artifact registry links.")
        key = (link.get("path"), link.get("sha256"), link.get("size_bytes"), link.get("kind"))
        if output_artifact_counter.get(key, 0) == 0:
            target.errors.append(f"{link_label} must match a supplied output artifact ref by path, sha256, size_bytes, and kind.")
            matching_roles = sorted(
                str(candidate[3])
                for candidate in output_artifact_counter
                if candidate[:3] == key[:3] and isinstance(candidate[3], str)
            )
            if matching_roles and link.get("kind") not in matching_roles:
                target.errors.append(f"{link_label}.kind must match the supplied output artifact role.")
        else:
            if link.get("collection") != "adapters":
                target.errors.append(f"{link_label}.collection must be 'adapters' for output artifact registry links.")
            if link.get("collection") == "adapters":
                linked_output_counter[key] += 1
    if links and isinstance(links[0], dict) and links[0].get("collection") != "training_runs":
        target.errors.append(f"{label}.links[0].collection must be 'training_runs'.")
    if status == "completed":
        missing_links = sorted(
            key[0]
            for key, expected_count in output_artifact_counter.items()
            if linked_output_counter.get(key, 0) < expected_count
        )
        if missing_links:
            target.errors.append(
                f"{label}.links must include size-bound registry links for completed output artifacts: {missing_links!r}."
            )
        extra_links = sorted(
            key[0]
            for key, linked_count in linked_output_counter.items()
            if linked_count > output_artifact_counter.get(key, 0)
        )
        if extra_links:
            target.errors.append(f"{label}.links must not duplicate output artifact registry links: {extra_links!r}.")


def _agentic_training_result_output_artifact_counter(artifacts: Any) -> Counter[tuple[Any, Any, Any, Any]]:
    if not isinstance(artifacts, list):
        return Counter()
    counter: Counter[tuple[Any, Any, Any, Any]] = Counter()
    for artifact in artifacts:
        if not isinstance(artifact, dict):
            continue
        if artifact.get("role") not in OUTPUT_ARTIFACT_ROLES:
            continue
        counter[(artifact.get("path"), artifact.get("sha256"), artifact.get("size_bytes"), artifact.get("role"))] += 1
    return counter


def _agentic_training_result_redacted_path(value: str) -> str:
    if _is_safe_agentic_training_result_path(value):
        return value
    normalized = value.replace("\\", "/")
    basename = normalized.rstrip("/").rsplit("/", 1)[-1]
    return basename if _is_safe_agentic_training_result_path(basename) else "artifact"


def _is_safe_agentic_training_result_path(value: str) -> bool:
    path = Path(value)
    windows_path = PureWindowsPath(value)
    return (
        bool(value)
        and not path.is_absolute()
        and not windows_path.is_absolute()
        and not windows_path.drive
        and "\\" not in value
        and "~" not in path.parts
        and ".." not in path.parts
    )


def _model_scout_reference_path(value: Any, source_path: Path) -> Path | None:
    if not isinstance(value, str) or not value:
        return None
    path = Path(value)
    if path.is_absolute() or path.exists():
        return path
    local_path = source_path.parent / path
    return local_path if local_path.exists() else path


def _validate_live_smoke_summary(summary: dict[str, Any], target: ValidationTarget) -> None:
    schema_version = summary.get("schema_version")
    allowed_versions = {LIVE_SMOKE_SUMMARY_SCHEMA_VERSION, *LEGACY_LIVE_SMOKE_SUMMARY_SCHEMA_VERSIONS}
    if schema_version not in allowed_versions:
        target.errors.append(
            f"live_smoke_summary.schema_version expected one of {sorted(allowed_versions)!r}, got {schema_version!r}."
        )
    if schema_version in LEGACY_LIVE_SMOKE_SUMMARY_SCHEMA_VERSIONS:
        target.warnings.append(
            "live_smoke_summary is a legacy schema without required runtime provenance; regenerate it with the current live smoke script."
        )
    if not isinstance(summary.get("passed"), bool):
        target.errors.append("live_smoke_summary.passed must be a boolean.")
    score = summary.get("score")
    if not isinstance(score, int) or isinstance(score, bool) or not 0 <= score <= 100:
        target.errors.append("live_smoke_summary.score must be an integer from 0 to 100.")
        score = 0
    for field_name in ("hermes_exit_code", "mock_request_count", "chat_completion_request_count"):
        if not _is_non_negative_int(summary.get(field_name)):
            target.errors.append(f"live_smoke_summary.{field_name} must be a non-negative integer.")
    required_paths = ["observer_file", "report", "lineage", "task_completion", "summary"]
    if schema_version == LIVE_SMOKE_SUMMARY_SCHEMA_VERSION:
        required_paths.append("run_digest")
    for field_name in required_paths:
        if not isinstance(summary.get(field_name), str) or not summary.get(field_name):
            target.errors.append(f"live_smoke_summary.{field_name} must be a non-empty string.")
    hooks = summary.get("hooks")
    if not _is_string_list(hooks):
        target.errors.append("live_smoke_summary.hooks must be a list of strings.")
        hooks = []
    missing_hooks = summary.get("missing_hooks")
    if not _is_string_list(missing_hooks):
        target.errors.append("live_smoke_summary.missing_hooks must be a list of strings.")
        missing_hooks = []
    environment = summary.get("environment")
    environment_details: dict[str, Any] = {}
    if schema_version == LIVE_SMOKE_SUMMARY_SCHEMA_VERSION:
        environment_details = _validate_live_smoke_environment(environment, target)
    elif isinstance(environment, dict):
        environment_details = _validate_live_smoke_environment(environment, target)

    expected_passed = (
        summary.get("hermes_exit_code") == 0
        and isinstance(score, int)
        and score >= 90
        and not missing_hooks
        and _is_non_negative_int(summary.get("chat_completion_request_count"))
        and int(summary.get("chat_completion_request_count")) > 0
    )
    if isinstance(summary.get("passed"), bool) and summary.get("passed") != expected_passed:
        target.errors.append(
            "live_smoke_summary.passed must match exit code, score, missing hooks, and chat completion request count."
        )
    target.details.update(
        {
            "passed": summary.get("passed"),
            "score": summary.get("score"),
            "hook_count": len(hooks),
            "missing_hook_count": len(missing_hooks),
            "chat_completion_request_count": summary.get("chat_completion_request_count"),
            **environment_details,
        }
    )


def _validate_live_smoke_environment(environment: Any, target: ValidationTarget) -> dict[str, Any]:
    if not isinstance(environment, dict):
        target.errors.append("live_smoke_summary.environment must be an object.")
        return {}
    details: dict[str, Any] = {}
    required_strings = (
        "python_version",
        "python_implementation",
        "platform",
        "hermes_root",
        "hermes_git_commit",
        "flight_recorder_root",
        "flight_recorder_git_commit",
    )
    for field_name in required_strings:
        value = environment.get(field_name)
        if not isinstance(value, str) or not value:
            target.errors.append(f"live_smoke_summary.environment.{field_name} must be a non-empty string.")
    for field_name in ("hermes_git_dirty", "flight_recorder_git_dirty"):
        value = environment.get(field_name)
        if value is not None and not isinstance(value, bool):
            target.errors.append(f"live_smoke_summary.environment.{field_name} must be a boolean or null.")
    for field_name in ("platform", "hermes_git_commit", "flight_recorder_git_commit"):
        value = environment.get(field_name)
        if isinstance(value, str) and value:
            details[field_name] = value
    return details


def validate_suite_trend(path: str | Path) -> ValidationTarget:
    """Validate one trend-suite artifact."""
    trend_path = Path(path)
    target = ValidationTarget("suite_trend", str(trend_path))
    trend = _read_object(trend_path, target, "suite_trend.json")
    if trend is None:
        return target
    _validate_suite_trend(trend, target)
    return target


def _validate_state_snapshot(
    snapshot: dict[str, Any],
    target: ValidationTarget,
    label: str,
    *,
    source_path: Path | None = None,
) -> None:
    _require_equal(snapshot, "schema_version", STATE_SNAPSHOT_SCHEMA_VERSION, target, prefix=f"{label}.")
    filesystem = snapshot.get("filesystem")
    if not isinstance(filesystem, dict):
        target.errors.append(f"{label}.filesystem must be an object.")
        filesystem = {}
    files = filesystem.get("files")
    if not isinstance(files, dict):
        target.errors.append(f"{label}.filesystem.files must be an object.")
        files = {}
    directories = filesystem.get("directories")
    if not isinstance(directories, dict):
        target.errors.append(f"{label}.filesystem.directories must be an object.")
        directories = {}
    for key, record in files.items():
        if not isinstance(key, str) or not key:
            target.errors.append(f"{label}.filesystem.files contains an empty source key.")
            continue
        _validate_snapshot_file_record(record, target, f"{label}.filesystem.files.{key}", source_path)
    for key, record in directories.items():
        if not isinstance(key, str) or not key:
            target.errors.append(f"{label}.filesystem.directories contains an empty source key.")
            continue
        _validate_snapshot_directory_record(record, target, f"{label}.filesystem.directories.{key}")

    json_sources = snapshot.get("json_sources")
    if not isinstance(json_sources, dict):
        target.errors.append(f"{label}.json_sources must be an object.")
        json_sources = {}
    json_payloads = snapshot.get("json")
    if not isinstance(json_payloads, dict):
        target.errors.append(f"{label}.json must be an object.")
        json_payloads = {}
    for key, record in json_sources.items():
        if not isinstance(key, str) or not key:
            target.errors.append(f"{label}.json_sources contains an empty source key.")
            continue
        _validate_snapshot_file_record(record, target, f"{label}.json_sources.{key}", source_path)
        if isinstance(record, dict) and record.get("exists") is True and record.get("kind") == "file" and key not in json_payloads:
            target.errors.append(f"{label}.json.{key} must contain imported JSON for an existing JSON source.")
    observations = snapshot.get("observations")
    if not isinstance(observations, dict):
        target.errors.append(f"{label}.observations must be an object.")
    verifiers = snapshot.get("verifiers")
    if verifiers is not None:
        _validate_snapshot_verifiers(verifiers, target, f"{label}.verifiers")


def _validate_snapshot_verifiers(verifiers: Any, target: ValidationTarget, label: str) -> None:
    if not isinstance(verifiers, dict):
        target.errors.append(f"{label} must be an object.")
        return
    _require_equal(verifiers, "schema_version", VERIFIER_SOURCES_SCHEMA_VERSION, target, prefix=f"{label}.")
    sources = verifiers.get("sources")
    if not isinstance(sources, dict):
        target.errors.append(f"{label}.sources must be an object.")
        sources = {}
    source_count = verifiers.get("source_count")
    if not isinstance(source_count, int):
        target.errors.append(f"{label}.source_count must be an integer.")
    elif source_count != len(sources):
        target.errors.append(f"{label}.source_count must equal the number of sources.")
    for source_id, source in sources.items():
        source_label = f"{label}.sources.{source_id}"
        if not isinstance(source_id, str) or not source_id:
            target.errors.append(f"{label}.sources contains an empty source id.")
            continue
        if not isinstance(source, dict):
            target.errors.append(f"{source_label} must be an object.")
            continue
        if not isinstance(source.get("type"), str) or not source.get("type"):
            target.errors.append(f"{source_label}.type must be a non-empty string.")
        if source.get("status") not in {"ok", "error"}:
            target.errors.append(f"{source_label}.status must be ok or error.")
        if source.get("readonly") is not True:
            target.errors.append(f"{source_label}.readonly must be true.")
        if "data" not in source:
            target.errors.append(f"{source_label}.data is required.")


def _validate_state_diff(diff: Any, target: ValidationTarget, label: str) -> None:
    if not isinstance(diff, dict):
        target.errors.append(f"{label} must be an object.")
        return
    _require_equal(diff, "schema_version", STATE_DIFF_SCHEMA_VERSION, target, prefix=f"{label}.")
    changed = diff.get("changed")
    if not isinstance(changed, bool):
        target.errors.append(f"{label}.changed must be a boolean.")
        changed = False
    change_count = diff.get("change_count")
    if not _is_non_negative_int(change_count):
        target.errors.append(f"{label}.change_count must be a non-negative integer.")
        change_count = 0
    max_changes = diff.get("max_changes")
    if not _is_non_negative_int(max_changes):
        target.errors.append(f"{label}.max_changes must be a non-negative integer.")
        max_changes = 0
    truncated = diff.get("truncated")
    if not isinstance(truncated, bool):
        target.errors.append(f"{label}.truncated must be a boolean.")
        truncated = False
    changes = diff.get("changes")
    if not isinstance(changes, list):
        target.errors.append(f"{label}.changes must be a list.")
        changes = []
    if changed != bool(change_count):
        target.errors.append(f"{label}.changed must match whether change_count is greater than zero.")
    if isinstance(change_count, int) and isinstance(max_changes, int):
        if len(changes) > max_changes:
            target.errors.append(f"{label}.changes length must not exceed max_changes.")
        expected_truncated = change_count > len(changes)
        if truncated != expected_truncated:
            target.errors.append(f"{label}.truncated must match whether change_count exceeds emitted changes.")
        if not truncated and len(changes) != change_count:
            target.errors.append(f"{label}.changes length must equal change_count when not truncated.")
    for index, change in enumerate(changes):
        _validate_state_diff_change(change, target, f"{label}.changes[{index}]")
    if not isinstance(diff.get("summary"), str) or not diff.get("summary"):
        target.errors.append(f"{label}.summary must be a non-empty string.")


def _validate_state_diff_change(change: Any, target: ValidationTarget, label: str) -> None:
    if not isinstance(change, dict):
        target.errors.append(f"{label} must be an object.")
        return
    if not isinstance(change.get("path"), str) or not change.get("path"):
        target.errors.append(f"{label}.path must be a non-empty string.")
    if change.get("kind") not in {"added", "removed", "changed"}:
        target.errors.append(f"{label}.kind must be added, removed, or changed.")
    if "before" not in change:
        target.errors.append(f"{label}.before is required.")
    if "after" not in change:
        target.errors.append(f"{label}.after is required.")


def _validate_state_diff_summary(summary: Any, target: ValidationTarget, label: str) -> None:
    if not isinstance(summary, dict):
        target.errors.append(f"{label} must be an object.")
        return
    _require_equal(summary, "schema_version", "hfr.state_diff.summary.v1", target, prefix=f"{label}.")
    if not isinstance(summary.get("available"), bool):
        target.errors.append(f"{label}.available must be a boolean.")
    if not isinstance(summary.get("changed"), bool):
        target.errors.append(f"{label}.changed must be a boolean.")
    if not _is_non_negative_int(summary.get("change_count")):
        target.errors.append(f"{label}.change_count must be a non-negative integer.")
    if not isinstance(summary.get("truncated"), bool):
        target.errors.append(f"{label}.truncated must be a boolean.")
    if not isinstance(summary.get("summary"), str):
        target.errors.append(f"{label}.summary must be a string.")
    changes = summary.get("changes")
    if not isinstance(changes, list):
        target.errors.append(f"{label}.changes must be a list.")
        return
    for index, change in enumerate(changes):
        if not isinstance(change, dict):
            target.errors.append(f"{label}.changes[{index}] must be an object.")
            continue
        if not isinstance(change.get("path"), str):
            target.errors.append(f"{label}.changes[{index}].path must be a string.")
        if change.get("kind") not in {"", "added", "removed", "changed"}:
            target.errors.append(f"{label}.changes[{index}].kind must be added, removed, changed, or empty.")


def _validate_run_digest(
    digest: Any,
    target: ValidationTarget,
    label: str,
    *,
    trace: dict[str, Any] | None = None,
    scorecard: dict[str, Any] | None = None,
    task_completion: dict[str, Any] | None = None,
    state_diff: Any = _COMPANION_NOT_PROVIDED,
) -> None:
    if not isinstance(digest, dict):
        target.errors.append(f"{label} must be an object.")
        return
    _require_equal(digest, "schema_version", RUN_DIGEST_SCHEMA_VERSION, target, prefix=f"{label}.")

    scenario = digest.get("scenario")
    if not isinstance(scenario, dict):
        target.errors.append(f"{label}.scenario must be an object.")
        scenario = {}
    for field_name in ("id", "title", "task_family"):
        if not isinstance(scenario.get(field_name), str) or not scenario.get(field_name):
            target.errors.append(f"{label}.scenario.{field_name} must be a non-empty string.")
    if scorecard is not None:
        if scenario.get("id") != scorecard.get("scenario_id"):
            target.errors.append(f"{label}.scenario.id must match scorecard.scenario_id.")
        if scenario.get("title") != scorecard.get("scenario_title"):
            target.errors.append(f"{label}.scenario.title must match scorecard.scenario_title.")

    outcome = digest.get("outcome")
    if not isinstance(outcome, dict):
        target.errors.append(f"{label}.outcome must be an object.")
        outcome = {}
    _validate_run_digest_outcome(outcome, target, f"{label}.outcome", scorecard, task_completion)

    trace_signal = digest.get("trace_signal")
    if not isinstance(trace_signal, dict):
        target.errors.append(f"{label}.trace_signal must be an object.")
        trace_signal = {}
    _validate_run_digest_trace_signal(trace_signal, target, f"{label}.trace_signal", trace)

    state_changes = digest.get("state_changes")
    if not isinstance(state_changes, dict):
        target.errors.append(f"{label}.state_changes must be an object.")
        state_changes = {}
    _validate_run_digest_state_changes(state_changes, target, f"{label}.state_changes", state_diff)

    rules = digest.get("rules")
    if not isinstance(rules, dict):
        target.errors.append(f"{label}.rules must be an object.")
        rules = {}
    _validate_run_digest_rules(rules, target, f"{label}.rules", scorecard)

    evidence = digest.get("evidence")
    if not isinstance(evidence, dict):
        target.errors.append(f"{label}.evidence must be an object.")
        evidence = {}
    _validate_run_digest_evidence(evidence, target, f"{label}.evidence", scorecard, task_completion)

    training = digest.get("training_signals")
    if not isinstance(training, dict):
        target.errors.append(f"{label}.training_signals must be an object.")
        training = {}
    _validate_run_digest_training(training, target, f"{label}.training_signals", outcome, state_changes, rules)

    actions = digest.get("recommended_actions")
    if not isinstance(actions, list):
        target.errors.append(f"{label}.recommended_actions must be a list.")
    else:
        for index, action in enumerate(actions):
            if not isinstance(action, dict):
                target.errors.append(f"{label}.recommended_actions[{index}] must be an object.")
                continue
            for field_name in ("id", "priority", "reason"):
                if not isinstance(action.get(field_name), str) or not action.get(field_name):
                    target.errors.append(f"{label}.recommended_actions[{index}].{field_name} must be a non-empty string.")


def _validate_run_digest_outcome(
    outcome: dict[str, Any],
    target: ValidationTarget,
    label: str,
    scorecard: dict[str, Any] | None,
    task_completion: dict[str, Any] | None,
) -> None:
    if not isinstance(outcome.get("passed"), bool):
        target.errors.append(f"{label}.passed must be a boolean.")
    if not _is_int_between(outcome.get("score"), 0, 100):
        target.errors.append(f"{label}.score must be an integer from 0 to 100.")
    if not _is_int_between(outcome.get("pass_threshold"), 0, 100):
        target.errors.append(f"{label}.pass_threshold must be an integer from 0 to 100.")
    if not _is_string_list(outcome.get("critical_failures")):
        target.errors.append(f"{label}.critical_failures must be a list of strings.")
    if not isinstance(outcome.get("summary"), str):
        target.errors.append(f"{label}.summary must be a string.")
    if outcome.get("task_completion_status") not in {"complete", "incomplete", "not_applicable"}:
        target.errors.append(f"{label}.task_completion_status must be complete, incomplete, or not_applicable.")
    if not isinstance(outcome.get("task_completion_passed"), bool):
        target.errors.append(f"{label}.task_completion_passed must be a boolean.")
    if scorecard is not None:
        for field_name in ("passed", "score", "pass_threshold", "critical_failures", "summary"):
            if outcome.get(field_name) != scorecard.get(field_name):
                target.errors.append(f"{label}.{field_name} must match scorecard.{field_name}.")
    task = task_completion
    if task is None and isinstance(scorecard, dict) and isinstance(scorecard.get("task_completion"), dict):
        task = scorecard["task_completion"]
    if isinstance(task, dict):
        if outcome.get("task_completion_status") != task.get("status"):
            target.errors.append(f"{label}.task_completion_status must match task_completion.status.")
        if outcome.get("task_completion_passed") != task.get("passed"):
            target.errors.append(f"{label}.task_completion_passed must match task_completion.passed.")


def _validate_run_digest_trace_signal(
    signal: dict[str, Any],
    target: ValidationTarget,
    label: str,
    trace: dict[str, Any] | None,
) -> None:
    for field_name in (
        "event_count",
        "tool_call_count",
        "tool_result_count",
        "api_call_count",
        "subagent_start_count",
        "max_subagent_depth",
    ):
        if not _is_non_negative_int(signal.get(field_name)):
            target.errors.append(f"{label}.{field_name} must be a non-negative integer.")
    if not _is_string_list(signal.get("event_types")):
        target.errors.append(f"{label}.event_types must be a list of strings.")
    for field_name in ("has_final_answer", "has_tool_or_api_events"):
        if not isinstance(signal.get(field_name), bool):
            target.errors.append(f"{label}.{field_name} must be a boolean.")
    for field_name in ("source_format", "model"):
        if not isinstance(signal.get(field_name), str) or not signal.get(field_name):
            target.errors.append(f"{label}.{field_name} must be a non-empty string.")
    if trace is None:
        return
    expected = _run_digest_trace_signal(trace)
    for field_name, expected_value in expected.items():
        if signal.get(field_name) != expected_value:
            target.errors.append(f"{label}.{field_name} expected {expected_value!r}, got {signal.get(field_name)!r}.")


def _validate_run_digest_state_changes(
    state_changes: dict[str, Any],
    target: ValidationTarget,
    label: str,
    state_diff: Any,
) -> None:
    for field_name in ("available", "changed", "truncated"):
        if not isinstance(state_changes.get(field_name), bool):
            target.errors.append(f"{label}.{field_name} must be a boolean.")
    if not _is_non_negative_int(state_changes.get("change_count")):
        target.errors.append(f"{label}.change_count must be a non-negative integer.")
    if not isinstance(state_changes.get("summary"), str):
        target.errors.append(f"{label}.summary must be a string.")
    top_changes = state_changes.get("top_changes")
    if not isinstance(top_changes, list):
        target.errors.append(f"{label}.top_changes must be a list.")
        top_changes = []
    for index, change in enumerate(top_changes):
        if not isinstance(change, dict):
            target.errors.append(f"{label}.top_changes[{index}] must be an object.")
            continue
        if not isinstance(change.get("path"), str):
            target.errors.append(f"{label}.top_changes[{index}].path must be a string.")
        if not isinstance(change.get("kind"), str):
            target.errors.append(f"{label}.top_changes[{index}].kind must be a string.")
    if state_diff is _COMPANION_NOT_PROVIDED:
        return
    if state_diff is None:
        if state_changes.get("available") is not False:
            target.errors.append(f"{label}.available must be false when state_diff.json is absent.")
        return
    if state_changes.get("available") is not True:
        target.errors.append(f"{label}.available must be true when state_diff.json is present.")
    expected_fields = {
        "changed": state_diff.get("changed"),
        "change_count": state_diff.get("change_count"),
        "truncated": state_diff.get("truncated"),
        "summary": state_diff.get("summary"),
    }
    for field_name, expected_value in expected_fields.items():
        if state_changes.get(field_name) != expected_value:
            target.errors.append(f"{label}.{field_name} must match state_diff.{field_name}.")
    expected_top = [
        {"path": str(change.get("path") or ""), "kind": str(change.get("kind") or "")}
        for change in (state_diff.get("changes") if isinstance(state_diff.get("changes"), list) else [])[:10]
        if isinstance(change, dict)
    ]
    if top_changes != expected_top:
        target.errors.append(f"{label}.top_changes must match the first state_diff changes by path/kind.")


def _validate_run_digest_rules(
    rules: dict[str, Any],
    target: ValidationTarget,
    label: str,
    scorecard: dict[str, Any] | None,
) -> None:
    for field_name in ("total_count", "failed_count", "critical_failed_count"):
        if not _is_non_negative_int(rules.get(field_name)):
            target.errors.append(f"{label}.{field_name} must be a non-negative integer.")
    failed = rules.get("failed")
    if not isinstance(failed, list):
        target.errors.append(f"{label}.failed must be a list.")
        failed = []
    for index, rule in enumerate(failed):
        if not isinstance(rule, dict):
            target.errors.append(f"{label}.failed[{index}] must be an object.")
            continue
        for field_name in ("id", "name"):
            if not isinstance(rule.get(field_name), str) or not rule.get(field_name):
                target.errors.append(f"{label}.failed[{index}].{field_name} must be a non-empty string.")
        if not isinstance(rule.get("critical"), bool):
            target.errors.append(f"{label}.failed[{index}].critical must be a boolean.")
        if not _is_int_between(rule.get("penalty"), 0, 100):
            target.errors.append(f"{label}.failed[{index}].penalty must be an integer from 0 to 100.")
        if not _is_non_negative_int(rule.get("evidence_ref_count")):
            target.errors.append(f"{label}.failed[{index}].evidence_ref_count must be a non-negative integer.")
        if not isinstance(rule.get("evidence"), list):
            target.errors.append(f"{label}.failed[{index}].evidence must be a list.")
        if not isinstance(rule.get("evidence_refs"), list):
            target.errors.append(f"{label}.failed[{index}].evidence_refs must be a list.")
    if scorecard is None:
        return
    score_rules = [rule for rule in scorecard.get("rules", []) if isinstance(rule, dict)]
    failed_score_rules = [rule for rule in score_rules if rule.get("passed") is False]
    if rules.get("total_count") != len(score_rules):
        target.errors.append(f"{label}.total_count must match scorecard.rules length.")
    if rules.get("failed_count") != len(failed_score_rules):
        target.errors.append(f"{label}.failed_count must match failed scorecard rules.")
    critical_failed = sum(1 for rule in failed_score_rules if rule.get("critical") is True)
    if rules.get("critical_failed_count") != critical_failed:
        target.errors.append(f"{label}.critical_failed_count must match failed critical scorecard rules.")
    expected_failed_ids = [str(rule.get("id") or "unknown") for rule in failed_score_rules]
    actual_failed_ids = [str(rule.get("id") or "unknown") for rule in failed if isinstance(rule, dict)]
    if actual_failed_ids != expected_failed_ids:
        target.errors.append(f"{label}.failed ids must match scorecard failed rule order.")


def _validate_run_digest_evidence(
    evidence: dict[str, Any],
    target: ValidationTarget,
    label: str,
    scorecard: dict[str, Any] | None,
    task_completion: dict[str, Any] | None,
) -> None:
    for field_name in (
        "rule_evidence_ref_count",
        "failed_rule_evidence_ref_count",
        "critical_failed_rule_evidence_ref_count",
        "task_completion_evidence_ref_count",
        "missing_evidence_ref_count",
        "total_evidence_ref_count",
    ):
        if not _is_non_negative_int(evidence.get(field_name)):
            target.errors.append(f"{label}.{field_name} must be a non-negative integer.")
    if scorecard is None:
        return
    expected = _run_digest_evidence_counts(scorecard, task_completion)
    for field_name, expected_value in expected.items():
        if evidence.get(field_name) != expected_value:
            target.errors.append(f"{label}.{field_name} expected {expected_value}, got {evidence.get(field_name)!r}.")


def _validate_run_digest_training(
    training: dict[str, Any],
    target: ValidationTarget,
    label: str,
    outcome: dict[str, Any],
    state_changes: dict[str, Any],
    rules: dict[str, Any],
) -> None:
    reward = training.get("score_reward")
    if not isinstance(reward, (int, float)) or isinstance(reward, bool) or not 0 <= float(reward) <= 1:
        target.errors.append(f"{label}.score_reward must be numeric from 0 to 1.")
    if training.get("binary_reward") not in {0, 1}:
        target.errors.append(f"{label}.binary_reward must be 0 or 1.")
    if training.get("task_completion_reward") not in {0, 1}:
        target.errors.append(f"{label}.task_completion_reward must be 0 or 1.")
    if training.get("task_completion_status") != outcome.get("task_completion_status"):
        target.errors.append(f"{label}.task_completion_status must match outcome.task_completion_status.")
    if training.get("task_completion_passed") != outcome.get("task_completion_passed"):
        target.errors.append(f"{label}.task_completion_passed must match outcome.task_completion_passed.")
    if training.get("state_changed") != state_changes.get("changed"):
        target.errors.append(f"{label}.state_changed must match state_changes.changed.")
    if training.get("state_change_count") != state_changes.get("change_count"):
        target.errors.append(f"{label}.state_change_count must match state_changes.change_count.")
    expected_binary = 1 if outcome.get("passed") is True else 0
    if training.get("binary_reward") != expected_binary:
        target.errors.append(f"{label}.binary_reward must match outcome.passed.")
    expected_task_reward = 1 if outcome.get("task_completion_passed") is True else 0
    if training.get("task_completion_reward") != expected_task_reward:
        target.errors.append(f"{label}.task_completion_reward must match outcome.task_completion_passed.")
    failure_modes = training.get("failure_modes")
    if not isinstance(failure_modes, list):
        target.errors.append(f"{label}.failure_modes must be a list.")
    elif _is_non_negative_int(rules.get("failed_count")) and len(failure_modes) != rules.get("failed_count"):
        target.errors.append(f"{label}.failure_modes length must match rules.failed_count.")


def _validate_snapshot_file_record(
    record: Any,
    target: ValidationTarget,
    label: str,
    source_path: Path | None,
) -> None:
    if not isinstance(record, dict):
        target.errors.append(f"{label} must be an object.")
        return
    path_label = record.get("path")
    if not isinstance(path_label, str) or not path_label:
        target.errors.append(f"{label}.path must be a non-empty string.")
    exists = record.get("exists")
    if not isinstance(exists, bool):
        target.errors.append(f"{label}.exists must be a boolean.")
    kind = record.get("kind")
    if kind not in {"missing", "file", "directory", "other"}:
        target.errors.append(f"{label}.kind must be missing, file, directory, or other.")
    if exists is False and kind != "missing":
        target.errors.append(f"{label}.kind must be missing when exists is false.")
    if exists is True and kind == "missing":
        target.errors.append(f"{label}.kind must not be missing when exists is true.")
    if kind == "file":
        if not _is_non_negative_int(record.get("size_bytes")):
            target.errors.append(f"{label}.size_bytes must be a non-negative integer for files.")
        if not _is_sha256(record.get("sha256")):
            target.errors.append(f"{label}.sha256 must be a 64-character hex digest for files.")
        if "text" in record and not isinstance(record.get("text"), str):
            target.errors.append(f"{label}.text must be a string when present.")
        if "text_truncated" in record and not isinstance(record.get("text_truncated"), bool):
            target.errors.append(f"{label}.text_truncated must be a boolean when present.")
        _validate_snapshot_record_fingerprint(record, target, label, source_path)


def _validate_snapshot_directory_record(record: Any, target: ValidationTarget, label: str) -> None:
    if not isinstance(record, dict):
        target.errors.append(f"{label} must be an object.")
        return
    path_label = record.get("path")
    if not isinstance(path_label, str) or not path_label:
        target.errors.append(f"{label}.path must be a non-empty string.")
    exists = record.get("exists")
    if not isinstance(exists, bool):
        target.errors.append(f"{label}.exists must be a boolean.")
    kind = record.get("kind")
    if kind not in {"missing", "directory", "not_directory"}:
        target.errors.append(f"{label}.kind must be missing, directory, or not_directory.")
    if kind == "directory":
        entry_count = record.get("entry_count")
        if not _is_non_negative_int(entry_count):
            target.errors.append(f"{label}.entry_count must be a non-negative integer.")
            entry_count = None
        if not isinstance(record.get("entries_truncated"), bool):
            target.errors.append(f"{label}.entries_truncated must be a boolean.")
        entries = record.get("entries")
        if not isinstance(entries, list):
            target.errors.append(f"{label}.entries must be a list.")
            entries = []
        if isinstance(entry_count, int) and len(entries) > entry_count:
            target.errors.append(f"{label}.entries length must not exceed entry_count.")
        for index, entry in enumerate(entries):
            _validate_snapshot_directory_entry(entry, target, f"{label}.entries[{index}]")


def _validate_snapshot_directory_entry(entry: Any, target: ValidationTarget, label: str) -> None:
    if not isinstance(entry, dict):
        target.errors.append(f"{label} must be an object.")
        return
    if not isinstance(entry.get("name"), str) or not entry.get("name"):
        target.errors.append(f"{label}.name must be a non-empty string.")
    kind = entry.get("kind")
    if kind not in {"file", "directory", "other", "missing"}:
        target.errors.append(f"{label}.kind must be file, directory, other, or missing.")
    if kind == "file":
        if not _is_non_negative_int(entry.get("size_bytes")):
            target.errors.append(f"{label}.size_bytes must be a non-negative integer for files.")
        if not _is_sha256(entry.get("sha256")):
            target.errors.append(f"{label}.sha256 must be a 64-character hex digest for files.")


def _validate_snapshot_record_fingerprint(
    record: dict[str, Any],
    target: ValidationTarget,
    label: str,
    source_path: Path | None,
) -> None:
    path_label = record.get("path")
    if not isinstance(path_label, str) or path_label.startswith("<redacted:"):
        return
    path = Path(path_label)
    if not path.is_absolute():
        candidates = [path.resolve()]
        if source_path is not None:
            candidates.append((source_path.parent / path).resolve())
        path = next((candidate for candidate in candidates if candidate.exists()), candidates[0])
    if not path.exists() or not path.is_file():
        return
    expected_size = record.get("size_bytes")
    if _is_non_negative_int(expected_size) and path.stat().st_size != expected_size:
        target.errors.append(f"{label}.size_bytes does not match current file size.")
    expected = record.get("sha256")
    if _is_sha256(expected):
        actual = _sha256(path)
        if actual != expected:
            target.errors.append(f"{label}.sha256 does not match current file contents.")


def _validate_trace(trace: dict[str, Any], target: ValidationTarget) -> None:
    _require_equal(trace, "schema_version", TRACE_SCHEMA_VERSION, target)
    session = trace.get("session")
    if not isinstance(session, dict):
        target.errors.append("trace.session must be an object.")
    else:
        for field_name in ("id", "source_format", "model"):
            if not isinstance(session.get(field_name), str) or not session.get(field_name):
                target.errors.append(f"trace.session.{field_name} must be a non-empty string.")
    events = trace.get("events")
    if not isinstance(events, list):
        target.errors.append("trace.events must be a list.")
        events = []
    for index, event in enumerate(events):
        if not isinstance(event, dict):
            target.errors.append(f"trace.events[{index}] must be an object.")
            continue
        if not isinstance(event.get("type"), str) or not event.get("type"):
            target.errors.append(f"trace.events[{index}].type must be a non-empty string.")
        if "session_id" in event and event.get("session_id") is not None and not isinstance(event.get("session_id"), str):
            target.errors.append(f"trace.events[{index}].session_id must be a string or null.")
        if "args" in event and not isinstance(event.get("args"), dict):
            target.errors.append(f"trace.events[{index}].args must be an object when present.")
    if not isinstance(trace.get("final_answer", ""), str):
        target.errors.append("trace.final_answer must be a string.")


def _validate_scorecard(scorecard: dict[str, Any], target: ValidationTarget) -> None:
    _require_equal(scorecard, "schema_version", SCORE_SCHEMA_VERSION, target)
    for field_name in ("scenario_id", "scenario_title", "summary"):
        if not isinstance(scorecard.get(field_name), str) or not scorecard.get(field_name):
            target.errors.append(f"scorecard.{field_name} must be a non-empty string.")
    score = scorecard.get("score")
    threshold = scorecard.get("pass_threshold")
    if not _is_int_between(score, 0, 100):
        target.errors.append("scorecard.score must be an integer from 0 to 100.")
    if not _is_int_between(threshold, 0, 100):
        target.errors.append("scorecard.pass_threshold must be an integer from 0 to 100.")
    if not isinstance(scorecard.get("passed"), bool):
        target.errors.append("scorecard.passed must be a boolean.")
    critical_failures = scorecard.get("critical_failures")
    if not _is_string_list(critical_failures):
        target.errors.append("scorecard.critical_failures must be a list of strings.")
        critical_failures = []
    rules = scorecard.get("rules")
    if not isinstance(rules, list):
        target.errors.append("scorecard.rules must be a list.")
        rules = []

    failed_critical: list[str] = []
    for index, rule in enumerate(rules):
        if not isinstance(rule, dict):
            target.errors.append(f"scorecard.rules[{index}] must be an object.")
            continue
        rule_id = rule.get("id")
        if not isinstance(rule_id, str) or not rule_id:
            target.errors.append(f"scorecard.rules[{index}].id must be a non-empty string.")
            rule_id = f"rule[{index}]"
        if not isinstance(rule.get("name"), str) or not rule.get("name"):
            target.errors.append(f"scorecard.rules[{index}].name must be a non-empty string.")
        if not isinstance(rule.get("passed"), bool):
            target.errors.append(f"scorecard.rules[{index}].passed must be a boolean.")
        if not isinstance(rule.get("critical"), bool):
            target.errors.append(f"scorecard.rules[{index}].critical must be a boolean.")
        if not _is_int_between(rule.get("penalty"), 0, 100):
            target.errors.append(f"scorecard.rules[{index}].penalty must be an integer from 0 to 100.")
        if not isinstance(rule.get("evidence"), list):
            target.errors.append(f"scorecard.rules[{index}].evidence must be a list.")
        if "evidence_refs" in rule:
            _validate_evidence_refs(rule.get("evidence_refs"), target, f"scorecard.rules[{index}].evidence_refs")
        if rule.get("critical") is True and rule.get("passed") is False:
            failed_critical.append(str(rule_id))

    if isinstance(critical_failures, list) and sorted(critical_failures) != sorted(failed_critical):
        target.errors.append(
            "scorecard.critical_failures must match failed critical rules: "
            f"expected {sorted(failed_critical)!r}, got {sorted(critical_failures)!r}."
        )
    if _is_int_between(score, 0, 100) and _is_int_between(threshold, 0, 100) and isinstance(scorecard.get("passed"), bool):
        expected_passed = int(score) >= int(threshold) and not failed_critical
        if scorecard["passed"] != expected_passed:
            target.errors.append(
                f"scorecard.passed inconsistent with score/threshold/critical failures: expected {expected_passed!r}."
            )
    if "task_completion" in scorecard:
        _validate_task_completion(scorecard.get("task_completion"), target, "scorecard.task_completion")
    else:
        target.warnings.append("scorecard.task_completion is missing; rerun scoring to emit task-completion evidence.")


def _validate_task_completion(value: Any, target: ValidationTarget, label: str) -> None:
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return
    _require_equal(value, "schema_version", TASK_COMPLETION_SCHEMA_VERSION, target, prefix=f"{label}.")
    status = value.get("status")
    if status not in {"complete", "incomplete", "not_applicable"}:
        target.errors.append(f"{label}.status must be complete, incomplete, or not_applicable.")
    passed = value.get("passed")
    if not isinstance(passed, bool):
        target.errors.append(f"{label}.passed must be a boolean.")
    elif status == "complete" and passed is not True:
        target.errors.append(f"{label}.passed must be true when status is complete.")
    elif status == "incomplete" and passed is not False:
        target.errors.append(f"{label}.passed must be false when status is incomplete.")
    elif status == "not_applicable" and passed is not True:
        target.errors.append(f"{label}.passed must be true when status is not_applicable.")
    configured = value.get("task_evidence_configured")
    if not isinstance(configured, bool):
        target.errors.append(f"{label}.task_evidence_configured must be a boolean.")
    elif configured is False and status != "not_applicable":
        target.errors.append(f"{label}.status must be not_applicable when no task evidence is configured.")
    elif configured is True and status == "not_applicable":
        target.errors.append(f"{label}.status must not be not_applicable when task evidence is configured.")
    counts: dict[str, int] = {}
    for field_name in ("required_check_count", "passed_check_count", "failed_check_count"):
        raw_count = value.get(field_name)
        if not _is_non_negative_int(raw_count):
            target.errors.append(f"{label}.{field_name} must be a non-negative integer.")
            continue
        counts[field_name] = int(raw_count)
    if len(counts) == 3:
        if counts["passed_check_count"] + counts["failed_check_count"] != counts["required_check_count"]:
            target.errors.append(f"{label}.passed_check_count + failed_check_count must equal required_check_count.")
        if counts["failed_check_count"] == 0 and status == "incomplete":
            target.errors.append(f"{label}.status must not be incomplete when failed_check_count is 0.")
        if counts["failed_check_count"] > 0 and status == "complete":
            target.errors.append(f"{label}.status must not be complete when failed_check_count is greater than 0.")
    if not _is_string_list(value.get("blocking_rule_ids")):
        target.errors.append(f"{label}.blocking_rule_ids must be a list of strings.")
    if not isinstance(value.get("summary"), str) or not value.get("summary"):
        target.errors.append(f"{label}.summary must be a non-empty string.")
    checks = value.get("checks")
    if not isinstance(checks, list):
        target.errors.append(f"{label}.checks must be a list.")
        checks = []
    if "required_check_count" in counts and len(checks) != counts["required_check_count"]:
        target.errors.append(f"{label}.checks length must match required_check_count.")
    observed_failed = 0
    for index, check in enumerate(checks):
        if not isinstance(check, dict):
            target.errors.append(f"{label}.checks[{index}] must be an object.")
            continue
        for field_name in ("id", "rule_id", "description", "evidence"):
            if not isinstance(check.get(field_name), str) or not check.get(field_name):
                target.errors.append(f"{label}.checks[{index}].{field_name} must be a non-empty string.")
        if not isinstance(check.get("passed"), bool):
            target.errors.append(f"{label}.checks[{index}].passed must be a boolean.")
        elif check.get("passed") is False:
            observed_failed += 1
        if "event_indices" in check and not all(isinstance(item, int) and not isinstance(item, bool) and item >= 0 for item in check.get("event_indices", [])):
            target.errors.append(f"{label}.checks[{index}].event_indices must be a list of non-negative integers.")
        _validate_evidence_refs(check.get("evidence_refs"), target, f"{label}.checks[{index}].evidence_refs")
    if "failed_check_count" in counts and observed_failed != counts["failed_check_count"]:
        target.errors.append(f"{label}.failed_check_count must match failed checks.")
    _validate_evidence_refs(value.get("evidence_refs"), target, f"{label}.evidence_refs")
    _validate_evidence_refs(value.get("missing_evidence_refs"), target, f"{label}.missing_evidence_refs")


def _validate_lineage(
    lineage: dict[str, Any],
    target: ValidationTarget,
    run_dir: Path,
    trace: dict[str, Any] | None,
    scorecard: dict[str, Any] | None,
) -> None:
    _require_equal(lineage, "schema_version", LINEAGE_SCHEMA_VERSION, target, prefix="artifact_lineage.")
    scenario = lineage.get("scenario")
    if not isinstance(scenario, dict):
        target.errors.append("artifact_lineage.scenario must be an object.")
        scenario = {}
    if scorecard is not None and scenario.get("id") != scorecard.get("scenario_id"):
        target.errors.append("artifact_lineage.scenario.id must match scorecard.scenario_id.")
    lineage_trace = lineage.get("trace")
    if not isinstance(lineage_trace, dict):
        target.errors.append("artifact_lineage.trace must be an object.")
        lineage_trace = {}
    events = trace.get("events", []) if isinstance(trace, dict) and isinstance(trace.get("events"), list) else []
    if trace is not None and lineage_trace.get("event_count") != len(events):
        target.errors.append("artifact_lineage.trace.event_count must match normalized_trace.events.")
    lineage_scorecard = lineage.get("scorecard")
    if not isinstance(lineage_scorecard, dict):
        target.errors.append("artifact_lineage.scorecard must be an object.")
        lineage_scorecard = {}
    if scorecard is not None:
        for field_name in ("score", "passed", "critical_failures"):
            if lineage_scorecard.get(field_name) != scorecard.get(field_name):
                target.errors.append(f"artifact_lineage.scorecard.{field_name} must match scorecard.{field_name}.")
    inputs = _lineage_records(lineage.get("inputs"), target, "artifact_lineage.inputs")
    for name, record in inputs.items():
        _validate_lineage_input_record(name, record, target, f"artifact_lineage.inputs.{name}")
    outputs = _lineage_records(lineage.get("outputs"), target, "artifact_lineage.outputs")
    for output_name in ("normalized_trace", "scorecard", "task_completion", "report"):
        if output_name not in outputs:
            target.errors.append(f"artifact_lineage.outputs missing {output_name!r}.")
            continue
        _validate_lineage_file_record(outputs[output_name], run_dir, target, f"artifact_lineage.outputs.{output_name}")
    if "run_digest" in outputs:
        _validate_lineage_file_record(outputs["run_digest"], run_dir, target, "artifact_lineage.outputs.run_digest")
    else:
        target.warnings.append("artifact_lineage.outputs missing 'run_digest'; rerun the run to fingerprint the evidence digest.")
    if "before_state_snapshot" in outputs:
        _validate_lineage_file_record(outputs["before_state_snapshot"], run_dir, target, "artifact_lineage.outputs.before_state_snapshot")
    if "state_snapshot" in outputs:
        _validate_lineage_file_record(outputs["state_snapshot"], run_dir, target, "artifact_lineage.outputs.state_snapshot")
    if "state_diff" in outputs:
        _validate_lineage_file_record(outputs["state_diff"], run_dir, target, "artifact_lineage.outputs.state_diff")
    evidence_links = lineage.get("evidence_links")
    if not isinstance(evidence_links, list):
        target.errors.append("artifact_lineage.evidence_links must be a list.")
        evidence_links = []
    expected_ref_count = _scorecard_evidence_ref_count(scorecard)
    if scorecard is not None and len(evidence_links) != expected_ref_count:
        target.errors.append(
            f"artifact_lineage.evidence_links expected {expected_ref_count}, got {len(evidence_links)}."
        )
    for index, link in enumerate(evidence_links):
        _validate_lineage_evidence_link(link, index, len(events), target)
    graph = lineage.get("graph")
    if not isinstance(graph, list):
        target.errors.append("artifact_lineage.graph must be a list.")
    replay = lineage.get("replay")
    if isinstance(replay, dict):
        _validate_lineage_replay(replay, inputs, target)
    else:
        target.warnings.append("artifact_lineage.replay is missing; rerun the run to emit replay instructions.")
    summary = lineage.get("summary")
    if not isinstance(summary, dict):
        target.errors.append("artifact_lineage.summary must be an object.")
    else:
        inputs_raw = lineage.get("inputs")
        expected_input_count = len(inputs_raw) if isinstance(inputs_raw, list) else None
        if summary.get("input_count") != expected_input_count:
            target.errors.append("artifact_lineage.summary.input_count must match inputs length.")
        outputs_raw = lineage.get("outputs")
        expected_output_count = len(outputs_raw) if isinstance(outputs_raw, list) else None
        if summary.get("output_count") != expected_output_count:
            target.errors.append("artifact_lineage.summary.output_count must match outputs length.")
        if summary.get("evidence_link_count") != len(evidence_links):
            target.errors.append("artifact_lineage.summary.evidence_link_count must match evidence_links length.")
        if isinstance(replay, dict) and summary.get("self_contained_replay") != replay.get("self_contained"):
            target.errors.append("artifact_lineage.summary.self_contained_replay must match replay.self_contained.")


def _validate_training_manifest(
    manifest: dict[str, Any],
    target: ValidationTarget,
    episodes: list[dict[str, Any]],
    rewards: list[dict[str, Any]],
    step_rewards: list[dict[str, Any]],
    preferences: list[dict[str, Any]],
    failure_modes: list[dict[str, Any]],
    curriculum: dict[str, Any] | None,
    sft: list[dict[str, Any]],
    dpo: list[dict[str, Any]],
    reward_model: list[dict[str, Any]],
    dataset_metrics: dict[str, Any] | None,
    dataset_splits: dict[str, Any] | None,
    dataset_registry: dict[str, Any] | None,
    expected_redaction_status: dict[str, Any],
    expected_label_provenance: dict[str, Any],
    has_dataset_card: bool,
    export_dir: Path,
) -> None:
    _require_equal(manifest, "schema_version", RL_MANIFEST_SCHEMA_VERSION, target)
    dataset_version = manifest.get("dataset_version")
    versioned_manifest = _is_dataset_version(dataset_version)
    if not versioned_manifest:
        target.warnings.append("manifest.dataset_version is missing; rerun export-rl to emit a selectable dataset version.")
    expected_counts = {
        "episode_count": len(episodes),
        "reward_count": len(rewards),
        "preference_count": len(preferences),
        "failure_mode_count": len(failure_modes),
    }
    if "step_reward_count" in manifest:
        expected_counts["step_reward_count"] = len(step_rewards)
    else:
        target.warnings.append("manifest.step_reward_count is missing; rerun export-rl to refresh training artifacts.")
    trainer_view_counts = {
        "sft_count": len(sft),
        "dpo_count": len(dpo),
        "reward_model_count": len(reward_model),
    }
    for field_name, expected in trainer_view_counts.items():
        if field_name in manifest:
            expected_counts[field_name] = expected
        else:
            target.warnings.append(f"manifest.{field_name} is missing; rerun export-rl to refresh trainer-ready views.")
    if "quality_flag_count" in manifest and dataset_metrics is not None:
        expected_counts["quality_flag_count"] = len(dataset_metrics.get("quality_flags", [])) if isinstance(dataset_metrics.get("quality_flags"), list) else 0
    elif "quality_flag_count" not in manifest:
        target.warnings.append("manifest.quality_flag_count is missing; rerun export-rl to refresh dataset-level metrics.")
    for field_name, expected in expected_counts.items():
        if manifest.get(field_name) != expected:
            target.errors.append(f"manifest.{field_name} expected {expected}, got {manifest.get(field_name)!r}.")
    if not isinstance(manifest.get("outputs"), dict):
        target.errors.append("manifest.outputs must be an object.")
    else:
        for output_name in ("episodes", "rewards", "preferences", "failure_modes", "curriculum", "manifest"):
            if output_name not in manifest["outputs"]:
                target.errors.append(f"manifest.outputs.{output_name} is missing.")
        if "step_rewards" not in manifest["outputs"]:
            target.warnings.append("manifest.outputs.step_rewards is missing; rerun export-rl to refresh training artifacts.")
        for output_name in ("sft", "dpo", "reward_model"):
            if output_name not in manifest["outputs"]:
                target.warnings.append(f"manifest.outputs.{output_name} is missing; rerun export-rl to refresh trainer-ready views.")
        if "dataset_metrics" not in manifest["outputs"]:
            target.warnings.append("manifest.outputs.dataset_metrics is missing; rerun export-rl to refresh dataset-level metrics.")
        if "dataset_splits" not in manifest["outputs"]:
            target.warnings.append("manifest.outputs.dataset_splits is missing; rerun export-rl to refresh deterministic split artifacts.")
        if "dataset_card" not in manifest["outputs"]:
            target.warnings.append("manifest.outputs.dataset_card is missing; rerun export-rl to refresh the dataset card.")
        if "dataset_registry" not in manifest["outputs"]:
            if versioned_manifest:
                target.errors.append("manifest.outputs.dataset_registry is missing.")
            else:
                target.warnings.append("manifest.outputs.dataset_registry is missing; rerun export-rl to emit dataset lineage.")
        for split_name in DATASET_SPLIT_NAMES:
            for artifact_name in DATASET_SPLIT_ARTIFACTS:
                output_name = f"{split_name}_{artifact_name}"
                if output_name not in manifest["outputs"]:
                    target.warnings.append(f"manifest.outputs.{output_name} is missing; rerun export-rl to refresh split artifacts.")
    _validate_manifest_artifact_fingerprints(
        manifest.get("artifact_fingerprints"),
        target,
        "manifest.artifact_fingerprints",
        _training_export_artifact_paths(export_dir),
    )
    if dataset_metrics is None:
        target.warnings.append("manifest has no validated dataset_metrics.json companion.")
    if dataset_splits is None:
        target.warnings.append("manifest has no validated dataset_splits.json companion.")
    elif manifest.get("dataset_splits") != dataset_splits.get("summary"):
        target.errors.append("manifest.dataset_splits must match dataset_splits.summary.")
    if dataset_registry is None:
        if versioned_manifest:
            target.errors.append("manifest has no validated dataset_registry.json companion.")
        else:
            target.warnings.append("manifest has no dataset_registry.json companion; rerun export-rl to emit dataset lineage.")
    if "redaction_status" in manifest:
        if manifest.get("redaction_status") != expected_redaction_status:
            target.errors.append("manifest.redaction_status must match recomputed redaction scan.")
    else:
        target.warnings.append("manifest.redaction_status is missing; rerun export-rl to emit redaction proof.")
    if "label_provenance" in manifest:
        if manifest.get("label_provenance") != expected_label_provenance:
            target.errors.append("manifest.label_provenance must match recomputed label provenance.")
    else:
        target.warnings.append("manifest.label_provenance is missing; rerun export-rl to emit label provenance.")
    registry = manifest.get("registry")
    if not isinstance(registry, dict):
        if versioned_manifest:
            target.errors.append("manifest.registry must be an object.")
        else:
            target.warnings.append("manifest.registry is missing; rerun export-rl to emit dataset lineage.")
    else:
        _require_equal(registry, "schema_version", RL_DATASET_REGISTRY_SCHEMA_VERSION, target, prefix="manifest.registry.")
        if registry.get("selection_key") != dataset_version:
            target.errors.append("manifest.registry.selection_key must match manifest.dataset_version.")
        if registry.get("redaction_passed") is not (expected_redaction_status.get("passed") is True):
            target.errors.append("manifest.registry.redaction_passed must match redaction_status.passed.")
        leakage = dataset_splits.get("leakage_checks") if isinstance(dataset_splits, dict) else {}
        if registry.get("heldout_scenario_exclusive") is not (isinstance(leakage, dict) and leakage.get("heldout_scenario_exclusive") is True):
            target.errors.append("manifest.registry.heldout_scenario_exclusive must match dataset_splits.leakage_checks.")
    if not has_dataset_card:
        target.warnings.append("manifest has no DATASET_CARD.md companion.")
    if "metadata" in manifest:
        _validate_metadata(manifest.get("metadata"), target, "manifest.metadata")
    if dataset_metrics is not None and "metadata" in manifest and "metadata" in dataset_metrics and manifest.get("metadata") != dataset_metrics.get("metadata"):
        target.errors.append("manifest.metadata does not match dataset_metrics.metadata.")
    if curriculum is not None and curriculum.get("failure_mode_count") != len(failure_modes):
        target.errors.append(
            f"curriculum.failure_mode_count expected {len(failure_modes)}, got {curriculum.get('failure_mode_count')!r}."
        )
    if _looks_absolute(str(manifest.get("source_runs_dir", ""))):
        target.warnings.append("manifest.source_runs_dir is absolute; prefer redacted or relative exports for sharing.")
    if _looks_absolute(str(manifest.get("output_dir", ""))):
        target.warnings.append("manifest.output_dir is absolute; prefer redacted or relative exports for sharing.")


def _validate_compare_manifest(
    manifest: dict[str, Any],
    target: ValidationTarget,
    pairs: list[dict[str, Any]],
    dpo: list[dict[str, Any]],
    has_card: bool,
    export_dir: Path,
) -> None:
    _require_equal(manifest, "schema_version", COMPARE_RL_MANIFEST_SCHEMA_VERSION, target)
    expected_counts = {
        "pair_count": len(pairs),
        "dpo_count": len(dpo),
        "candidate_win_count": sum(1 for pair in pairs if pair.get("chosen_side") == "candidate"),
        "baseline_win_count": sum(1 for pair in pairs if pair.get("chosen_side") == "baseline"),
    }
    for field_name, expected in expected_counts.items():
        if manifest.get(field_name) != expected:
            target.errors.append(f"compare_manifest.{field_name} expected {expected}, got {manifest.get(field_name)!r}.")
    expected_movement = compare_movement_summary(pairs)
    for field_name, expected in expected_movement.items():
        if field_name not in manifest:
            target.errors.append(f"compare_manifest.{field_name} is missing.")
        elif manifest.get(field_name) != expected:
            target.errors.append(f"compare_manifest.{field_name} expected {expected!r}, got {manifest.get(field_name)!r}.")
    for field_name in ("baseline_run_count", "candidate_run_count", "paired_scenario_count", "skipped_pair_count", "min_score_gap"):
        if not _is_non_negative_int(manifest.get(field_name)):
            target.errors.append(f"compare_manifest.{field_name} must be a non-negative integer.")
    expected_contract_drift_count = sum(1 for pair in pairs if pair.get("contract_fingerprint_status") == "drifted")
    expected_unverified_contract_count = sum(1 for pair in pairs if pair.get("contract_fingerprint_status") == "unverified")
    if manifest.get("contract_drift_count") != expected_contract_drift_count:
        target.errors.append(
            f"compare_manifest.contract_drift_count expected {expected_contract_drift_count}, got {manifest.get('contract_drift_count')!r}."
        )
    if manifest.get("unverified_contract_count") != expected_unverified_contract_count:
        target.errors.append(
            "compare_manifest.unverified_contract_count "
            f"expected {expected_unverified_contract_count}, got {manifest.get('unverified_contract_count')!r}."
        )
    if not isinstance(manifest.get("outputs"), dict):
        target.errors.append("compare_manifest.outputs must be an object.")
    else:
        for output_name in ("improvement_pairs", "improvement_dpo", "manifest", "improvement_card"):
            if output_name not in manifest["outputs"]:
                target.errors.append(f"compare_manifest.outputs.{output_name} is missing.")
    _validate_manifest_artifact_fingerprints(
        manifest.get("artifact_fingerprints"),
        target,
        "compare_manifest.artifact_fingerprints",
        _compare_export_artifact_paths(export_dir),
    )
    for field_name in ("missing_in_candidate", "new_in_candidate"):
        if not _is_string_list(manifest.get(field_name)):
            target.errors.append(f"compare_manifest.{field_name} must be a list of strings.")
    skipped = manifest.get("skipped_pairs")
    if not isinstance(skipped, list):
        target.errors.append("compare_manifest.skipped_pairs must be a list.")
    if "metadata" in manifest:
        _validate_metadata(manifest.get("metadata"), target, "compare_manifest.metadata")
    if not has_card:
        target.warnings.append("compare_manifest has no IMPROVEMENT_CARD.md companion.")
    if "contract_scope" in manifest and manifest.get("contract_scope") not in CONTRACT_SCOPES:
        target.errors.append(f"compare_manifest.contract_scope must be one of {sorted(CONTRACT_SCOPES)!r}.")
    if manifest.get("contract_scope") in CONTRACT_SCOPES:
        for index, pair in enumerate(pairs):
            if isinstance(pair, dict) and pair.get("contract_fingerprint_scope") not in {None, manifest.get("contract_scope")}:
                target.errors.append(
                    f"improvement_pairs[{index}].contract_fingerprint_scope must match compare_manifest.contract_scope."
                )
    for field_name in ("baseline_runs_dir", "candidate_runs_dir", "output_dir"):
        if _looks_absolute(str(manifest.get(field_name, ""))):
            target.warnings.append(f"compare_manifest.{field_name} is absolute; prefer redacted or relative exports for sharing.")


def _validate_manifest_artifact_fingerprints(
    value: Any,
    target: ValidationTarget,
    label: str,
    expected_paths: dict[str, Path],
) -> None:
    if value is None:
        target.errors.append(f"{label} is missing; rerun the export to emit artifact integrity hashes.")
        return
    if not isinstance(value, dict):
        target.errors.append(f"{label} must be an object.")
        return

    expected_names = set(expected_paths)
    actual_names = {name for name in value if isinstance(name, str)}
    for name in sorted(actual_names - expected_names):
        target.errors.append(f"{label}.{name} is not a known export artifact.")
    for name in value:
        if not isinstance(name, str) or not name:
            target.errors.append(f"{label} keys must be non-empty strings.")

    for name, path in expected_paths.items():
        record = value.get(name)
        record_label = f"{label}.{name}"
        if not isinstance(record, dict):
            target.errors.append(f"{record_label} must be an object.")
            continue
        if not isinstance(record.get("path"), str) or not record.get("path"):
            target.errors.append(f"{record_label}.path must be a non-empty string.")
        elif _looks_absolute(record["path"]):
            target.warnings.append(f"{record_label}.path is absolute; prefer redacted or relative exports for sharing.")
        if record.get("exists") is not True:
            target.errors.append(f"{record_label}.exists must be true for generated export artifacts.")
        if path.is_symlink():
            target.errors.append(f"{record_label} file must not be a symlink: {path}")
            continue
        if not _path_resolves_inside(path, path.parent):
            target.errors.append(f"{record_label} file must resolve inside the export directory: {path}")
            continue
        if not path.exists() or not path.is_file():
            target.errors.append(f"{record_label} file is missing: {path}")
            continue
        size_bytes = record.get("size_bytes")
        if not _is_non_negative_int(size_bytes):
            target.errors.append(f"{record_label}.size_bytes must be a non-negative integer.")
        elif size_bytes != path.stat().st_size:
            target.errors.append(f"{record_label}.size_bytes does not match current file size.")
        expected_sha = record.get("sha256")
        if not _is_sha256(expected_sha):
            target.errors.append(f"{record_label}.sha256 must be a SHA-256 hex string.")
        elif _sha256(path) != expected_sha:
            target.errors.append(f"{record_label}.sha256 does not match current file contents.")


def _training_export_artifact_paths(export_dir: Path) -> dict[str, Path]:
    paths = {
        "curriculum": export_dir / "curriculum.json",
        "dataset_card": export_dir / "DATASET_CARD.md",
        "dataset_metrics": export_dir / "dataset_metrics.json",
        "dataset_splits": export_dir / "dataset_splits.json",
        "dpo": export_dir / "dpo.jsonl",
        "episodes": export_dir / "episodes.jsonl",
        "failure_modes": export_dir / "failure_modes.jsonl",
        "preferences": export_dir / "preferences.jsonl",
        "reward_model": export_dir / "reward_model.jsonl",
        "rewards": export_dir / "rewards.jsonl",
        "sft": export_dir / "sft.jsonl",
        "step_rewards": export_dir / "step_rewards.jsonl",
    }
    for split_name in DATASET_SPLIT_NAMES:
        for artifact_name in DATASET_SPLIT_ARTIFACTS:
            paths[f"{split_name}_{artifact_name}"] = export_dir / "splits" / split_name / f"{artifact_name}.jsonl"
    return paths


def _read_training_split_rows(export_dir: Path, target: ValidationTarget) -> dict[str, dict[str, list[dict[str, Any]]]]:
    split_rows: dict[str, dict[str, list[dict[str, Any]]]] = {}
    for split_name in DATASET_SPLIT_NAMES:
        split_rows[split_name] = {}
        for artifact_name in DATASET_SPLIT_ARTIFACTS:
            label = f"splits/{split_name}/{artifact_name}.jsonl"
            split_rows[split_name][artifact_name] = _read_jsonl_objects_optional(
                export_dir / "splits" / split_name / f"{artifact_name}.jsonl",
                target,
                label,
                "rerun export-rl to emit deterministic train/validation/test split artifacts",
            )
    return split_rows


def _validate_dataset_splits(
    value: dict[str, Any],
    target: ValidationTarget,
    rows_by_artifact: dict[str, list[dict[str, Any]]],
    split_rows: dict[str, dict[str, list[dict[str, Any]]]],
) -> None:
    _require_equal(value, "schema_version", RL_DATASET_SPLITS_SCHEMA_VERSION, target, prefix="dataset_splits.")
    if value.get("strategy") != "task_family_hash":
        target.errors.append("dataset_splits.strategy must be 'task_family_hash'.")
    if value.get("split_names") != list(DATASET_SPLIT_NAMES):
        target.errors.append(f"dataset_splits.split_names must be {list(DATASET_SPLIT_NAMES)!r}.")
    if value.get("artifact_names") != list(DATASET_SPLIT_ARTIFACTS):
        target.errors.append(f"dataset_splits.artifact_names must be {list(DATASET_SPLIT_ARTIFACTS)!r}.")

    episodes = rows_by_artifact.get("episodes", [])
    episode_by_id = {str(episode.get("episode_id")): episode for episode in episodes if isinstance(episode.get("episode_id"), str)}
    family_episode_ids: dict[str, list[str]] = {}
    family_scenario_ids: dict[str, set[str]] = {}
    for episode in episodes:
        family = str(episode.get("task_family") or "unknown")
        family_episode_ids.setdefault(family, []).append(str(episode.get("episode_id") or ""))
        family_scenario_ids.setdefault(family, set()).add(str(episode.get("scenario_id") or ""))

    assignments = value.get("assignments")
    if not isinstance(assignments, list):
        target.errors.append("dataset_splits.assignments must be a list.")
        assignments = []
    family_to_split: dict[str, str] = {}
    assigned_episode_ids: set[str] = set()
    for index, assignment in enumerate(assignments):
        if not isinstance(assignment, dict):
            target.errors.append(f"dataset_splits.assignments[{index}] must be an object.")
            continue
        family = assignment.get("task_family")
        split_name = assignment.get("split")
        if not isinstance(family, str) or not family:
            target.errors.append(f"dataset_splits.assignments[{index}].task_family must be a non-empty string.")
            continue
        if family in family_to_split:
            target.errors.append(f"dataset_splits.assignments[{index}].task_family duplicates {family!r}.")
        if split_name not in DATASET_SPLIT_NAMES:
            target.errors.append(f"dataset_splits.assignments[{index}].split must be one of {list(DATASET_SPLIT_NAMES)!r}.")
            split_name = "train"
        family_to_split[family] = str(split_name)
        expected_episode_ids = sorted(family_episode_ids.get(family, []))
        expected_scenario_ids = sorted(family_scenario_ids.get(family, set()))
        if assignment.get("episode_count") != len(expected_episode_ids):
            target.errors.append(
                f"dataset_splits.assignments[{index}].episode_count expected {len(expected_episode_ids)}, got {assignment.get('episode_count')!r}."
            )
        if assignment.get("episode_ids") != expected_episode_ids:
            target.errors.append(f"dataset_splits.assignments[{index}].episode_ids must match exported episodes for family {family!r}.")
        if assignment.get("scenario_ids") != expected_scenario_ids:
            target.errors.append(f"dataset_splits.assignments[{index}].scenario_ids must match exported scenarios for family {family!r}.")
        assigned_episode_ids.update(item for item in expected_episode_ids if item)

    expected_families = set(family_episode_ids)
    missing_families = sorted(expected_families - set(family_to_split))
    unknown_families = sorted(set(family_to_split) - expected_families)
    if missing_families:
        target.errors.append(f"dataset_splits.assignments missing task families: {missing_families!r}.")
    if unknown_families:
        target.errors.append(f"dataset_splits.assignments contain unknown task families: {unknown_families!r}.")
    if assigned_episode_ids != set(episode_by_id):
        target.errors.append("dataset_splits.assignments episode_ids must cover exported episodes exactly.")

    placement_errors = _validate_split_row_placement(rows_by_artifact, split_rows, family_to_split, episode_by_id, target)
    cross_split_families = _cross_split_families(split_rows)
    family_exclusive = not cross_split_families and not placement_errors
    split_scenario_ids = _split_scenario_ids(split_rows)
    train_scenario_ids = split_scenario_ids["train"]
    heldout_scenario_ids = sorted(set(split_scenario_ids["validation"]) | set(split_scenario_ids["test"]))
    cross_split_scenario_ids = sorted(set(train_scenario_ids) & set(heldout_scenario_ids))
    heldout_scenario_exclusive = not cross_split_scenario_ids
    train_task_families = _split_task_families(split_rows)["train"]
    heldout_task_families = sorted(set(_split_task_families(split_rows)["validation"]) | set(_split_task_families(split_rows)["test"]))
    if value.get("split_scenario_ids") != split_scenario_ids:
        target.errors.append("dataset_splits.split_scenario_ids must match split episode scenario IDs.")
    _validate_dataset_split_counts(value.get("split_counts"), target, assignments, split_rows)
    _validate_dataset_split_summary(
        value.get("summary"),
        target,
        family_to_split,
        episodes,
        split_rows,
        family_exclusive,
        train_scenario_ids,
        heldout_scenario_ids,
        heldout_scenario_exclusive,
    )
    _validate_dataset_split_leakage(
        value.get("leakage_checks"),
        target,
        family_exclusive,
        cross_split_families,
        train_scenario_ids,
        heldout_scenario_ids,
        cross_split_scenario_ids,
        heldout_scenario_exclusive,
        train_task_families,
        heldout_task_families,
    )


def _split_scenario_ids(split_rows: dict[str, dict[str, list[dict[str, Any]]]]) -> dict[str, list[str]]:
    return {
        split_name: sorted(
            {
                str(episode.get("scenario_id") or "")
                for episode in split_rows[split_name]["episodes"]
                if str(episode.get("scenario_id") or "")
            }
        )
        for split_name in DATASET_SPLIT_NAMES
    }


def _split_task_families(split_rows: dict[str, dict[str, list[dict[str, Any]]]]) -> dict[str, list[str]]:
    return {
        split_name: sorted({str(episode.get("task_family") or "unknown") for episode in split_rows[split_name]["episodes"]})
        for split_name in DATASET_SPLIT_NAMES
    }


def _validate_split_row_placement(
    rows_by_artifact: dict[str, list[dict[str, Any]]],
    split_rows: dict[str, dict[str, list[dict[str, Any]]]],
    family_to_split: dict[str, str],
    episode_by_id: dict[str, dict[str, Any]],
    target: ValidationTarget,
) -> int:
    errors = 0
    episode_family = {
        episode_id: str(episode.get("task_family") or "unknown")
        for episode_id, episode in episode_by_id.items()
    }
    for artifact_name in DATASET_SPLIT_ARTIFACTS:
        expected_total = len(rows_by_artifact.get(artifact_name, []))
        actual_total = sum(len(split_rows[split_name][artifact_name]) for split_name in DATASET_SPLIT_NAMES)
        if actual_total != expected_total:
            target.errors.append(
                f"dataset_splits split rows for {artifact_name} expected {expected_total}, got {actual_total}."
            )
            errors += 1
    for split_name in DATASET_SPLIT_NAMES:
        for artifact_name in DATASET_SPLIT_ARTIFACTS:
            for row_index, row in enumerate(split_rows[split_name][artifact_name]):
                expected_split = _expected_row_split(row, family_to_split, episode_family)
                if expected_split != split_name:
                    target.errors.append(
                        f"splits/{split_name}/{artifact_name}.jsonl row {row_index + 1} belongs in {expected_split!r}."
                    )
                    errors += 1
                if artifact_name in {"preferences", "dpo"}:
                    errors += _validate_pair_row_split_locality(row, artifact_name, row_index, episode_family, family_to_split, target)
    return errors


def _validate_pair_row_split_locality(
    row: dict[str, Any],
    artifact_name: str,
    row_index: int,
    episode_family: dict[str, str],
    family_to_split: dict[str, str],
    target: ValidationTarget,
) -> int:
    chosen_id = row.get("chosen_episode_id")
    rejected_id = row.get("rejected_episode_id")
    if not isinstance(chosen_id, str) or not isinstance(rejected_id, str):
        return 0
    chosen_split = family_to_split.get(episode_family.get(chosen_id, ""))
    rejected_split = family_to_split.get(episode_family.get(rejected_id, ""))
    if chosen_split and rejected_split and chosen_split != rejected_split:
        target.errors.append(
            f"{artifact_name}[{row_index}] crosses dataset splits: chosen={chosen_split!r}, rejected={rejected_split!r}."
        )
        return 1
    return 0


def _expected_row_split(row: dict[str, Any], family_to_split: dict[str, str], episode_family: dict[str, str]) -> str:
    family = row.get("task_family")
    if isinstance(family, str) and family in family_to_split:
        return family_to_split[family]
    episode_id = row.get("episode_id")
    if isinstance(episode_id, str):
        return family_to_split.get(episode_family.get(episode_id, ""), "train")
    for field_name in ("chosen_episode_id", "rejected_episode_id"):
        candidate = row.get(field_name)
        if isinstance(candidate, str):
            split_name = family_to_split.get(episode_family.get(candidate, ""))
            if split_name:
                return split_name
    return "train"


def _cross_split_families(split_rows: dict[str, dict[str, list[dict[str, Any]]]]) -> list[str]:
    family_splits: dict[str, set[str]] = {}
    for split_name in DATASET_SPLIT_NAMES:
        for episode in split_rows[split_name]["episodes"]:
            family_splits.setdefault(str(episode.get("task_family") or "unknown"), set()).add(split_name)
    return sorted(family for family, splits in family_splits.items() if len(splits) > 1)


def _validate_dataset_split_counts(
    value: Any,
    target: ValidationTarget,
    assignments: list[Any],
    split_rows: dict[str, dict[str, list[dict[str, Any]]]],
) -> None:
    if not isinstance(value, dict):
        target.errors.append("dataset_splits.split_counts must be an object.")
        return
    for split_name in DATASET_SPLIT_NAMES:
        split_count = value.get(split_name)
        if not isinstance(split_count, dict):
            target.errors.append(f"dataset_splits.split_counts.{split_name} must be an object.")
            continue
        expected_family_count = sum(
            1 for assignment in assignments if isinstance(assignment, dict) and assignment.get("split") == split_name
        )
        expected_episode_count = len(split_rows[split_name]["episodes"])
        if split_count.get("task_family_count") != expected_family_count:
            target.errors.append(
                f"dataset_splits.split_counts.{split_name}.task_family_count expected {expected_family_count}, got {split_count.get('task_family_count')!r}."
            )
        if split_count.get("episode_count") != expected_episode_count:
            target.errors.append(
                f"dataset_splits.split_counts.{split_name}.episode_count expected {expected_episode_count}, got {split_count.get('episode_count')!r}."
            )
        artifacts = split_count.get("artifacts")
        if not isinstance(artifacts, dict):
            target.errors.append(f"dataset_splits.split_counts.{split_name}.artifacts must be an object.")
            continue
        for artifact_name in DATASET_SPLIT_ARTIFACTS:
            expected_artifact_count = len(split_rows[split_name][artifact_name])
            if artifacts.get(artifact_name) != expected_artifact_count:
                target.errors.append(
                    f"dataset_splits.split_counts.{split_name}.artifacts.{artifact_name} expected {expected_artifact_count}, got {artifacts.get(artifact_name)!r}."
                )


def _validate_dataset_split_summary(
    value: Any,
    target: ValidationTarget,
    family_to_split: dict[str, str],
    episodes: list[dict[str, Any]],
    split_rows: dict[str, dict[str, list[dict[str, Any]]]],
    family_exclusive: bool,
    train_scenario_ids: list[str],
    heldout_scenario_ids: list[str],
    heldout_scenario_exclusive: bool,
) -> None:
    if not isinstance(value, dict):
        target.errors.append("dataset_splits.summary must be an object.")
        return
    expected = {
        "task_family_count": len(family_to_split),
        "episode_count": len(episodes),
        "train_episode_count": len(split_rows["train"]["episodes"]),
        "validation_episode_count": len(split_rows["validation"]["episodes"]),
        "test_episode_count": len(split_rows["test"]["episodes"]),
        "family_exclusive": family_exclusive,
        "train_scenario_count": len(train_scenario_ids),
        "heldout_scenario_count": len(heldout_scenario_ids),
        "heldout_scenario_exclusive": heldout_scenario_exclusive,
    }
    for field_name, expected_value in expected.items():
        if value.get(field_name) != expected_value:
            target.errors.append(f"dataset_splits.summary.{field_name} expected {expected_value!r}, got {value.get(field_name)!r}.")


def _validate_dataset_split_leakage(
    value: Any,
    target: ValidationTarget,
    family_exclusive: bool,
    cross_split_families: list[str],
    train_scenario_ids: list[str],
    heldout_scenario_ids: list[str],
    cross_split_scenario_ids: list[str],
    heldout_scenario_exclusive: bool,
    train_task_families: list[str],
    heldout_task_families: list[str],
) -> None:
    if not isinstance(value, dict):
        target.errors.append("dataset_splits.leakage_checks must be an object.")
        return
    if value.get("family_exclusive") != family_exclusive:
        target.errors.append(
            f"dataset_splits.leakage_checks.family_exclusive expected {family_exclusive!r}, got {value.get('family_exclusive')!r}."
        )
    if value.get("cross_split_task_families") != cross_split_families:
        target.errors.append(
            f"dataset_splits.leakage_checks.cross_split_task_families expected {cross_split_families!r}, got {value.get('cross_split_task_families')!r}."
        )
    expected = {
        "train_scenario_ids": train_scenario_ids,
        "heldout_scenario_ids": heldout_scenario_ids,
        "cross_split_scenario_ids": cross_split_scenario_ids,
        "heldout_scenario_exclusive": heldout_scenario_exclusive,
        "train_task_families": train_task_families,
        "heldout_task_families": heldout_task_families,
    }
    for field_name, expected_value in expected.items():
        if value.get(field_name) != expected_value:
            target.errors.append(
                f"dataset_splits.leakage_checks.{field_name} expected {expected_value!r}, got {value.get(field_name)!r}."
            )


def _validate_dataset_registry(
    registry: dict[str, Any],
    target: ValidationTarget,
    manifest: dict[str, Any],
    export_dir: Path,
    expected_redaction_status: dict[str, Any],
    expected_label_provenance: dict[str, Any],
    dataset_splits: dict[str, Any] | None,
    dataset_metrics: dict[str, Any] | None,
    episodes: list[dict[str, Any]],
) -> None:
    _require_equal(registry, "schema_version", RL_DATASET_REGISTRY_SCHEMA_VERSION, target, prefix="dataset_registry.")
    if registry.get("artifact_type") != "training_export":
        target.errors.append("dataset_registry.artifact_type must be 'training_export'.")
    if registry.get("dataset_version") != manifest.get("dataset_version"):
        target.errors.append("dataset_registry.dataset_version must match manifest.dataset_version.")
    if registry.get("manifest_sha256") != _sha256(export_dir / "manifest.json"):
        target.errors.append("dataset_registry.manifest_sha256 must match manifest.json contents.")
    selection = registry.get("selection")
    if not isinstance(selection, dict):
        target.errors.append("dataset_registry.selection must be an object.")
    elif selection.get("key") != manifest.get("dataset_version"):
        target.errors.append("dataset_registry.selection.key must match manifest.dataset_version.")
    if registry.get("redaction_status") != expected_redaction_status:
        target.errors.append("dataset_registry.redaction_status must match recomputed redaction scan.")
    if registry.get("label_provenance") != expected_label_provenance:
        target.errors.append("dataset_registry.label_provenance must match recomputed label provenance.")
    if registry.get("dataset_splits") != (dataset_splits.get("summary") if isinstance(dataset_splits, dict) else None):
        target.errors.append("dataset_registry.dataset_splits must match dataset_splits.summary.")
    if registry.get("leakage_checks") != (dataset_splits.get("leakage_checks") if isinstance(dataset_splits, dict) else None):
        target.errors.append("dataset_registry.leakage_checks must match dataset_splits.leakage_checks.")
    if registry.get("source_fingerprint_coverage") != (
        dataset_metrics.get("source_fingerprint_coverage") if isinstance(dataset_metrics, dict) else None
    ):
        target.errors.append("dataset_registry.source_fingerprint_coverage must match dataset_metrics.source_fingerprint_coverage.")
    if registry.get("quality_flags") != (dataset_metrics.get("quality_flags") if isinstance(dataset_metrics, dict) else None):
        target.errors.append("dataset_registry.quality_flags must match dataset_metrics.quality_flags.")
    if registry.get("artifact_fingerprints") != manifest.get("artifact_fingerprints"):
        target.errors.append("dataset_registry.artifact_fingerprints must match manifest.artifact_fingerprints.")
    source_runs = registry.get("source_runs")
    if not isinstance(source_runs, list):
        target.errors.append("dataset_registry.source_runs must be a list.")
    elif len(source_runs) != len(episodes):
        target.errors.append(f"dataset_registry.source_runs expected {len(episodes)} rows, got {len(source_runs)}.")


